# ============================================================================
# FILE-BATCHED PROCESSING INFRASTRUCTURE
# Groups polygons by image file and processes all polygons for each file
# before moving to the next. Per-file caches (band-math arrays, scene stats,
# RF model expressions) are computed once and reused across all polygons.
# ============================================================================


# ============================================================================
# BACKGROUND EXPORT SYSTEM
# Allows CSV exports to run in background while user continues working
# ============================================================================

class ExportWorker(QtCore.QThread):
    """
    Background worker thread for CSV polygon export.

    Critical safety rules:
      - Never consult a live viewer during export (even on the GUI thread).
      - Always operate on a disk-snapshotted polygon job list (JSON), so UI edits cannot
        mutate jobs mid-export.
      - Avoid nested thread pools inside this QThread (Windows + OpenCV/imagecodecs/BLAS
        combinations can hard-crash). We still run in a background QThread so the UI stays responsive.
    """
    progress = QtCore.pyqtSignal(int, int, str)   # current, total, message
    finished = QtCore.pyqtSignal(str, bool, str)  # output_path, success, error_message

    def __init__(
        self,
        project_tab,
        output_path,
        opts,
        polygons_to_process,
        exif_data_dict,
        exif_tags,
        model_loaded,
        export_mods,
        processing_mode,
        n_workers,
        snapshot_json_path=None,
        snapshot_dir=None,
        parent=None
    ):
        super().__init__(parent)
        self.project_tab = project_tab
        self.output_path = output_path
        self.opts = opts or {}
        self.polygons_to_process = polygons_to_process or []
        self.exif_data_dict = exif_data_dict or {}
        self.exif_tags = exif_tags or []
        self.model_loaded = model_loaded
        self.export_mods = bool(export_mods)
        self.processing_mode = processing_mode or "sequential"
        self.n_workers = int(n_workers or 1)
        self.snapshot_json_path = snapshot_json_path
        self.snapshot_dir = snapshot_dir

        self._cancelled = False
        self._is_exporting = False  # requested: per-worker flag

    def cancel(self):
        self._cancelled = True

    def _set_exporting_flag(self, val: bool):
        self._is_exporting = bool(val)
        try:
            setattr(self.project_tab, "_is_exporting", bool(val))
        except Exception:
            pass

    def run(self):
        import os, csv, json, time, logging, tempfile, faulthandler, threading

        # Enable a faulthandler dump to disk for true hard-crashes (segfault/access violation).
        fh = None
        try:
            d = self.snapshot_dir or tempfile.gettempdir()
            fh_path = os.path.join(d, "canopie_csv_export_faulthandler.log")
            fh = open(fh_path, "a", encoding="utf-8", errors="replace")
            faulthandler.enable(file=fh, all_threads=True)
            fh.write("\n\n===== CSV EXPORT START {} =====\n".format(time.strftime("%Y-%m-%d %H:%M:%S")))
            fh.flush()
        except Exception:
            fh = None

        # Reduce risk of OpenMP / BLAS / OpenCV / sklearn thread interactions (esp. on Windows).
        try:
            os.environ.setdefault("OMP_NUM_THREADS", "1")
            os.environ.setdefault("OPENBLAS_NUM_THREADS", "1")
            os.environ.setdefault("MKL_NUM_THREADS", "1")
            os.environ.setdefault("NUMEXPR_NUM_THREADS", "1")
            os.environ.setdefault("VECLIB_MAXIMUM_THREADS", "1")
            os.environ.setdefault("BLIS_NUM_THREADS", "1")
            # Sklearn/joblib thread safety
            os.environ["JOBLIB_MULTIPROCESSING"] = "0"
            os.environ.setdefault("LOKY_MAX_CPU_COUNT", "1")
        except Exception:
            pass

        try:
            import cv2
            try:
                cv2.setNumThreads(1)
            except Exception:
                pass
            try:
                cv2.ocl.setUseOpenCL(False)
            except Exception:
                pass
        except Exception:
            pass
        
        # Limit sklearn/joblib parallelism
        try:
            import joblib
            joblib.parallel_backend('threading', n_jobs=1)
        except Exception:
            pass
        
        # CRITICAL: Ensure sklearn prediction lock exists for thread safety
        try:
            pt = self.project_tab
            if not hasattr(pt, "_sklearn_predict_lock"):
                pt._sklearn_predict_lock = threading.Lock()
            # Track files processed for periodic GC
            files_processed = 0
            gc_interval = 5  # Run GC every N files
        except Exception:
            files_processed = 0
            gc_interval = 5

        # IMPORTANT: mark export active so ALL mapping code stays offline-only.
        self._set_exporting_flag(True)

        def _load_snapshot_jobs():
            if not self.snapshot_json_path:
                return None
            try:
                with open(self.snapshot_json_path, "r", encoding="utf-8") as f:
                    jobs = json.load(f)
                if isinstance(jobs, list):
                    normalized = []
                    for item in jobs:
                        if not (isinstance(item, (list, tuple)) and len(item) == 3):
                            continue
                        g, fp, pd = item
                        if not isinstance(g, str) or not isinstance(fp, str) or not isinstance(pd, dict):
                            continue
                        normalized.append((g, fp, pd))
                    return normalized
            except Exception as e:
                logging.warning(f"[CSV export] Failed to load polygon snapshot: {e}")
            return None

        snap = _load_snapshot_jobs()
        if snap is not None:
            self.polygons_to_process = snap

        n_polygons = len(self.polygons_to_process)
        if n_polygons == 0:
            self.finished.emit(self.output_path, False, "No polygons to export")
            self._set_exporting_flag(False)
            return

        # Always process sequentially inside this QThread for stability.
        from collections import defaultdict
        file_batches = defaultdict(list)
        filepath_map = {}
        for g, fp, pd in self.polygons_to_process:
            fp_key = os.path.normcase(os.path.abspath(fp))
            filepath_map[fp_key] = fp
            file_batches[fp_key].append((g, pd))

        file_items = list(file_batches.items())
        n_files = len(file_items)

        tmp_rows_path = None
        keys_union = set()
        errors = 0
        processed_poly = 0

        def _to_jsonable(v):
            try:
                import numpy as np
                if isinstance(v, (np.generic,)):
                    return v.item()
                if isinstance(v, np.ndarray):
                    return v.tolist()
            except Exception:
                pass
            return v

        try:
            tmp_dir = self.snapshot_dir or tempfile.gettempdir()
            tmp_rows_path = os.path.join(tmp_dir, f"canopie_csv_rows_{int(time.time())}_{threading.get_ident()}.jsonl")
            rows_f = open(tmp_rows_path, "w", encoding="utf-8", errors="replace")

            for file_idx, (fp_key, polys) in enumerate(file_items, start=1):
                if self._cancelled:
                    break
                filepath = filepath_map[fp_key]
                self.progress.emit(processed_poly, n_polygons, f"Image {file_idx}/{n_files}: {os.path.basename(filepath)}")

                for (group_name, polygon_dict) in polys:
                    if self._cancelled:
                        break
                    try:
                        rows, _mods = self.project_tab.process_polygon(
                            group_name,
                            filepath,
                            polygon_dict,
                            self.exif_data_dict,
                            self.exif_tags,
                            self.model_loaded,
                            opts=self.opts
                        )
                        if rows:
                            for r in rows:
                                if not isinstance(r, dict):
                                    continue
                                for k in r.keys():
                                    keys_union.add(k)
                                r2 = {k: _to_jsonable(v) for k, v in r.items()}
                                rows_f.write(json.dumps(r2, ensure_ascii=False, allow_nan=True) + "\n")
                    except Exception as e:
                        errors += 1
                        logging.error(f"[CSV export] Error in {os.path.basename(filepath)} / {group_name}: {e}", exc_info=True)

                    processed_poly += 1
                    if (processed_poly % 25) == 0:
                        self.progress.emit(processed_poly, n_polygons, f"Processed {processed_poly}/{n_polygons}")

                # Purge per-file caches to prevent memory growth / fragmentation
                try:
                    pt = self.project_tab
                    fp_norm = fp_key  # already normcase(abspath)

                    # 1) Export cache holds full image arrays per file; remove this file's entries
                    if hasattr(pt, "_export_cache") and getattr(pt, "_export_cache", None):
                        lock = getattr(pt, "_export_cache_lock", None)
                        if lock:
                            with lock:
                                keys = [k for k in list(pt._export_cache.keys())
                                        if isinstance(k, tuple) and len(k) > 0 and
                                        os.path.normcase(os.path.abspath(k[0])) == fp_norm]
                                for k in keys:
                                    pt._export_cache.pop(k, None)
                        else:
                            keys = [k for k in list(pt._export_cache.keys())
                                    if isinstance(k, tuple) and len(k) > 0 and
                                    os.path.normcase(os.path.abspath(k[0])) == fp_norm]
                            for k in keys:
                                pt._export_cache.pop(k, None)

                    # 2) Scene-stats cache is small, but purge to avoid unbounded growth across many files
                    if hasattr(pt, "_scene_stats_cache") and getattr(pt, "_scene_stats_cache", None):
                        lock = getattr(pt, "_export_cache_lock", None)
                        if lock:
                            with lock:
                                keys = [k for k in list(pt._scene_stats_cache.keys())
                                        if isinstance(k, tuple) and len(k) > 0 and
                                        os.path.normcase(os.path.abspath(k[0])) == fp_norm]
                                for k in keys:
                                    pt._scene_stats_cache.pop(k, None)
                        else:
                            keys = [k for k in list(pt._scene_stats_cache.keys())
                                    if isinstance(k, tuple) and len(k) > 0 and
                                    os.path.normcase(os.path.abspath(k[0])) == fp_norm]
                            for k in keys:
                                pt._scene_stats_cache.pop(k, None)

                    # 3) Raw cache is for editor UX; during export it can bloat RAM on large files
                    if hasattr(pt, "_raw_cache") and getattr(pt, "_raw_cache", None):
                        rlock = getattr(pt, "_raw_cache_lock", None)
                        if rlock:
                            with rlock:
                                pt._raw_cache.pop(fp_norm, None)
                        else:
                            pt._raw_cache.pop(fp_norm, None)
                    
                    # 4) Periodic garbage collection to actually free memory
                    files_processed += 1
                    if files_processed % gc_interval == 0:
                        import gc
                        gc.collect()
                except Exception:
                    pass

            rows_f.flush()
            rows_f.close()

            if self._cancelled:
                self.finished.emit(self.output_path, False, "Cancelled by user")
                return

            if not keys_union:
                self.finished.emit(self.output_path, False, "No data to export")
                return

            all_keys = sorted(keys_union)
            with open(self.output_path, "w", newline="", encoding="utf-8-sig") as fcsv:
                writer = csv.DictWriter(
                    fcsv,
                    fieldnames=all_keys,
                    extrasaction="ignore",
                    quoting=csv.QUOTE_MINIMAL
                )
                writer.writeheader()
                with open(tmp_rows_path, "r", encoding="utf-8", errors="replace") as rf:
                    for line in rf:
                        line = line.strip()
                        if not line:
                            continue
                        try:
                            row = json.loads(line)
                            if isinstance(row, dict):
                                writer.writerow(row)
                        except Exception:
                            continue

            self.finished.emit(self.output_path, True, f"Exported {len(all_keys)} columns ({errors} errors)")

        except Exception as e:
            self.finished.emit(self.output_path, False, str(e))

        finally:
            import gc
            
            try:
                if tmp_rows_path and os.path.exists(tmp_rows_path):
                    os.remove(tmp_rows_path)
            except Exception:
                pass
            try:
                if self.snapshot_json_path and os.path.isfile(self.snapshot_json_path):
                    os.remove(self.snapshot_json_path)
            except Exception:
                pass
            try:
                if self.snapshot_dir and os.path.isdir(self.snapshot_dir):
                    try:
                        os.rmdir(self.snapshot_dir)
                    except Exception:
                        pass
            except Exception:
                pass

            self._set_exporting_flag(False)
            
            # MEMORY CLEANUP: Clear all caches and force garbage collection
            try:
                pt = self.project_tab
                if pt:
                    if hasattr(pt, '_export_cache') and pt._export_cache:
                        lock = getattr(pt, '_export_cache_lock', None)
                        if lock:
                            with lock:
                                pt._export_cache.clear()
                        else:
                            pt._export_cache.clear()
                    if hasattr(pt, '_scene_stats_cache') and pt._scene_stats_cache:
                        pt._scene_stats_cache.clear()
                    if hasattr(pt, '_raw_cache') and pt._raw_cache:
                        rlock = getattr(pt, '_raw_cache_lock', None)
                        if rlock:
                            with rlock:
                                pt._raw_cache.clear()
                        else:
                            pt._raw_cache.clear()
                    logging.info("[ExportWorker] Cleared all export caches")
            except Exception as e:
                logging.debug(f"[ExportWorker] Cache cleanup: {e}")
            
            gc.collect()

            try:
                if fh is not None:
                    fh.write("\n===== CSV EXPORT END {} =====\n".format(time.strftime("%Y-%m-%d %H:%M:%S")))
                    fh.flush()
                    fh.close()
            except Exception:
                pass



class ExifExportWorker(QtCore.QThread):
    """Background worker for EXIF CSV export."""
    progress = QtCore.pyqtSignal(int, int, str)  # current, total, message
    finished = QtCore.pyqtSignal(str, bool, str)  # output_path, success, error_message
    
    def __init__(self, project_tab, output_path, filepaths, exif_tags, parent=None):
        super().__init__(parent)
        self.project_tab = project_tab
        self.output_path = output_path
        self.filepaths = filepaths
        self.exif_tags = exif_tags
        self._cancelled = False
        # Capture project info at creation time (thread-safe)
        self.project_name = getattr(project_tab, 'project_name', 'N/A') or 'N/A'
        self.root_id_mapping = dict(getattr(project_tab, 'root_id_mapping', {}) or {})
    
    def cancel(self):
        self._cancelled = True
    
    def run(self):
        import os, csv, logging
        
        try:
            total = len(self.filepaths)
            
            # Helper to normalize keys
            def _normkey(p): 
                return os.path.normcase(os.path.abspath(p))

            self.progress.emit(0, total, f"scanning {total} files for EXIF tags...")
            
            # 1. BATCH EXTRACTION (Fast & Thread-safe provided we don't touch UI widgets)
            # This replaces the slow one-by-one loop.
            # We access project_tab helper methods. Assuming they don't access GUI.
            # _get_exif_data_with_optional_path -> _extract_exif_via_subprocess or internal readers
            
            normed_paths = [_normkey(p) for p in self.filepaths]
            
            # Note: This might take time, but now it's in the background thread!
            raw_exif = {}
            if hasattr(self.project_tab, '_get_exif_data_with_optional_path'):
                raw_exif = self.project_tab._get_exif_data_with_optional_path(normed_paths) or {}
            
            if self._cancelled:
                self.finished.emit(self.output_path, False, "Cancelled by user")
                return

            self.progress.emit(total, total, "Processing tags...")

            # 2. TAG DISCOVERY (if needed)
            tags_to_use = self.exif_tags
            if not tags_to_use:
                # Discover tags from the data we just read
                discovered_tags = []
                for fp, kv in raw_exif.items():
                    if isinstance(kv, dict):
                        for k in kv.keys():
                            if k not in discovered_tags:
                                discovered_tags.append(str(k))
                
                # Sort/Deduplicate
                seen = set()
                tags_to_use = [t for t in discovered_tags if not (t in seen or seen.add(t))]

            # 3. BUILD ROWS
            rows = []
            fieldnames = ['Project', 'Root ID', 'Root Folder', 'File Name'] + list(tags_to_use)
            
            for i, fp in enumerate(self.filepaths):
                if self._cancelled:
                    break
                
                # Get root info
                root_name = ""
                # get_root_by_filepath might be purely logic (regex), but if it accesses UI it could be risky.
                # Assuming regex-based 'extract_root_name' or internal dict lookups.
                # ProjectTab.get_root_by_filepath usually checks self.multispectral_image_data_groups (safe).
                if hasattr(self.project_tab, 'get_root_by_filepath'):
                    try:
                        root_name = self.project_tab.get_root_by_filepath(fp) or ""
                    except Exception:
                        pass
                root_id = self.root_id_mapping.get(root_name, "N/A")
                
                # Get data from our batch result
                nk = _normkey(fp)
                exif_data = raw_exif.get(nk, {})
                
                row = {
                    'Project': self.project_name,
                    'Root ID': root_id,
                    'Root Folder': os.path.dirname(fp),
                    'File Name': os.path.basename(fp)
                }
                
                for tag in tags_to_use:
                    val = exif_data.get(tag, "")
                    # Basic sanitization
                    if isinstance(val, (list, tuple)):
                        val = " ".join(str(v) for v in val)
                    elif isinstance(val, dict):
                        val = str(val)
                    row[tag] = str(val) if val else ""
                
                rows.append(row)
            
            if self._cancelled:
                self.finished.emit(self.output_path, False, "Cancelled by user")
                return

            # 4. WRITE CSV
            self.progress.emit(total, total, "Writing CSV...")
            
            if rows:
                with open(self.output_path, 'w', newline='', encoding='utf-8-sig') as f:
                    writer = csv.DictWriter(f, fieldnames=fieldnames, extrasaction='ignore',
                                           quoting=csv.QUOTE_MINIMAL)
                    writer.writeheader()
                    writer.writerows(rows)
                
                self.finished.emit(self.output_path, True, f"Exported {len(rows)} files")
            else:
                self.finished.emit(self.output_path, False, "No data to export")
                
        except Exception as e:
            logging.exception("[ExifExportWorker] Fatal error")
            self.finished.emit(self.output_path, False, str(e))
        finally:
            import gc
            gc.collect()


class ThumbnailExportWorker(QtCore.QThread):
    """Background worker for thumbnail export."""
    progress = QtCore.pyqtSignal(int, int, str)  # current, total, message
    finished = QtCore.pyqtSignal(str, bool, str)  # output_path, success, error_message
    
    def __init__(self, project_tab, output_dir, polygons_data, thumbnail_size, parent=None):
        super().__init__(parent)
        self.project_tab = project_tab
        self.output_dir = output_dir
        # Make a copy of the data to ensure thread safety
        self.polygons_data = list(polygons_data) if polygons_data else []
        self.thumbnail_size = thumbnail_size
        self._cancelled = False
    
    def cancel(self):
        self._cancelled = True
    
    def _load_image_simple(self, filepath):
        """Thread-safe image loading without Qt dependencies."""
        import numpy as np
        
        # Try OpenCV first (usually more reliable)
        try:
            import cv2
            data = np.fromfile(filepath, dtype=np.uint8)
            img = cv2.imdecode(data, cv2.IMREAD_UNCHANGED)
            if img is not None:
                # BGR->RGB for 3-channel
                if img.ndim == 3 and img.shape[2] == 3:
                    img = img[..., ::-1].copy()
                return img
        except Exception:
            pass
        
        # Try PIL as fallback
        try:
            from PIL import Image
            im = Image.open(filepath)
            im.load()
            if im.mode == "P":
                im = im.convert("RGBA")
            return np.array(im)
        except Exception:
            pass
        
        return None
    
    def run(self):
        import os
        import logging
        import numpy as np
        
        # Try to import PIL, fall back to cv2 if not available
        try:
            from PIL import Image
            HAS_PIL = True
        except ImportError:
            HAS_PIL = False
            logging.info("[ThumbnailWorker] PIL not available, using OpenCV")
        
        try:
            import cv2
            HAS_CV2 = True
        except ImportError:
            HAS_CV2 = False
        
        if not HAS_PIL and not HAS_CV2:
            self.finished.emit(self.output_dir, False, "Neither PIL nor OpenCV available")
            return
        
        logging.info(f"[ThumbnailWorker] Starting with {len(self.polygons_data)} polygons (PIL={HAS_PIL}, CV2={HAS_CV2})")
        
        try:
            total = len(self.polygons_data)
            if total == 0:
                self.finished.emit(self.output_dir, False, "No polygons to process")
                return
                
            saved = 0
            errors = 0
            skipped = 0
            
            os.makedirs(self.output_dir, exist_ok=True)
            
            for i, item in enumerate(self.polygons_data):
                if self._cancelled:
                    logging.info(f"[ThumbnailWorker] Cancelled at {i}/{total}")
                    self.finished.emit(self.output_dir, False, "Cancelled by user")
                    return
                
                # Unpack safely
                try:
                    group_name, filepath, polygon_dict = item
                except (ValueError, TypeError) as e:
                    logging.warning(f"[ThumbnailWorker] Invalid item at {i}: {e}")
                    errors += 1
                    continue
                
                self.progress.emit(i, total, f"Saving: {group_name}")
                
                try:
                    # Get polygon points
                    points = polygon_dict.get("points", []) if isinstance(polygon_dict, dict) else []
                    if not points or len(points) < 3:
                        skipped += 1
                        continue
                    
                    # Load image using thread-safe method
                    img = self._load_image_simple(filepath)
                    if img is None:
                        errors += 1
                        continue
                    
                    # Get bounding box
                    pts = np.array(points)
                    x_min, y_min = pts.min(axis=0).astype(int)
                    x_max, y_max = pts.max(axis=0).astype(int)
                    
                    # Clamp to image bounds
                    H, W = img.shape[:2]
                    x_min, x_max = max(0, x_min), min(W, x_max)
                    y_min, y_max = max(0, y_min), min(H, y_max)
                    
                    if x_max <= x_min or y_max <= y_min:
                        skipped += 1
                        continue
                    
                    # Crop
                    crop = img[y_min:y_max, x_min:x_max]
                    
                    # Prepare for saving
                    if crop.ndim == 3 and crop.shape[2] >= 3:
                        crop_rgb = crop[:, :, :3]
                    elif crop.ndim == 2:
                        crop_rgb = crop
                    else:
                        skipped += 1
                        continue
                    
                    # Ensure uint8
                    if crop_rgb.dtype != np.uint8:
                        if crop_rgb.max() <= 1.0:
                            crop_rgb = (crop_rgb * 255).astype(np.uint8)
                        else:
                            crop_rgb = np.clip(crop_rgb, 0, 255).astype(np.uint8)
                    
                    # Resize and save
                    safe_name = "".join(c if c.isalnum() or c in "._-" else "_" for c in str(group_name))
                    out_path = os.path.join(self.output_dir, f"{safe_name}.png")
                    
                    # Handle duplicates
                    counter = 1
                    while os.path.exists(out_path):
                        out_path = os.path.join(self.output_dir, f"{safe_name}_{counter}.png")
                        counter += 1
                    
                    # Try PIL first, then OpenCV
                    save_success = False
                    if HAS_PIL:
                        try:
                            if crop_rgb.ndim == 2:
                                pil_img = Image.fromarray(crop_rgb, mode='L')
                            else:
                                pil_img = Image.fromarray(crop_rgb)
                            pil_img.thumbnail((self.thumbnail_size, self.thumbnail_size), Image.LANCZOS)
                            pil_img.save(out_path)
                            save_success = True
                            del pil_img
                        except Exception as e:
                            logging.debug(f"[ThumbnailWorker] PIL save failed: {e}")
                    
                    if not save_success and HAS_CV2:
                        try:
                            # Resize with OpenCV
                            h, w = crop_rgb.shape[:2]
                            scale = min(self.thumbnail_size / w, self.thumbnail_size / h)
                            if scale < 1.0:
                                new_w, new_h = int(w * scale), int(h * scale)
                                crop_rgb = cv2.resize(crop_rgb, (new_w, new_h), interpolation=cv2.INTER_AREA)
                            # Convert RGB to BGR for OpenCV
                            if crop_rgb.ndim == 3:
                                crop_bgr = crop_rgb[..., ::-1]
                            else:
                                crop_bgr = crop_rgb
                            cv2.imwrite(out_path, crop_bgr)
                            save_success = True
                        except Exception as e:
                            logging.debug(f"[ThumbnailWorker] OpenCV save failed: {e}")
                    
                    if save_success:
                        saved += 1
                    else:
                        errors += 1
                    
                    # Free memory
                    del img, crop, crop_rgb
                    
                except Exception as e:
                    logging.warning(f"[ThumbnailWorker] Error for {group_name}: {e}")
                    errors += 1
            
            # Final progress
            self.progress.emit(total, total, "Complete")
            
            msg = f"Saved {saved} thumbnails"
            if errors > 0:
                msg += f" ({errors} errors)"
            if skipped > 0:
                msg += f" ({skipped} skipped)"
            
            logging.info(f"[ThumbnailWorker] Finished: {msg}")
            self.finished.emit(self.output_dir, True, msg)
            
        except Exception as e:
            logging.exception("[ThumbnailExportWorker] Fatal error")
            self.finished.emit(self.output_dir, False, str(e))
        finally:
            # Memory cleanup
            import gc
            gc.collect()


class ProjectImagesExportWorker(QtCore.QThread):
    """Background worker for exporting project images with .ax transformations."""
    progress = QtCore.pyqtSignal(int, int, str)  # current, total, message
    finished = QtCore.pyqtSignal(str, bool, str)  # output_path, success, error_message
    
    def __init__(self, project_tab, output_dir, filepaths, export_format, parent=None):
        super().__init__(parent)
        self.project_tab = project_tab
        self.output_dir = output_dir
        self.filepaths = filepaths
        self.export_format = export_format
        self._cancelled = False
        # Capture critical project state to avoid hitting 'self.project_tab' repeatedly
        self.project_folder = getattr(project_tab, 'project_folder', None)
    
    def cancel(self):
        self._cancelled = True
    
    def _load_image_simple(self, filepath):
        """Thread-safe image loading avoiding all Qt/GUI dependencies."""
        import os, numpy as np, cv2
        ext = os.path.splitext(filepath)[1].lower()
        try:
            if ext in ('.tif', '.tiff'):
                import tifffile
                with tifffile.TiffFile(filepath) as tf:
                    return np.ascontiguousarray(np.squeeze(tf.asarray()))
            
            # Using imdecode is safer for unicode paths on some systems
            data = np.fromfile(filepath, dtype=np.uint8)
            img = cv2.imdecode(data, cv2.IMREAD_UNCHANGED)
            return img 
        except Exception:
            return None

    def run(self):
        import os, logging, numpy as np
        try:
            import cv2
            total = len(self.filepaths)
            saved, errors = 0, 0
            os.makedirs(self.output_dir, exist_ok=True)
            
            # Set flag on project_tab to prevent UI interference
            self.project_tab._is_exporting = True

            for i, filepath in enumerate(self.filepaths):
                if self._cancelled:
                    break
                
                basename = os.path.basename(filepath)
                self.progress.emit(i, total, f"Processing: {basename}")
                
                try:
                    # 1. Load Raw
                    img = self._load_image_simple(filepath)
                    if img is None: raise ValueError("Load failed")
                    
                    # 2. Load AX Configuration (Offline)
                    ax = self.project_tab._load_ax_json(filepath)  # pure-logic (.ax sidecar), cached
                    
                    # 3. Apply Transformations
                    # Note: Ensure _apply_ax_to_raw does NOT call _resolve_viewer
                    if ax:
                        img, _ = self.project_tab._apply_ax_to_raw(img, ax, filepath=filepath)
                    
                    # 4. Save Logic (Standardized)
                    stem = os.path.splitext(basename)[0]
                    out_path = os.path.join(self.output_dir, f"{stem}.{self.export_format}")

                    # Deduplicate filenames
                    c = 1
                    while os.path.exists(out_path):
                        out_path = os.path.join(self.output_dir, f"{stem}_{c}.{self.export_format}")
                        c += 1

                    # Check if we have band expressions/appended bands (need float preservation)
                    has_band_expr = bool((ax.get("band_expression") or "").strip()) and ax.get("band_enabled", True)
                    has_appended_bands = bool(ax.get("appended_bands"))
                    has_classification = (ax.get("classification") or {}).get("enabled", False)
                    needs_float = has_band_expr or has_appended_bands or has_classification

                    # Convert RGB/BGR if needed and save
                    if self.export_format == 'jpg':
                        cv2.imwrite(out_path, img[..., ::-1] if img.ndim==3 else img, [cv2.IMWRITE_JPEG_QUALITY, 95])
                    elif self.export_format in ('tif', 'tiff') and (needs_float or img.dtype not in (np.uint8, np.uint16)):
                        # Use tifffile for float data or multiband to preserve precision
                        import tifffile
                        a = np.ascontiguousarray(img)
                        if a.ndim == 2:
                            photometric = "minisblack"
                            write_arr = a
                        elif a.ndim == 3 and a.shape[2] == 3:
                            # BGR -> RGB for TIFF
                            photometric = "rgb"
                            write_arr = a[:, :, ::-1].copy()
                        elif a.ndim == 3 and a.shape[2] > 3:
                            # Multiband: write as CHW
                            photometric = "minisblack"
                            write_arr = np.moveaxis(a, -1, 0)
                        else:
                            photometric = "minisblack"
                            write_arr = a
                        tifffile.imwrite(out_path, write_arr, compression="deflate", photometric=photometric)
                    else:
                        cv2.imwrite(out_path, img[..., ::-1] if img.ndim==3 else img)
                    
                    saved += 1
                except Exception as e:
                    errors += 1
                    logging.error(f"Failed {basename}: {e}")

            status_msg = f"Exported {saved} images ({errors} errors)"
            self.finished.emit(self.output_dir, not self._cancelled, status_msg)
            
        except Exception as e:
            self.finished.emit(self.output_dir, False, f"Fatal error: {str(e)}")
        finally:
            self.project_tab._is_exporting = False

class ExportManagerDialog(QtWidgets.QDialog):
    """
    Non-modal dialog showing all running and completed exports.
    Allows users to monitor progress and cancel exports.
    """
    
    _instance = None  # Singleton instance
    
    @classmethod
    def get_instance(cls, parent=None):
        # Only create new instance if none exists or it was deleted
        if cls._instance is None:
            cls._instance = cls(parent)
        else:
            # Check if the C++ object was deleted
            try:
                cls._instance.isVisible()  # This will raise if deleted
            except RuntimeError:
                cls._instance = cls(parent)
        return cls._instance
    
    def __init__(self, parent=None):
        super().__init__(parent)
        self.setWindowTitle("Export Manager")
        self.setMinimumSize(650, 450)
        self.setModal(False)
        self.setAttribute(QtCore.Qt.WA_DeleteOnClose, False)
        
        self._exports = {}  # export_id -> {worker, progress_bar, status_label, ...}
        self._next_id = 1
        
        layout = QtWidgets.QVBoxLayout(self)
        
        # Header
        header = QtWidgets.QLabel("<b>Background Exports</b>")
        layout.addWidget(header)
        
        # Scroll area for exports
        scroll = QtWidgets.QScrollArea()
        scroll.setWidgetResizable(True)
        scroll.setHorizontalScrollBarPolicy(QtCore.Qt.ScrollBarAlwaysOff)
        
        self._container = QtWidgets.QWidget()
        self._container_layout = QtWidgets.QVBoxLayout(self._container)
        self._container_layout.setAlignment(QtCore.Qt.AlignTop)
        self._container_layout.addStretch()
        
        scroll.setWidget(self._container)
        layout.addWidget(scroll)
        
        # Bottom buttons
        btn_layout = QtWidgets.QHBoxLayout()
        
        self._clear_completed_btn = QtWidgets.QPushButton("Clear Completed")
        self._clear_completed_btn.clicked.connect(self._clear_completed)
        btn_layout.addWidget(self._clear_completed_btn)
        
        btn_layout.addStretch()
        
        close_btn = QtWidgets.QPushButton("Hide")
        close_btn.clicked.connect(self.hide)
        btn_layout.addWidget(close_btn)
        
        layout.addLayout(btn_layout)
        
        # Empty state label
        self._empty_label = QtWidgets.QLabel("No exports running.\nStart an export to see it here.")
        self._empty_label.setAlignment(QtCore.Qt.AlignCenter)
        self._empty_label.setStyleSheet("color: gray;")
        self._container_layout.insertWidget(0, self._empty_label)
    
    def add_export(self, worker, output_path, export_type="csv"):
        """
        Add a new export to track.
        
        Args:
            worker: QThread worker with progress/finished signals
            output_path: Output file or directory path
            export_type: One of 'csv', 'exif', 'thumbnails', 'images'
        """
        export_id = self._next_id
        self._next_id += 1
        worker._export_id = export_id
        
        # Type-specific icons and labels
        type_icons = {
            'csv': '📊',
            'exif': '📷',
            'thumbnails': '🖼️',
            'images': '💾'
        }
        type_labels = {
            'csv': 'CSV Export',
            'exif': 'EXIF Export',
            'thumbnails': 'Thumbnails',
            'images': 'Image Export'
        }
        icon = type_icons.get(export_type, '📄')
        type_label = type_labels.get(export_type, 'Export')
        
        # Create UI for this export
        frame = QtWidgets.QFrame()
        frame.setFrameStyle(QtWidgets.QFrame.StyledPanel)
        frame_layout = QtWidgets.QVBoxLayout(frame)
        frame_layout.setContentsMargins(8, 8, 8, 8)
        
        # Title row
        title_layout = QtWidgets.QHBoxLayout()
        name_label = QtWidgets.QLabel(f"{icon} <b>{type_label}:</b> {os.path.basename(output_path)}")
        title_layout.addWidget(name_label)
        title_layout.addStretch()
        
        cancel_btn = QtWidgets.QPushButton("Cancel")
        cancel_btn.setFixedWidth(60)
        title_layout.addWidget(cancel_btn)
        frame_layout.addLayout(title_layout)
        
        # Path
        path_label = QtWidgets.QLabel(output_path)
        path_label.setStyleSheet("color: gray; font-size: 10px;")
        path_label.setWordWrap(True)
        frame_layout.addWidget(path_label)
        
        # Progress bar
        progress_bar = QtWidgets.QProgressBar()
        progress_bar.setRange(0, 100)
        progress_bar.setValue(0)
        frame_layout.addWidget(progress_bar)
        
        # Status label
        status_label = QtWidgets.QLabel("Starting...")
        status_label.setStyleSheet("font-size: 11px;")
        frame_layout.addWidget(status_label)
        
        # Store reference
        self._exports[export_id] = {
            'worker': worker,
            'frame': frame,
            'progress_bar': progress_bar,
            'status_label': status_label,
            'cancel_btn': cancel_btn,
            'output_path': output_path,
            'completed': False
        }
        
        # Connect signals
        worker.progress.connect(lambda c, t, m, eid=export_id: self._on_progress(eid, c, t, m))
        worker.finished.connect(lambda p, s, m, eid=export_id: self._on_finished(eid, p, s, m))
        cancel_btn.clicked.connect(lambda checked, eid=export_id: self._cancel_export(eid))
        
        # Add to layout (before the stretch)
        self._container_layout.insertWidget(self._container_layout.count() - 1, frame)
        self._empty_label.hide()
        
        # Start worker
        worker.start()
        
        return export_id
    
    def _on_progress(self, export_id, current, total, message):
        if export_id not in self._exports:
            return
        
        export = self._exports[export_id]
        if total > 0:
            pct = int(100 * current / total)
            export['progress_bar'].setValue(pct)
        
        if message:
            export['status_label'].setText(message)
        else:
            export['status_label'].setText(f"Processing... {current}/{total}")
    
    def _on_finished(self, export_id, output_path, success, message):
        if export_id not in self._exports:
            return
        
        export = self._exports[export_id]
        export['completed'] = True
        export['cancel_btn'].setEnabled(False)
        export['cancel_btn'].setText("Done")
        
        if success:
            export['progress_bar'].setValue(100)
            export['status_label'].setText(f"✓ {message}")
            export['status_label'].setStyleSheet("color: green; font-size: 11px;")
            
            # Add "Open Folder" button
            open_btn = QtWidgets.QPushButton("Open Folder")
            open_btn.setFixedWidth(80)
            open_btn.clicked.connect(lambda: self._open_folder(output_path))
            export['frame'].layout().itemAt(0).layout().insertWidget(2, open_btn)
        else:
            export['progress_bar'].setStyleSheet("QProgressBar::chunk { background-color: red; }")
            export['status_label'].setText(f"✗ {message}")
            export['status_label'].setStyleSheet("color: red; font-size: 11px;")
        
        # Trigger memory cleanup in the parent project_tab
        try:
            parent = self.parent()
            if parent and hasattr(parent, '_cleanup_export_memory'):
                parent._cleanup_export_memory()
        except Exception:
            pass
    
    def _cancel_export(self, export_id):
        if export_id not in self._exports:
            return
        
        export = self._exports[export_id]
        if not export['completed']:
            export['worker'].cancel()
            export['status_label'].setText("Cancelling...")
    
    def _open_folder(self, path):
        import subprocess, sys
        folder = os.path.dirname(path)
        if sys.platform == 'win32':
            os.startfile(folder)
        elif sys.platform == 'darwin':
            subprocess.run(['open', folder])
        else:
            subprocess.run(['xdg-open', folder])
    
    def _clear_completed(self):
        """Remove completed exports from the list."""
        to_remove = [eid for eid, exp in self._exports.items() if exp['completed']]
        for eid in to_remove:
            export = self._exports.pop(eid)
            export['frame'].setParent(None)
            export['frame'].deleteLater()
        
        if not self._exports:
            self._empty_label.show()
    
    def has_running_exports(self):
        return any(not exp['completed'] for exp in self._exports.values())
    
    def closeEvent(self, event):
        # Just hide instead of close
        event.ignore()
        self.hide()


class _StretchParams(object):
    def __init__(self, mode="percentile", low_p=0.5, high_p=99.5,
                 k_sigma=1.0, min_val=None, max_val=None,
                 per_channel=True, clip=True, scope="viewer",
                 display_band=None,                 # single-band index or None
                 display_mode="auto",               # "auto" | "single" | "rgb"
                 r_band=None, g_band=None, b_band=None):  # for RGB compose
        self.mode = mode
        self.low_p = float(low_p)
        self.high_p = float(high_p)
        self.k_sigma = float(k_sigma)
        self.min_val = None if min_val is None else float(min_val)
        self.max_val = None if max_val is None else float(max_val)
        self.per_channel = bool(per_channel)
        self.clip = bool(clip)
        self.scope = scope
        self.display_band = (None if display_band is None else int(display_band))
        self.display_mode = str(display_mode or "auto").lower()
        self.r_band = (None if r_band is None else int(r_band))
        self.g_band = (None if g_band is None else int(g_band))
        self.b_band = (None if b_band is None else int(b_band))

        # Optional per-band absolute ranges (used only if mode=="absolute" and per_channel==True)
        self.band_mins = None  # list[float] or None
        self.band_maxs = None  # list[float] or None

class CollapsibleBox(QtWidgets.QWidget):
    def __init__(self, title="", parent=None):
        super(CollapsibleBox, self).__init__(parent)
        from PyQt5 import QtCore, QtWidgets
        
        self.toggle_button = QtWidgets.QToolButton(text=title, checkable=True, checked=False)
        self.toggle_button.setStyleSheet("QToolButton { border: none; font-weight: bold; }")
        self.toggle_button.setToolButtonStyle(QtCore.Qt.ToolButtonTextBesideIcon)
        self.toggle_button.setArrowType(QtCore.Qt.RightArrow)
        self.toggle_button.setSizePolicy(QtWidgets.QSizePolicy.Expanding, QtWidgets.QSizePolicy.Preferred)
        self.toggle_button.toggled.connect(self._on_toggled)

        self.content_area = QtWidgets.QWidget()
        self.content_area.setVisible(False)
        
        self.main_layout = QtWidgets.QVBoxLayout(self)
        self.main_layout.setSpacing(0)
        self.main_layout.setContentsMargins(0, 0, 0, 0)
        self.main_layout.addWidget(self.toggle_button)
        self.main_layout.addWidget(self.content_area)
        
        self.content_layout = QtWidgets.QVBoxLayout(self.content_area)

    def _on_toggled(self, checked):
        from PyQt5 import QtCore, QtWidgets
        self.toggle_button.setArrowType(QtCore.Qt.DownArrow if checked else QtCore.Qt.RightArrow)
        self.content_area.setVisible(checked)
        
        # Trigger parent window to adapt its size
        p = self.parent()
        while p:
            if isinstance(p, QtWidgets.QDialog) or isinstance(p, QtWidgets.QMainWindow):
                p.adjustSize()
                break
            p = p.parent()

class ImageStretchDialog(QtWidgets.QDialog):
    resetRequested   = QtCore.pyqtSignal(str)
    applyRequested   = QtCore.pyqtSignal(object)  # emits _StretchParams without closing

    def __init__(self, parent, base_image, initial_params=None, image_filepath=""):
        super().__init__(parent)
        from PyQt5 import QtCore, QtGui, QtWidgets
        import os, json, logging
        import numpy as np

        # --- global style tweaks (consistent with ImageEditorDialog) ---
        self.setStyleSheet("""
            QWidget { font-size: 10px; }
            QLabel { margin: 0px; padding: 0px; font-size: 12px; }
            QComboBox { padding: 0px 4px; min-height: 20px; font-size: 12px; }
            QLineEdit { padding: 1px 3px; }
            QPushButton { padding: 2px 6px; min-height: 20px; }
            QToolButton { padding: 0px; }
            
            QCheckBox { font-size: 13px; }
            QCheckBox::indicator:checked {
                background-color: #FFD700; 
                border: 1px solid #006400;
            }
            QCheckBox::indicator:unchecked {
                background-color: white; 
                border: 1px solid gray;
            }
            QToolButton.collapsible-toggle {
                color: #006400; /* Dark Green text/arrow */
                font-weight: bold;
                font-size: 11pt;
            }
        """)

        self.setWindowTitle("Stretch Viewer")
        self._img = base_image
        self._init = initial_params or _StretchParams()
        self.image_filepath = image_filepath
        self.parent_tab = parent

        # ---------- choose stats source ----------
        try:
            has_classification = False
            if self.image_filepath and hasattr(self.parent_tab, "_ax_path_for"):
                ax_path = self.parent_tab._ax_path_for(self.image_filepath)
                if os.path.exists(ax_path):
                    with open(ax_path, 'r', encoding='utf-8') as f:
                        ax = json.load(f) or {}
                    cblock = ax.get("classification", {})
                    if cblock and cblock.get("enabled"):
                        has_classification = True

            if has_classification:
                stats_img = self.parent_tab.apply_aux_modifications(
                    self.image_filepath, self._img, self.parent_tab.project_folder,
                    all_polygons=getattr(self.parent_tab, "all_polygons", None),
                )
            else:
                stats_img = _preview_take3(self._img, prefer_last_band=False)
        except Exception as e:
            logging.warning(f"Stretch dialog stats source failed: {e}")
            stats_img = self._img

        # small sampler for label
        def _sample_for_stats_local(arr, k=400):
            a = np.asarray(arr)
            if a.ndim == 3:
                H, W, _ = a.shape
                stride = max(1, int(np.sqrt((H * W) / float(max(1, k)))))
                return a[::stride, ::stride, :]
            H, W = a.shape[:2]
            stride = max(1, int(np.sqrt((H * W) / float(max(1, k)))))
            return a[::stride, ::stride]

        s = _sample_for_stats_local(stats_img)
        self._real_min = float(np.nanmin(s)) if s is not None else 0.0
        self._real_max = float(np.nanmax(s)) if s is not None else 1.0

        # ---------- UI Helpers ----------
        def _fixw(widget, w):
            widget.setFixedWidth(w)
            return widget

        # ========== Sidebar Layout ==========
        main_layout = QtWidgets.QVBoxLayout(self)
        main_layout.setContentsMargins(8, 8, 8, 8)
        main_layout.setSpacing(8)

        # 1. DISPLAY & BANDS
        disp_group = CollapsibleBox("Display & Bands")
        disp_group.toggle_button.setProperty("class", "collapsible-toggle")
        disp_group.toggle_button.setChecked(True)
        disp_layout = disp_group.content_layout
        disp_form = QtWidgets.QFormLayout()
        disp_form.setSpacing(6)

        self._channels = int(self._img.shape[2]) if (hasattr(self._img, "ndim") and getattr(self._img, "ndim", 2) == 3) else 1
        
        self.cb_disp_mode = QtWidgets.QComboBox()
        self.cb_disp_mode.addItem("Auto (default)", "auto")
        self.cb_disp_mode.addItem("Single band (gray)", "single")
        self.cb_disp_mode.addItem("RGB composite", "rgb")
        if self._channels < 3:
            idx_rgb = self.cb_disp_mode.findData("rgb")
            if idx_rgb != -1:
                mi = self.cb_disp_mode.model().item(idx_rgb)
                if mi is not None: mi.setEnabled(False)

        self.cb_band = QtWidgets.QComboBox()
        for b in range(self._channels):
            label = "Band 1 (gray)" if b == 0 else f"Band {b+1}"
            self.cb_band.addItem(label, b)

        row_rgb = QtWidgets.QHBoxLayout()
        self.cb_r = QtWidgets.QComboBox(); self.cb_g = QtWidgets.QComboBox(); self.cb_b = QtWidgets.QComboBox()
