    def _note_nav_activity(self):
        """Call this on every root change / slider jump / keyboard nav."""
        self._nav_seq += 1
        # kill any per-viewer timers that might be pending
        self._cancel_all_scheduled_poly_loads()
        try:
            self._poly_idle_timer.stop()
        except Exception:
            pass

    def _on_nav_idle(self):
        """Fires once user has been idle long enough; load polygons *once*."""
        seq = self._nav_seq  # capture the latest generation
        for rec in list(getattr(self, "viewer_widgets", [])):
            v = rec.get('viewer'); idata = rec.get('image_data')
            if v and idata:
                # per-viewer schedule with 0ms because we already debounced globally
                self._schedule_polygons_for_viewer(v, idata, delay_ms=0, nav_seq=seq) 
    def _compute_stretched_preview(self, base_img, params, mask=None):
        """
        Build a DISPLAY-ONLY frame from `base_img` (your current scientific array),
        apply stretch per `params`, and return a uint8 (H,W) or (H,W,3).
        No geometry changes; no scene resets.
        
        Args:
            base_img: The source image array
            params: Stretch parameters (_StretchParams)
            mask: Optional boolean mask where True = pixels to exclude from stats
        """
        def _pick_display_stack(img, p):
            if img is None:
                return None, "none"
            if img.ndim == 2:
                return img, "gray"
            C = img.shape[2]
            mode = (p.display_mode or "auto").lower()
            if mode == "single":
                b = int(p.display_band or 0)
                b = max(0, min(C - 1, b))
                return img[..., b], "gray"
            if mode == "rgb" and C >= 3:
                rb = int(p.r_band if p.r_band is not None else 0)
                gb = int(p.g_band if p.g_band is not None else 1)
                bb = int(p.b_band if p.b_band is not None else 2)
                rb = max(0, min(C - 1, rb))
                gb = max(0, min(C - 1, gb))
                bb = max(0, min(C - 1, bb))
                return np.stack([img[..., rb], img[..., gb], img[..., bb]], axis=2), "rgb"
            # AUTO
            if C >= 3:
                return img[..., :3], "rgb"
            return img[..., 0], "gray"

        def _minmax_from_mode(x, p, mask=None):
            if x is None:
                return 0.0, 1.0
            
            # Apply mask if provided - use NaN for masked pixels
            if mask is not None:
                x_masked = x.copy().astype(np.float32)
                if x_masked.ndim == 2:
                    x_masked[mask] = np.nan
                else:
                    for c in range(x_masked.shape[2]):
                        x_masked[..., c][mask] = np.nan
            else:
                x_masked = x
            
            if (p.mode or "percentile") == "percentile":
                if x_masked.ndim == 3 and p.per_channel:
                    lo = np.nanpercentile(x_masked, p.low_p, axis=(0, 1))
                    hi = np.nanpercentile(x_masked, p.high_p, axis=(0, 1))
                else:
                    lo = np.nanpercentile(x_masked, p.low_p)
                    hi = np.nanpercentile(x_masked, p.high_p)
                return lo, hi
            elif p.mode in ("stddev", "std"):
                if x_masked.ndim == 3 and p.per_channel:
                    mu = np.nanmean(x_masked, axis=(0, 1))
                    sd = np.nanstd(x_masked, axis=(0, 1))
                else:
                    mu = np.nanmean(x_masked)
                    sd = np.nanstd(x_masked)
                lo = mu - p.k_sigma * sd
                hi = mu + p.k_sigma * sd
                return lo, hi
            else:  # absolute
                if x_masked.ndim == 3 and p.per_channel and getattr(p, "band_mins", None) and getattr(p, "band_maxs", None):
                    lo = np.asarray(p.band_mins, dtype=np.float32)
                    hi = np.asarray(p.band_maxs, dtype=np.float32)
                else:
                    lo = p.min_val if p.min_val is not None else float(np.nanmin(x_masked))
                    hi = p.max_val if p.max_val is not None else float(np.nanmax(x_masked))
                return lo, hi

        def _apply_stretch_uint8(x, lo, hi, clip=True):
            if x is None:
                return None
            x = x.astype(np.float32, copy=False)
            if np.ndim(lo) == 0:
                y = (x - float(lo)) / max(1e-12, (float(hi) - float(lo)))
            else:
                lo = np.asarray(lo, dtype=np.float32).reshape((1, 1, -1))
                hi = np.asarray(hi, dtype=np.float32).reshape((1, 1, -1))
                y = (x - lo) / np.maximum(1e-12, hi - lo)
            if clip:
                y = np.clip(y, 0.0, 1.0)
            y = np.nan_to_num(y, nan=0.0, posinf=1.0, neginf=0.0)
            out = (y * 255.0 + 0.5).astype(np.uint8)
            return out

        disp, kind = _pick_display_stack(base_img, params)

        # PERFORMANCE: Downsample large images before stretch for dialog preview
        try:
            disp, _ds_scale = _downsample_for_stretch(disp)
            # Also downsample mask if provided and downsampling occurred
            if mask is not None and _ds_scale < 1.0:
                mask = cv2.resize(mask.astype(np.uint8), (disp.shape[1], disp.shape[0]),
                                  interpolation=cv2.INTER_NEAREST).astype(bool)
        except Exception:
            pass

        lo, hi = _minmax_from_mode(disp, params, mask)
        out = _apply_stretch_uint8(disp, lo, hi, clip=params.clip)

        if out is None:
            return None
        if kind == "gray":
            return out  # (H,W)
        # Ensure 3-ch
        if out.ndim == 2:
            out = np.stack([out, out, out], axis=2)
        elif out.shape[2] == 1:
            out = np.repeat(out, 3, axis=2)
        return out


    @QtCore.pyqtSlot(object)
    def _on_stretch_apply(self, params, viewer, root_name):
        """
        Live-apply: compute a uint8 preview and swap ONLY the pixmap.
        Scope honored via params.scope: 'viewer' | 'root' | 'project'.
        """
        scope = (getattr(params, "scope", "viewer") or "viewer").lower()

        def _get_stretch_mask(v, base_img):
            """Build combined mask for stretch stats (nodata + mask polygons)."""
            if base_img is None:
                return None
            
            H, W = base_img.shape[:2]
            mask = None
            
            # Get filepath for this viewer
            fp = getattr(getattr(v, "image_data", None), "filepath", None)
            if not fp:
                return None
            
            # Get nodata values from .ax file
            nodata_values = []
            try:
                base = os.path.splitext(os.path.basename(fp))[0] + ".ax"
                pf = getattr(self, "project_folder", None)
                ax_path = os.path.join(pf, base) if pf else None
                if ax_path and os.path.exists(ax_path):
                    with open(ax_path, "r", encoding="utf-8") as f:
                        ax_cfg = json.load(f) or {}
                    nodata_values = list(ax_cfg.get("nodata_values", []) or [])
                    
                    # Check if mask_polygon is enabled
                    mp_cfg = ax_cfg.get("mask_polygon", {}) or {}
                    if isinstance(mp_cfg, dict) and mp_cfg.get("enabled", False):
                        mask_polygon_names = mp_cfg.get("names", []) or []
                        if not mask_polygon_names and mp_cfg.get("name"):
                            mask_polygon_names = [mp_cfg.get("name")]
                        
                        # Look up polygon points - O(1) using index
                        if mask_polygon_names and hasattr(self, '_get_polygons_for_filepath'):
                            for group_name, poly_data in self._get_polygons_for_filepath(fp, mask_polygon_names):
                                if isinstance(poly_data, dict):
                                    points = poly_data.get('points', [])
                                    if points and len(points) >= 3:
                                        # Scale points if needed
                                        ref_size = poly_data.get('image_ref_size', {}) or {}
                                        ref_w = ref_size.get('w', 0) or 0
                                        ref_h = ref_size.get('h', 0) or 0
                                        if ref_w > 0 and ref_h > 0 and (ref_w != W or ref_h != H):
                                            scale_x = W / float(ref_w)
                                            scale_y = H / float(ref_h)
                                            points = [(x * scale_x, y * scale_y) for (x, y) in points]
                                        
                                        # Build polygon mask
                                        pts = np.array([[int(round(x)), int(round(y))] for x, y in points], dtype=np.int32)
                                        pts = pts.reshape((-1, 1, 2))
                                        poly_mask = np.zeros((H, W), dtype=np.uint8)
                                        cv2.fillPoly(poly_mask, [pts], 255)
                                        if mask is None:
                                            mask = poly_mask > 0
                                        else:
                                            mask = mask | (poly_mask > 0)
            except Exception:
                pass
            
            # Add nodata mask using shared function
            if nodata_values:
                from .utils import build_nodata_mask as _shared_build_nodata_mask
                nd_mask = _shared_build_nodata_mask(base_img, nodata_values, bgr_input=True)
                if nd_mask is not None:
                    if mask is None:
                        mask = nd_mask
                    else:
                        mask = mask | nd_mask

            
            return mask

        def _apply_to_viewer(v):
            try:
                base_img = getattr(getattr(v, "image_data", None), "image", None)
                if base_img is None:
                    return
                # Get mask for stretch stats (nodata + mask polygons)
                mask = _get_stretch_mask(v, base_img)
                preview = self._compute_stretched_preview(base_img, params, mask)
                if preview is None:
                    return
                # remember params per-viewer for consistency
                setattr(v, "stretch_params", params)
                v.show_preview_array(preview)  # swaps pixmap only; overlays intact
            except Exception:
                pass

        if scope == "project":
            for v in self._all_open_viewers():
                _apply_to_viewer(v)
            return

        if scope == "root" and root_name:
            target_files = set(self._filepaths_for_loaded_root(root_name))
            for v in self._all_open_viewers():
                # try both attributes to be safe
                fp = getattr(v, "filepath", None) or getattr(getattr(v, "image_data", None), "filepath", None)
                if fp and fp in target_files:
                    _apply_to_viewer(v)
            return

        # default: only this viewer
        if viewer is not None:
            _apply_to_viewer(viewer)
  
    @staticmethod
    def _apply_hist_match(img, mods, *args, fast=True, max_samples=None, nodata_values=None,
                          mask_polygon_points=None, mask_polygon_enabled=False):
        """
        Histogram normalization used by ProjectTab viewers.
        - Mean/Std path: Uses LUT for uint8 only (fast). Full float precision for 16-bit/float.
        - CDF path: fast LUT using histogram bins (per band), semantics aligned with editor.
        - Keeps original dtype for integer images.
        - PRESERVES FULL PRECISION for 16-bit and float images.
        - NoData values are excluded from statistics and preserved unchanged.
        - Mask polygon pixels are excluded from statistics and preserved unchanged.

        Compatibility: accepts an optional 3rd positional arg (old callers pass a big int).
        """
        import numpy as np
        import cv2

        # Back-compat: some callers pass a 3rd positional "max_samples"
        if args and max_samples is None:
            try:
                max_samples = int(args[0])
            except Exception:
                max_samples = None

        if img is None or getattr(img, "size", 0) == 0:
            return img

        hcfg = (mods or {}).get("hist_match")
        if not hcfg:
            return img

        mode = (hcfg.get("mode") or "meanstd").lower()
        bands_cfg = int(hcfg.get("bands", 0)) if hcfg.get("bands", 0) else 0

        src_dtype = img.dtype
        H, W = img.shape[:2]
        C = img.shape[2] if img.ndim == 3 else 1
        twoD = (img.ndim == 2)
        bands = min(bands_cfg if bands_cfg > 0 else C, C)

        # Build combined mask (NoData + polygon)
        combined_mask = None
        
        # NoData mask
        if nodata_values:
            x_test = img.astype(np.float32, copy=False)
            if x_test.ndim == 2:
                x_test = x_test[..., None]
            combined_mask = np.zeros((H, W), dtype=bool)
            for v in nodata_values:
                try:
                    fv = float(v)
                    abs_fv = abs(fv)
                    if abs_fv > 1e+30:
                        tol = abs_fv * 0.01
                    elif abs_fv > 1e+10:
                        tol = abs_fv * 0.001
                    elif abs_fv > 100:
                        tol = abs_fv * 0.001
                    else:
                        tol = 0.01
                    for c in range(min(C, x_test.shape[2] if x_test.ndim == 3 else 1)):
                        ch = x_test[..., c] if x_test.ndim == 3 else x_test
                        combined_mask |= np.isclose(ch, fv, rtol=0.0, atol=tol)
                except Exception:
                    pass
            # Also check for NaN/Inf
            for c in range(min(C, x_test.shape[2] if x_test.ndim == 3 else 1)):
                ch = x_test[..., c] if x_test.ndim == 3 else x_test
                combined_mask |= np.isnan(ch)
                combined_mask |= np.isinf(ch)
        
        # Polygon mask (can be a list of polygon point lists)
        if mask_polygon_enabled and mask_polygon_points:
            # Handle both single polygon (legacy) and list of polygons
            polygon_list = mask_polygon_points
            # Check if this is a legacy single polygon format (list of tuples)
            if polygon_list and len(polygon_list) > 0:
                first_item = polygon_list[0]
                # If first item is a tuple/list of 2 numbers, it's a single polygon
                if isinstance(first_item, (list, tuple)) and len(first_item) == 2:
                    try:
                        float(first_item[0])  # Test if it's a coordinate
                        float(first_item[1])
                        # It's a legacy single polygon format
                        polygon_list = [mask_polygon_points]
                    except (TypeError, ValueError):
                        pass  # It's a list of polygons
            
            # Build combined mask from all polygons
            poly_mask_combined = np.zeros((H, W), dtype=bool)
            for poly_pts in polygon_list:
                if poly_pts and len(poly_pts) >= 3:
                    pts = np.array([[int(round(x)), int(round(y))] for x, y in poly_pts], dtype=np.int32)
                    pts = pts.reshape((-1, 1, 2))
                    poly_mask = np.zeros((H, W), dtype=np.uint8)
                    cv2.fillPoly(poly_mask, [pts], 255)
                    poly_mask_combined |= (poly_mask > 0)
            
            if poly_mask_combined.any():
                if combined_mask is None:
                    combined_mask = poly_mask_combined
                else:
                    combined_mask = combined_mask | poly_mask_combined
        
        # Use combined_mask instead of nodata_mask throughout
        nodata_mask = combined_mask

        # --- small, safe sampler for stats (to keep UI snappy) ---
        def _sample_stride(h, w, target_pixels=90000):
            # ~300x300 sample for stats
            total = h * w
            if total <= target_pixels:
                return 1
            return max(1, int(np.sqrt(total / target_pixels)))

        # ------------- MEAN/STD -------------
        if mode == "meanstd":
            ref = hcfg.get("ref_stats") or []
            C2 = min(bands, len(ref))
            if C2 == 0:
                return img

            # Compute stats on a SAMPLE only
            s = _sample_stride(H, W, 90000)
            if twoD:
                samp = img[::s, ::s] if s > 1 else img
            else:
                samp = img[::s, ::s, :C2] if s > 1 else img[:, :, :C2]
            samp_f = samp.astype(np.float32, copy=False)
            if samp_f.ndim == 2:
                samp_f = samp_f[..., None]

            # Apply nodata mask to sample for stats
            if nodata_mask is not None:
                samp_mask = nodata_mask[::s, ::s] if s > 1 else nodata_mask
                # Mask nodata as NaN for stats calculation
                samp_f = samp_f.copy()
                for c in range(C2):
                    samp_f[..., c] = np.where(samp_mask, np.nan, samp_f[..., c])

            mu_t = np.nanmean(samp_f, axis=(0, 1)).astype(np.float32)
            sd_t = np.nanstd(samp_f, axis=(0, 1)).astype(np.float32)
            sd_t = np.where(sd_t < 1e-6, 1.0, sd_t)

            mu_r = np.array([float(ref[i].get("mean", 0.0)) for i in range(C2)], dtype=np.float32)
            sd_r = np.array([float(ref[i].get("std", 1.0)) for i in range(C2)], dtype=np.float32)

            # FAST PATH: Use 256-entry LUT for uint8 ONLY (no precision loss)
            if src_dtype == np.uint8:
                out = img.copy()
                for c in range(C2):
                    # Linear transform: out = (in - mu_t) * (sd_r/sd_t) + mu_r
                    gain = float(sd_r[c] / sd_t[c])
                    offset = float(mu_r[c] - mu_t[c] * gain)
                    # Build 256-entry LUT (exact for uint8)
                    lut = np.arange(256, dtype=np.float32) * gain + offset
                    lut = np.clip(lut, 0, 255).astype(np.uint8)
                    if twoD:
                        new_vals = lut[out]
                        if nodata_mask is not None:
                            out = np.where(nodata_mask, out, new_vals)
                        else:
                            out = new_vals
                    else:
                        new_vals = lut[out[..., c]]
                        if nodata_mask is not None:
                            out[..., c] = np.where(nodata_mask, out[..., c], new_vals)
                        else:
                            out[..., c] = new_vals
                return out

            # FULL PRECISION PATH: For 16-bit and float images
            # Use vectorized float operations to preserve all precision
            x = img.astype(np.float32, copy=True)
            orig_x = x.copy() if nodata_mask is not None else None
            if twoD:
                x = x[..., None]
                if orig_x is not None:
                    orig_x = orig_x[..., None]

            gain = (sd_r / sd_t).reshape(1, 1, C2)
            x_view = x[:, :, :C2]
            x_view -= mu_t.reshape(1, 1, C2)
            x_view *= gain
            x_view += mu_r.reshape(1, 1, C2)

            # Restore nodata values
            if nodata_mask is not None and orig_x is not None:
                for c in range(C2):
                    x[:, :, c] = np.where(nodata_mask, orig_x[:, :, c], x[:, :, c])

            out = x[..., 0] if twoD else x
            if np.issubdtype(src_dtype, np.integer):
                info = np.iinfo(src_dtype)
                out = np.clip(out, info.min, info.max).astype(src_dtype, copy=False)
            return out

        # ------------- CDF -------------
        if mode == "cdf":
            refcdf = (hcfg.get("ref_cdf") or {}).get("per_band") or []

            # Need float working copy for CDF (preserves precision during transform)
            x = img.astype(np.float32, copy=True)
            orig_x = x.copy() if nodata_mask is not None else None
            if twoD:
                x = x[..., None]
                if orig_x is not None:
                    orig_x = orig_x[..., None]

            # Sample stride for histogram computation (stats only, not transform)
            s = _sample_stride(H, W, 90000)

            for c in range(min(bands, len(refcdf))):
                ch = x[..., c]
                info = refcdf[c] or {}

                lo = float(info.get("lo", 0.0))
                hi = float(info.get("hi", 1.0))
                if not np.isfinite(lo) or not np.isfinite(hi) or hi <= lo:
                    # fallback: compute percentiles on SAMPLE only
                    ch_samp = ch[::s, ::s] if s > 1 else ch
                    # Exclude nodata from percentile calculation
                    if nodata_mask is not None:
                        samp_mask = nodata_mask[::s, ::s] if s > 1 else nodata_mask
                        finite = np.isfinite(ch_samp) & ~samp_mask
                    else:
                        finite = np.isfinite(ch_samp)
                    if np.any(finite):
                        lo = float(np.nanpercentile(ch_samp[finite], 0.01))
                        hi = float(np.nanpercentile(ch_samp[finite], 99.99))
                        if not np.isfinite(lo) or not np.isfinite(hi) or hi <= lo:
                            lo, hi = 0.0, 1.0
                    else:
                        lo, hi = 0.0, 1.0

                x_ref_n = np.asarray(info.get("x", [0.0, 1.0]), dtype=np.float32)
                y_ref = np.asarray(info.get("y", [0.0, 1.0]), dtype=np.float32)

                # Compute histogram on SAMPLE for speed
                ch_samp = ch[::s, ::s] if s > 1 else ch
                z_samp = np.clip((ch_samp - lo) / (hi - lo), 0.0, 1.0)

                # Use fine bins for histogram (stats estimation)
                bins = 4096
                idx_samp = np.clip((z_samp * (bins - 1)).astype(np.int32), 0, bins - 1)
                
                # Exclude nodata from histogram
                if nodata_mask is not None:
                    samp_mask = nodata_mask[::s, ::s] if s > 1 else nodata_mask
                    valid_idx = idx_samp[~samp_mask]
                    hist = np.bincount(valid_idx.ravel(), minlength=bins).astype(np.float32)
                else:
                    hist = np.bincount(idx_samp.ravel(), minlength=bins).astype(np.float32)
                cdf_src = np.cumsum(hist)
                cdf_src /= max(float(cdf_src[-1]), 1.0)
                
                # Build LUT for the bins
                xprime_norm = np.interp(cdf_src, y_ref, x_ref_n).astype(np.float32)

                # Apply to FULL image with full float precision
                # Normalize full channel
                z_full = np.clip((ch - lo) / (hi - lo), 0.0, 1.0)
                # Map to bin indices (for LUT lookup)
                idx_full = np.clip((z_full * (bins - 1)).astype(np.int32), 0, bins - 1)
                # Apply LUT and denormalize
                new_vals = xprime_norm[idx_full] * (hi - lo) + lo
                
                # Restore nodata values
                if nodata_mask is not None and orig_x is not None:
                    ch[:] = np.where(nodata_mask, orig_x[..., c], new_vals)
                else:
                    ch[:] = new_vals

            out = x[..., 0] if twoD else x
            if np.issubdtype(src_dtype, np.integer):
                info = np.iinfo(src_dtype)
                out = np.clip(out, info.min, info.max).astype(src_dtype, copy=False)
            return out

        # Unknown mode -> no-op
        return img

    def _apply_hist_match_np(arr, block):
        import numpy as np
        if arr is None or getattr(arr, "size", 0) == 0 or not isinstance(block, dict):
            return arr
        src_dtype = arr.dtype
        f = arr.astype(np.float32, copy=False)
        if f.ndim == 2:
            f = f[..., None]
        mode = (block.get("mode") or "").lower()
        bands = int(block.get("bands", f.shape[2]))
        eps = 1e-6

        if mode == "meanstd":
            ref = block.get("ref_stats") or []
            for c in range(min(bands, f.shape[2], len(ref))):
                ch = f[..., c]
                m_src = float(np.nanmean(ch))
                s_src = float(np.nanstd(ch))
                m_ref = float(ref[c].get("mean", m_src))
                s_ref = float(ref[c].get("std", s_src))
                if s_src < eps:
                    ch_m = (ch - m_src) + m_ref
                else:
                    ch_m = (ch - m_src) * (s_ref / max(s_src, eps)) + m_ref
                f[..., c] = ch_m

        elif mode == "cdf":
            refcdf = (block.get("ref_cdf") or {}).get("per_band") or []
            for c in range(min(bands, f.shape[2], len(refcdf))):
                ch = f[..., c]
                info = refcdf[c]
                lo = float(info.get("lo", 0.0)); hi = float(info.get("hi", 1.0))
                if hi <= lo + eps:
                    continue
                x_ref = np.asarray(info.get("x", [0.0, 1.0]), dtype=np.float32) * (hi - lo) + lo
                y_ref = np.asarray(info.get("y", [0.0, 1.0]), dtype=np.float32)
                flat = ch.reshape(-1)
                flat = flat[~np.isnan(flat)]
                if flat.size == 0:
                    continue
                xs = np.linspace(float(np.min(flat)), float(np.max(flat)), x_ref.size).astype(np.float32)
                flat_sorted = np.sort(flat)
                idx = np.searchsorted(flat_sorted, xs, side="right")
                ys = (idx / float(flat_sorted.size)).astype(np.float32)

                def inv_ref(p):
                    return np.interp(p, y_ref, x_ref, left=x_ref[0], right=x_ref[-1]).astype(np.float32)
                xprime = inv_ref(ys)
                ch[:] = np.interp(ch, xs, xprime, left=xprime[0], right=xprime[-1]).astype(np.float32)

        if f.shape[2] == 1:
            f = f[..., 0]

        if np.issubdtype(src_dtype, np.integer):
            info = np.iinfo(src_dtype)
            f = np.clip(f, info.min, info.max).astype(src_dtype, copy=False)
        else:
            f = f.astype(np.float32, copy=False)
        return f

    @staticmethod
    def apply_aux_modifications(image_filepath,
                                image,
                                project_folder=None,
                                global_mode=False,
                                *,
                                export_label_band=False,      # NEW: when True, append expr + labels as bands
                                _float_dtype=np.float32,      # keep numeric stability consistent
                                all_polygons=None):           # for mask_polygon name lookup
        """
        Apply edits recorded in the .ax in the SAME order the editor saved.
        Pixel order: crop -> rotate -> hist_match -> resize -> band_expression -> classification

        Viewer (default): classification is terminal and returns a colorized (RGB) or label map.
        Export (export_label_band=True): append band_expression and label-map as extra bands at the end.
        """
        import os, json, logging, cv2, numpy as np

        HIST_MAX_SAMPLES = 250

        # ---------- locate .ax ----------
        if global_mode:
            mod_filename = (
                os.path.join(project_folder, "global.ax")
                if project_folder and project_folder.strip()
                else os.path.join(os.path.dirname(image_filepath), "global.ax")
            )
        else:
            base = os.path.splitext(os.path.basename(image_filepath))[0] + ".ax"
            mod_filename = (
                os.path.join(project_folder, base)
                if project_folder and project_folder.strip()
                else os.path.splitext(image_filepath)[0] + ".ax"
            )

        if not os.path.exists(mod_filename) or image is None or getattr(image, "size", 0) == 0:
            return image

        try:
            with open(mod_filename, "r", encoding="utf-8") as f:
                ax = json.load(f) or {}
        except Exception as e:
            logging.error(f"Failed to load aux modifications from {mod_filename}: {e}")
            return image

        # --- start with a scientific copy (RGB order if needed) ---
        result = np.array(image, copy=True)
        #if result.ndim == 3 and result.shape[2] == 3:
            #result = cv2.cvtColor(result, cv2.COLOR_BGR2RGB)

        # ---- parse params ----
        try:
            rot = int(ax.get("rotate", 0)) % 360
        except Exception:
            rot = 0
        crop_rect = ax.get("crop_rect") or None
        crop_ref  = ax.get("crop_rect_ref_size") or None
        resize    = ax.get("resize") or None
        expr_str  = (ax.get("band_expression") or "").strip()
        op_order  = ax.get("op_order") or ["crop","rotate","hist","resize","band_expression"]
        
        # ---- parse enabled flags (default True for backward compatibility) ----
        rotate_enabled = ax.get("rotate_enabled", True)
        crop_enabled = ax.get("crop_enabled", True)
        resize_enabled = ax.get("resize_enabled", True)
        hist_enabled = ax.get("hist_enabled", True)
        band_enabled = ax.get("band_enabled", True)
        
        # NoData values - only use if enabled (default True if not specified)
        nodata_enabled = ax.get("nodata_enabled", True)
        if nodata_enabled:
            nodata_values = list(ax.get("nodata_values", []) or [])
        else:
            nodata_values = []

        # Mask polygon - only use if enabled (names-based lookup)
        mask_polygon_cfg = ax.get("mask_polygon", {}) or {}
        mask_polygon_enabled = bool(mask_polygon_cfg.get("enabled", False)) if isinstance(mask_polygon_cfg, dict) else False
        mask_polygon_names = mask_polygon_cfg.get("names", []) if isinstance(mask_polygon_cfg, dict) else []
        
        # Legacy: support old single-name format
        if not mask_polygon_names and mask_polygon_cfg.get("name"):
            mask_polygon_names = [mask_polygon_cfg.get("name")]
        
        # Also support legacy points format (direct points in .ax)
        mask_polygon_points_list = []
        legacy_points = mask_polygon_cfg.get("points", []) if isinstance(mask_polygon_cfg, dict) else []
        if legacy_points and len(legacy_points) >= 3:
            mask_polygon_points_list.append(legacy_points)
        
        # Look up polygon points by name from all_polygons
        # Note: points will be scaled after transformations are applied to match final image size
        # CRITICAL: Also try loading from disk to get fresh data
        _mask_polygon_raw_data = []  # Store (points, ref_size) tuples for later scaling
        if mask_polygon_enabled and mask_polygon_names:
            # FIRST: Try to load from disk (most up-to-date)
            polygons_dir = os.path.join(project_folder, "polygons") if project_folder else None
            if polygons_dir and os.path.exists(polygons_dir):
                image_base = os.path.splitext(os.path.basename(image_filepath))[0]
                for mask_name in mask_polygon_names:
                    json_path = os.path.join(polygons_dir, f"{mask_name}_{image_base}_polygons.json")
                    if os.path.exists(json_path):
                        try:
                            with open(json_path, 'r', encoding='utf-8') as f:
                                poly_data = json.load(f)
                            if isinstance(poly_data, dict):
                                points = poly_data.get('points', [])
                                if points and len(points) >= 3:
                                    ref_size = poly_data.get('image_ref_size', {}) or {}
                                    _mask_polygon_raw_data.append((points, ref_size))
                                    logging.debug(f"[apply_all_modifications] Loaded mask polygon '{mask_name}' from disk")
                        except Exception as e:
                            logging.debug(f"[apply_all_modifications] Failed to load mask from disk: {e}")
            
            # SECOND: If not found on disk, try from all_polygons parameter
            # PERFORMANCE: Use O(1) index lookup if available
            if not _mask_polygon_raw_data and all_polygons:
                # Try to use the fast indexed lookup if available on self
                if hasattr(self, '_get_polygons_for_filepath'):
                    for group_name, poly_data in self._get_polygons_for_filepath(image_filepath, mask_polygon_names):
                        if isinstance(poly_data, dict):
                            points = poly_data.get('points', [])
                            if points and len(points) >= 3:
                                ref_size = poly_data.get('image_ref_size', {}) or {}
                                _mask_polygon_raw_data.append((points, ref_size))
                else:
                    # Fallback to O(N) iteration if index not available
                    fp_norm = os.path.normpath(image_filepath).lower()
                    for group_name, file_map in all_polygons.items():
                        for stored_fp, poly_data in file_map.items():
                            stored_fp_norm = os.path.normpath(stored_fp).lower() if stored_fp else ""
                            if stored_fp_norm == fp_norm:
                                if isinstance(poly_data, dict):
                                    poly_name = poly_data.get('name', group_name)
                                    if poly_name in mask_polygon_names:
                                        points = poly_data.get('points', [])
                                        if points and len(points) >= 3:
                                            ref_size = poly_data.get('image_ref_size', {}) or {}
                                            _mask_polygon_raw_data.append((points, ref_size))

        # ---------- Determine crop/rotate order based on crop_rect_ref_size ----------
        # crop_rect_ref_size tells us which reference frame the crop was drawn in:
        # - If matches ORIGINAL dims → user cropped BEFORE rotating → do CROP first
        # - If matches ROTATED dims → user rotated BEFORE cropping → do ROTATE first
        raw_h, raw_w = result.shape[:2]
        rotated_w, rotated_h = (raw_h, raw_w) if rot in (90, 270) else (raw_w, raw_h)
        
        do_rotate_first = True  # Default: rotate first
        if crop_enabled and crop_rect and rot in (90, 180, 270):
            if isinstance(crop_ref, dict) and "w" in crop_ref and "h" in crop_ref:
                ref_w = int(crop_ref.get("w", 0)) or 0
                ref_h = int(crop_ref.get("h", 0)) or 0
                if ref_w > 0 and ref_h > 0:
                    # If ref matches original dims → crop was drawn BEFORE rotate
                    if (ref_w, ref_h) == (raw_w, raw_h):
                        do_rotate_first = False
                    # If ref matches rotated dims → crop was drawn AFTER rotate
                    elif (ref_w, ref_h) == (rotated_w, rotated_h):
                        do_rotate_first = True

        # ---------- helper to build nodata mask (uses shared utility supporting expressions) ----------
        def _build_nodata_mask(arr, nd_vals):
            """Build boolean mask where True = NoData pixel. Supports both numeric literals and threshold expressions."""
            from .utils import build_nodata_mask as _shared_build_nodata_mask
            return _shared_build_nodata_mask(arr, nd_vals, bgr_input=True)

        # ---------- helpers ----------
        def resize_safe(img_, new_w, new_h, interp=cv2.INTER_LINEAR):
            """
            Stack-safe resize:
              - 2D → single cv2.resize
              - 3D & C<=4 → single cv2.resize
              - 3D & C>4 → per-band resize + stack
            Preserves dtype and avoids unnecessary work.
            """
            import numpy as np, cv2

            if img_ is None:
                return None

            # Avoid unnecessary resizes
            h0, w0 = img_.shape[:2]
            if h0 <= 0 or w0 <= 0 or (new_w == w0 and new_h == h0):
                return img_

            img = np.ascontiguousarray(img_)  # cv2 prefers contiguous

            if img.ndim == 2:
                return cv2.resize(img, (new_w, new_h), interpolation=interp)

            if img.ndim == 3:
                c = img.shape[2]
                if c <= 4:
                    return cv2.resize(img, (new_w, new_h), interpolation=interp)

                # Fallback for stacks (>4 bands)
                bands = []
                for i in range(c):
                    bi = cv2.resize(img[..., i], (new_w, new_h), interpolation=interp)
                    bands.append(bi)
                out = np.stack(bands, axis=2)

                # keep original dtype if possible
                if out.dtype != img.dtype:
                    out = out.astype(img.dtype, copy=False)
                return out

            # Unexpected ndim (rare) – try generic path
            return cv2.resize(img, (new_w, new_h), interpolation=interp)


        def _do_rotate():
            nonlocal result
            if not rotate_enabled:
                return
            if not rot:
                return
            try:
                if rot == 90:
                    result = np.rot90(result, k=3)  # cv2-style cw
                elif rot == 180:
                    result = np.rot90(result, k=2)
                elif rot == 270:
                    result = np.rot90(result, k=1)
            except Exception as e:
                logging.warning(f"Rotate failed: {e}")

        def _do_crop():
            nonlocal result
            if not crop_enabled:
                return
            if not (isinstance(crop_rect, dict) and crop_rect):
                return
            try:
                h0, w0 = result.shape[:2]
                if h0 <= 0 or w0 <= 0:
                    return
                # map from saved ref size to current image
                if isinstance(crop_ref, dict) and "w" in crop_ref and "h" in crop_ref:
                    refW = max(1, int(crop_ref.get("w") or w0))
                    refH = max(1, int(crop_ref.get("h") or h0))
                else:
                    refW, refH = (w0, h0)
                x = int(crop_rect.get("x", 0)); y = int(crop_rect.get("y", 0))
                rw = int(crop_rect.get("width", w0)); rh = int(crop_rect.get("height", h0))
                sx = w0 / float(max(1, refW)); sy = h0 / float(max(1, refH))
                xi = max(0, int(round(x * sx))); yi = max(0, int(round(y * sy)))
                xe = min(w0, xi + max(1, int(round(rw * sx))))
                ye = min(h0, yi + max(1, int(round(rh * sy))))
                result = result[yi:ye, xi:xe, ...] if result.ndim == 3 else result[yi:ye, xi:xe]
            except Exception as e:
                logging.warning(f"Crop failed: {e}")

        def _do_hist():
            nonlocal result, mask_polygon_points_list
            if not hist_enabled:
                return
            
            # Scale mask polygon points to match current image dimensions
            if mask_polygon_enabled and _mask_polygon_raw_data:
                cur_h, cur_w = result.shape[:2]
                mask_polygon_points_list = []  # Reset and rebuild with scaling
                for points, ref_size in _mask_polygon_raw_data:
                    ref_w = ref_size.get('w', 0) or 0
                    ref_h = ref_size.get('h', 0) or 0
                    if ref_w > 0 and ref_h > 0 and (ref_w != cur_w or ref_h != cur_h):
                        # Scale points from ref size to current image size
                        scale_x = cur_w / float(ref_w)
                        scale_y = cur_h / float(ref_h)
                        scaled_points = [(x * scale_x, y * scale_y) for (x, y) in points]
                        mask_polygon_points_list.append(scaled_points)
                    else:
                        mask_polygon_points_list.append(points)
            
            try:
                result = ProjectTab._apply_hist_match(result, ax, fast=True, max_samples=HIST_MAX_SAMPLES, 
                                                      nodata_values=nodata_values,
                                                      mask_polygon_points=mask_polygon_points_list,
                                                      mask_polygon_enabled=mask_polygon_enabled)
            except TypeError:
                # Fallback if function doesn't support mask_polygon
                try:
                    result = ProjectTab._apply_hist_match(result, ax, fast=True, max_samples=HIST_MAX_SAMPLES, 
                                                          nodata_values=nodata_values)
                except TypeError:
                    try:
                        result = ProjectTab._apply_hist_match(result, ax, fast=True, max_samples=HIST_MAX_SAMPLES)
                    except Exception as e:
                        logging.warning(f"hist_match failed: {e}")
            except Exception as e:
                logging.warning(f"hist_match failed: {e}")

        def _do_resize():
            nonlocal result
            if not resize_enabled:
                return
            if not isinstance(resize, dict) or not resize:
                return
            try:
                h0, w0 = result.shape[:2]
                if h0 <= 0 or w0 <= 0:
                    return
                if "px_w" in resize or "px_h" in resize:
                    tw = int(resize.get("px_w", 0)); th = int(resize.get("px_h", 0))
                    if   tw > 0 and th > 0: new_w, new_h = tw, th
                    elif tw > 0:            s = tw / float(w0); new_w, new_h = tw, max(1, int(round(h0 * s)))
                    elif th > 0:            s = th / float(h0); new_h, new_w = th, max(1, int(round(w0 * s)))
                    else: return
                elif "scale" in resize:
                    s = float(resize.get("scale", 100.0)) / 100.0
                    new_w, new_h = max(1, int(round(w0 * s))), max(1, int(round(h0 * s)))
                else:
                    pw = float(resize.get("width", 100.0))  / 100.0
                    ph = float(resize.get("height", 100.0)) / 100.0
                    new_w, new_h = max(1, int(round(w0 * pw))), max(1, int(round(h0 * ph)))
                interp = cv2.INTER_AREA if (new_w < w0 or new_h < h0) else (cv2.INTER_LINEAR if max(new_w/w0, new_h/h0) < 2.0 else cv2.INTER_CUBIC)
                
                # Handle NoData during resize using NaN propagation:
                # 1. Replace NoData with NaN before resize
                # 2. Resize - any pixel touching NaN becomes NaN
                # 3. Replace NaN with NoData value after resize
                # IMPORTANT: Only use numeric NoData values for restoration (not expression strings)
                nd_restore_val = None
                for nv in (nodata_values or []):
                    if not isinstance(nv, str):  # Skip expression strings
                        try:
                            nd_restore_val = float(nv)
                            break
                        except (ValueError, TypeError):
                            pass
                
                if nodata_values and nd_restore_val is not None:
                    # Convert to float32 and replace NoData with NaN
                    orig_dtype = result.dtype
                    work = result.astype(np.float32, copy=True)
                    nd_mask = _build_nodata_mask(result, nodata_values)
                    if nd_mask is not None and nd_mask.any():
                        if work.ndim == 2:
                            work[nd_mask] = np.nan
                        else:
                            for c in range(work.shape[2]):
                                work[..., c][nd_mask] = np.nan
                    
                    # Resize - NaN propagates through interpolation
                    work = resize_safe(work, new_w, new_h, interp)
                    
                    # Replace NaN with NoData value
                    nan_mask = np.isnan(work)
                    if nan_mask.any():
                        work[nan_mask] = nd_restore_val
                    
                    result = work
                else:
                    # No NoData - standard resize
                    result = resize_safe(result, new_w, new_h, interp)
            except Exception as e:
                logging.warning(f"Resize failed: {e}")

        def _do_registration():
            nonlocal result
            # --- REGISTRATION (applied BEFORE crop/rotate) ---
            # The matrix was calculated on CROPPED images for accuracy, but we apply it
            # to the RAW image and translate the matrix from crop-space to raw-space.
            # This allows the warp to pull pixels from outside the crop boundary,
            # producing clean alignment without black borders.
            reg_cfg = ax.get("registration") or {}
            if isinstance(reg_cfg, dict) and reg_cfg.get("enabled") and reg_cfg.get("matrix") is not None:
                try:
                    import pystackreg
                    mat_list = reg_cfg["matrix"]
                    tmat = np.array(mat_list, dtype=np.float64)
                
                    # Determine mode from string or infer
                    mode_str = str(reg_cfg.get("mode", "")).lower()
                
                    was_uint8 = (result.dtype == np.uint8)
                    was_int = np.issubdtype(result.dtype, np.integer)
                
                    try:
                        import cv2
                        h, w = result.shape[:2]
                    
                        # Convert 4x4 affine matrices (e.g. from Bilinear mode) to 3x3 for OpenCV
                        if tmat.shape == (4, 4):
                             tmat_3x3 = np.zeros((3, 3), dtype=np.float64)
                             tmat_3x3[0:2, 0:2] = tmat[0:2, 0:2]
                             tmat_3x3[0:2, 2] = tmat[0:2, 3]
                             tmat_3x3[2, :] = [0, 0, 1]
                             tmat = tmat_3x3
                        elif tmat.shape != (3, 3):
                             raise ValueError(f"Matrix shape {tmat.shape} not supported by OpenCV warp")
                        
                        # --- 1. RESOLVE SCALE INVARIANCE ---
                        # tmat was computed on a `calc_shape` image, representing the area inside the crop box
                        # Calculate the expected crop dimensions in RAW pixels for comparison
                        expected_w, expected_h = w, h # default if no crop
                        _crop_rect = crop_rect
                        _crop_ref  = crop_ref
                        
                        cx, cy = 0, 0
                        if crop_enabled and isinstance(_crop_rect, dict) and _crop_rect:
                            cw = int(_crop_rect.get("width", 0)) or 0
                            ch = int(_crop_rect.get("height", 0)) or 0
                            cx = int(_crop_rect.get("x", 0))
                            cy = int(_crop_rect.get("y", 0))
                            if isinstance(_crop_ref, dict) and "w" in _crop_ref and "h" in _crop_ref:
                                refW = max(1, int(_crop_ref.get("w") or w))
                                refH = max(1, int(_crop_ref.get("h") or h))
                                expected_w = int(round(cw * (w / float(refW))))
                                expected_h = int(round(ch * (h / float(refH))))
                                cx = int(round(cx * (w / float(refW))))
                                cy = int(round(cy * (h / float(refH))))
                            else:
                                expected_w, expected_h = cw, ch

                        calc_shape = reg_cfg.get("calc_shape")
                        if calc_shape and isinstance(calc_shape, list) and len(calc_shape) == 2:
                            calc_w, calc_h = calc_shape
                            if calc_w > 0 and calc_h > 0 and (calc_w, calc_h) != (expected_w, expected_h):
                                sx = expected_w / float(calc_w)
                                sy = expected_h / float(calc_h)
                                S = np.array([[sx, 0, 0], [0, sy, 0], [0, 0, 1]], dtype=np.float64)
                                S_inv = np.array([[1/sx, 0, 0], [0, 1/sy, 0], [0, 0, 1]], dtype=np.float64)
                                # MATHEMATICAL FIX FOR SCALE: S @ tmat @ S_inv
                                # We scale the translation components by S, and preserve affine components.
                                tmat = S @ tmat @ S_inv
                                logging.info(f"[REG VIEWER] SCALE APPLIED: sx={sx:.2f}, sy={sy:.2f}")

                        # --- 2. COORDINATE TRANSLATION: crop-space -> raw-space ---
                        # tmat now maps the crop exactly. We want to apply it to the RAW image of size (w, h). 
                        # We translate using M_raw = T_crop @ M_crop @ T_crop_inv
                        if cx != 0 or cy != 0:
                            T_crop = np.array([[1, 0, cx], [0, 1, cy], [0, 0, 1]], dtype=np.float64)
                            T_crop_inv = np.array([[1, 0, -cx], [0, 1, -cy], [0, 0, 1]], dtype=np.float64)
                            tmat = T_crop @ tmat @ T_crop_inv
                            logging.info(f"[REG VIEWER] TRANSLATION APPLIED: cx={cx} cy={cy}")
                    
                        # pystackreg matrix is Dst->Src mapping, use WARP_INVERSE_MAP
                        is_perspective = "bilinear" in mode_str or not np.allclose(tmat[2, :2], 0)
                        flags = cv2.INTER_LINEAR | cv2.WARP_INVERSE_MAP
                    
                        C_out = 1 if result.ndim == 2 else result.shape[2]
                    
                        def _warp_block_viewer(block):
                            if is_perspective:
                                return cv2.warpPerspective(block, tmat, (w, h), flags=flags, borderMode=cv2.BORDER_CONSTANT, borderValue=0)
                            else:
                                return cv2.warpAffine(block, tmat[:2, :], (w, h), flags=flags, borderMode=cv2.BORDER_CONSTANT, borderValue=0)
                    
                        if C_out <= 4:
                            result = _warp_block_viewer(result)
                            if C_out == 1 and result.ndim == 2:
                                result = result[..., None]
                        else:
                            warped_bands = []
                            for c in range(C_out):
                                warped_bands.append(_warp_block_viewer(result[..., c]))
                            result = np.stack(warped_bands, axis=2)
                        
                    except Exception as cv_e:
                        logging.warning(f"OpenCV warp failed, falling back to pystackreg: {cv_e}")
                        import pystackreg
                        sr_mode = pystackreg.StackReg.RIGID_BODY
                        if "translation" in mode_str: sr_mode = pystackreg.StackReg.TRANSLATION
                        elif "scaled" in mode_str: sr_mode = pystackreg.StackReg.SCALED_ROTATION
                        elif "affine" in mode_str: sr_mode = pystackreg.StackReg.AFFINE
                        elif "bilinear" in mode_str: sr_mode = pystackreg.StackReg.BILINEAR
                    
                        sr = pystackreg.StackReg(sr_mode)
                    
                        def _apply_reg_2d(plane):
                            f_plane = plane.astype(np.float32)
                            return sr.transform(f_plane, tmat=tmat)

                        if result.ndim == 2:
                            result = _apply_reg_2d(result)
                        elif result.ndim == 3:
                             bands = []
                             for c in range(result.shape[2]):
                                 bands.append(_apply_reg_2d(result[..., c]))
                             result = np.stack(bands, axis=2)

                    # Restore dtype
                    if was_int:
                        if was_uint8:
                            result = np.clip(result, 0, 255).astype(np.uint8)
                        else:
                            info = np.iinfo(image.dtype)
                            result = np.clip(result, info.min, info.max).astype(image.dtype)
                        
                except ImportError:
                    logging.warning("Skipping registration: pystackreg not installed.")
                except Exception as e:
                    logging.warning(f"Registration application failed: {e}")


        def _do_band_expr():
            nonlocal result
            if not band_enabled:
                return
            if not expr_str:
                return
            
            # Build NoData mask before expression
            nd_mask = _build_nodata_mask(result, nodata_values) if nodata_values else None
            nd_restore_val = None
            for nv in (nodata_values or []):
                if not isinstance(nv, str):
                    try: nd_restore_val = float(nv); break
                    except: pass
            
            try:
                # Ensure band-expression evaluates on RGB when the working image is cv2-style BGR.
                # Optional override via .ax:  ax["channel_order"] in {"rgb","bgr"}
                _co = str((ax.get("channel_order") or "")).lower()
                bgr_like = (result.ndim == 3 and result.shape[2] == 3)
                if _co == "rgb":
                    bgr_like = False
                elif _co == "bgr":
                    bgr_like = True

                # For exactly-3-channel images that look BGR, give the expression an RGB view.
                # (For stacks >3 we keep band ordering untouched to preserve band_i semantics.)
                base_expr = result[..., [2, 1, 0]] if bgr_like else result

                # Compute expression on the RGB view (or unchanged stack if not bgr_like)
                # FIX: Use eval_band_expression instead of non-existent process_band_expression_float
                res = eval_band_expression(base_expr.astype(np.float32, copy=False), expr_str)
                
                # Restore NoData values in result
                if nd_mask is not None and nd_restore_val is not None:
                    if res.ndim == 2:
                        res = np.where(nd_mask, nd_restore_val, res)
                    else:
                        for c in range(res.shape[2]):
                            res[..., c] = np.where(nd_mask, nd_restore_val, res[..., c])

                if export_label_band:
                    # Append a single 2D expression band to the ORIGINAL result (no channel reorders here)
                    expr2d = res if getattr(res, "ndim", 0) == 2 else res[..., 0]
                    expr2d = expr2d.astype(_float_dtype, copy=False)
                    if result.ndim == 2:
                        result = result[..., None]
                    result = result.astype(_float_dtype, copy=False)
                    result = np.concatenate([result, expr2d[..., None]], axis=2)
                else:
                    # Viewer path: replace result with expression output.
                    # If the expression produced a 3-channel RGB image but our base looked BGR,
                    # flip it back to BGR so downstream expectations remain consistent.
                    if isinstance(res, np.ndarray) and res.ndim == 3 and res.shape[2] == 3:
                        result = res[..., [2, 1, 0]] if bgr_like else res
                    else:
                        result = res.astype(_float_dtype, copy=False) if hasattr(res, "dtype") else res

            except Exception as e:
                logging.warning(f"Band expression failed ('{expr_str}'): {e}")

        # ---------- REGISTRATION FIRST (on raw image, with coordinate translation) ----------
        # Registration is applied BEFORE crop so the warp can pull pixels from
        # outside the crop boundary, producing clean alignment without black borders.
        # The matrix is translated from crop-space to raw-space inside _do_registration.
        _do_registration()
        
        # ---------- execute core ops in dynamic order ----------
        # Execute crop/rotate based on when crop was drawn
        if do_rotate_first:
            _do_rotate()
            _do_crop()
        else:
            _do_crop()
            _do_rotate()
        
        # Check if resize is a shrink - if so, defer histogram to AFTER resize
        # This matches the editor's HIST_MATCH_AFTER_RESIZE_IF_SHRINK = True behavior
        defer_hist = False
        if hist_enabled and resize_enabled and isinstance(resize, dict) and resize:
            h0, w0 = result.shape[:2]
            if h0 > 0 and w0 > 0:
                if "px_w" in resize or "px_h" in resize:
                    tw = int(resize.get("px_w", 0)) or 0
                    th = int(resize.get("px_h", 0)) or 0
                    if tw > 0 and th > 0:
                        new_w, new_h = tw, th
                    elif tw > 0:
                        s = tw / float(w0)
                        new_w, new_h = tw, max(1, int(round(h0 * s)))
                    elif th > 0:
                        s = th / float(h0)
                        new_h, new_w = th, max(1, int(round(w0 * s)))
                    else:
                        new_w, new_h = w0, h0
                elif "scale" in resize:
                    s = float(resize.get("scale", 100.0)) / 100.0
                    new_w, new_h = max(1, int(round(w0 * s))), max(1, int(round(h0 * s)))
                else:
                    pw = float(resize.get("width", 100.0)) / 100.0
                    ph = float(resize.get("height", 100.0)) / 100.0
                    new_w, new_h = max(1, int(round(w0 * pw))), max(1, int(round(h0 * ph)))
                # If shrinking, defer histogram to after resize
                if new_w < w0 or new_h < h0:
                    defer_hist = True
        
        # Apply histogram BEFORE resize (unless deferred for shrink)
        if not defer_hist:
            _do_hist()
        
        _do_resize()
        
        # Apply deferred histogram AFTER resize (for shrink case)
        if defer_hist:
            _do_hist()

        # IMPORTANT: Save pre-band-expression image for classification
        # Classification needs the original RGB channels, not the band expression output
        # (e.g., b1>165 transforms RGB to a single boolean band, destroying R/G/B)
        pre_band_expr_result = result.copy() if (band_enabled and expr_str) else None
        
        _do_band_expr()

        # ---------- classification ----------
                # ---------- classification ----------
        try:
            cblock = (ax.get("classification") or {})
            if isinstance(cblock, dict) \
               and str(cblock.get("mode", "")).lower() == "sklearn" \
               and bool(cblock.get("enabled", False)):

                logging.info(f"[apply_aux_modifications] Classification ENABLED in .ax, attempting to run...")

                # Prefer helper if present (same as your code)
                helper = getattr(ProjectTab, "_apply_sklearn_classification_static", None)
                if callable(helper) and not export_label_band:
                    color = helper(result)  # expected to return RGB/BGR uint8 or None
                    if color is not None:
                        logging.info("[apply_aux_modifications] Used _apply_sklearn_classification_static helper")
                        return color

                # Build model bundle - check class attribute first
                bundle = None
                try:
                    bundle = getattr(ProjectTab, "shared_random_forest_model", None)
                    logging.info(f"[apply_aux_modifications] shared_random_forest_model: {type(bundle).__name__ if bundle else 'None'}")
                    if bundle is None:
                        # Try class-level random_forest_model (won't work for instance attr)
                        bundle = getattr(ProjectTab, "random_forest_model", None)
                        logging.info(f"[apply_aux_modifications] ProjectTab.random_forest_model: {type(bundle).__name__ if bundle else 'None'}")
                except Exception as e:
                    logging.warning(f"[apply_aux_modifications] Model lookup failed: {e}")
                    bundle = None

                if isinstance(bundle, dict) and "model" in bundle:
                    logging.info(f"[apply_aux_modifications] Model bundle found! Running classification...")
                    model = bundle["model"]
                    feat_names = list(bundle.get("feature_names") or [])
                    labels = list(bundle.get("label_names") or getattr(getattr(model, "classes_", []), "tolist", lambda: [])())
                    expressions = bundle.get("expressions", [])  # Get custom expressions
                    window_size = bundle.get("window_size", 1)  # Get spatial window size
                    base_feature_names = bundle.get("base_feature_names", [])  # Base names without window suffix
                    logging.info(f"[apply_aux_modifications] feat_names={feat_names}, base_feature_names={base_feature_names}, window_size={window_size}")
                    
                    # IMPORTANT: Use pre-band-expression image for classification if available
                    # This ensures classification has access to original RGB channels even when
                    # a band expression (like b1>165) has transformed the result to a single band
                    cls_input = pre_band_expr_result if pre_band_expr_result is not None else result
                    logging.info(f"[apply_aux_modifications] cls_input.shape={cls_input.shape}, cls_input.dtype={cls_input.dtype}")

                    # --- NEW: ensure ML sees RGB, even if 'cls_input' is BGR (because cv2.imread) ---
                    # Honor an explicit override if you ever store it in .ax:
                    #   ax["channel_order"] in {"rgb","bgr"}
                    _co = str((ax.get("channel_order") or "")).lower()
                    is_bgr_like = (cls_input.ndim == 3 and cls_input.shape[2] == 3)
                    if _co == "rgb":
                        is_bgr_like = False
                    elif _co == "bgr":
                        is_bgr_like = True
                    # If exactly 3 channels and we think it's BGR, flip to RGB for ML only
                    if is_bgr_like:
                        base_ml = cls_input[..., [2, 1, 0]]  # BGR -> RGB (view only for ML)
                    else:
                        base_ml = cls_input

                    # Guarantee a 3D array for feature addressing
                    if base_ml.ndim == 2:
                        base_ml = base_ml[..., None]

                    base_ml = base_ml.astype(np.float32, copy=False)
                    H, W, C = base_ml.shape

                    # Pre-compute expression images if model has custom expressions
                    expr_images = {}  # name -> HxW array
                    if expressions:
                        import re
                        def _normalize_expr(expr: str) -> str:
                            s = re.sub(r'\bAND\b', '&', expr, flags=re.IGNORECASE)
                            s = re.sub(r'\bOR\b',  '|', s,   flags=re.IGNORECASE)
                            s = re.sub(r'\bNOT\b', '~', s,   flags=re.IGNORECASE)
                            return s
                        
                        for expr_name, expr_str in expressions:
                            try:
                                expr_norm = _normalize_expr(expr_str)
                                expr_result = eval_band_expression(base_ml, expr_norm)
                                if expr_result is not None:
                                    if expr_result.ndim == 3:
                                        expr_result = expr_result[:, :, -1]
                                    expr_images[expr_name] = expr_result.astype(np.float32, copy=False)
                            except Exception as e:
                                logging.debug(f"[classification] Failed to compute expression '{expr_name}': {e}")

                    # Helper to get band array by name
                    def _get_band_array(nm: str):
                        n = str(nm).strip().lower()
                        if n in ("red_channel", "red", "r"):
                            return base_ml[:,:,0] if C >= 1 else None
                        if n in ("green_channel", "green", "g"):
                            return base_ml[:,:,1] if C >= 2 else None
                        if n in ("blue_channel", "blue", "b"):
                            return base_ml[:,:,2] if C >= 3 else None
                        if n.startswith("band_"):
                            try:
                                idx = int(n.split("_", 1)[1]) - 1
                                if 0 <= idx < C:
                                    return base_ml[:,:,idx]
                            except Exception:
                                pass
                        if nm in expr_images:
                            return expr_images[nm]
                        return None

                    # Determine base feature names for window extraction
                    # For window_size > 1: base_feature_names contains names without window suffixes
                    # For window_size == 1: base_feature_names should be used if available (has correct model names)
                    if base_feature_names:
                        # Use provided base names (these have correct model names like "red_channel")
                        base_names = list(base_feature_names)
                    else:
                        # Fallback: use feat_names (for old models without base_feature_names)
                        base_names = list(feat_names)

                    half = window_size // 2
                    n_features = len(feat_names)
                    logging.info(f"[apply_aux_modifications] base_names to check: {base_names}")

                    # Check if all base features are available
                    all_available = True
                    for nm in base_names:
                        arr = _get_band_array(nm)
                        logging.info(f"[apply_aux_modifications] Checking feature '{nm}': {'FOUND' if arr is not None else 'NOT FOUND'}")
                        if arr is None:
                            logging.info(f"[apply_aux_modifications] Classification skipped: base feature '{nm}' not available.")
                            all_available = False
                            break

                    if all_available:
                        logging.info(f"[apply_aux_modifications] All {len(base_names)} features available, building X matrix...")
                        if window_size == 1:
                            # Original vectorized approach for window_size=1
                            # Use base_names which has the correct model feature names
                            feature_arrays = []
                            for nm in base_names:
                                arr = _get_band_array(nm)
                                if arr is None:
                                    logging.debug(f"Classification skipped: feature '{nm}' not available.")
                                    feature_arrays = []
                                    break
                                feature_arrays.append(arr.reshape(-1))
                            
                            if feature_arrays:
                                X = np.column_stack(feature_arrays).astype(np.float32, copy=False)
                        else:
                            # Window-based feature extraction for window_size > 1
                            # Pad all base feature arrays
                            padded_arrays = {}
                            for nm in base_names:
                                arr = _get_band_array(nm)
                                padded_arrays[nm] = np.pad(arr, half, mode='edge')
                            
                            # Build feature array: iterate over each pixel
                            X = np.zeros((H * W, n_features), dtype=np.float32)
                            
                            for y in range(H):
                                for x in range(W):
                                    flat_idx = y * W + x
                                    feat_idx = 0
                                    
                                    # Window positions in row-major order
                                    for dr in range(-half, half + 1):
                                        for dc in range(-half, half + 1):
                                            py = y + half + dr
                                            px = x + half + dc
                                            
                                            for nm in base_names:
                                                X[flat_idx, feat_idx] = padded_arrays[nm][py, px]
                                                feat_idx += 1
                            
                            feature_arrays = [X]  # Just to signal success
                        
                        if feature_arrays:
                            if window_size > 1:
                                # X is already built
                                pass
                            else:
                                X = np.column_stack(feature_arrays).astype(np.float32, copy=False)
                            
                            # Build NoData mask - pixels where ANY feature channel has NoData
                            nodata_mask_flat = np.zeros(H * W, dtype=bool)
                            if nodata_values:
                                for j in range(X.shape[1]):
                                    col = X[:, j]
                                    for nv in nodata_values:
                                        try:
                                            fv = float(nv)
                                            abs_fv = abs(fv)
                                            if abs_fv > 1e+30:
                                                tol = abs_fv * 0.01
                                            elif abs_fv > 1e+10:
                                                tol = abs_fv * 0.001
                                            elif abs_fv > 100:
                                                tol = abs_fv * 0.001
                                            else:
                                                tol = 0.01
                                            nodata_mask_flat |= np.isclose(col, fv, rtol=0.0, atol=tol)
                                        except Exception:
                                            pass
                            # Also mark NaN/Inf as invalid
                            nodata_mask_flat |= ~np.all(np.isfinite(X), axis=1)
                            
                            valid_mask = ~nodata_mask_flat
                            
                            # Get NoData fill value for classification result
                            nodata_fill = 0.0
                            if nodata_values:
                                for v in nodata_values:
                                    try:
                                        if isinstance(v, (int, float)):
                                            nodata_fill = float(v)
                                            break
                                        elif isinstance(v, str):
                                            # Skip expression strings like 'b1>100'
                                            if '>' not in v and '<' not in v and '=' not in v:
                                                nodata_fill = float(v)
                                                break
                                    except (ValueError, TypeError):
                                        pass
                            
                            # Initialize output with NoData value
                            idx = np.full((H * W,), nodata_fill, dtype=np.float32)
                            
                            # Only predict for valid pixels
                            if valid_mask.any():
                                X_valid = X[valid_mask]
                                # predict in chunks - use class-level lock for thread safety (no self in @staticmethod)
                                n_valid = X_valid.shape[0]
                                chunk = max(50_000, min(500_000, n_valid // 8 or 50_000))
                                out = np.empty((n_valid,), dtype=object)
                                i = 0
                                lock = getattr(ProjectTab, "_sklearn_predict_lock", None)
                                while i < n_valid:
                                    j = min(i + chunk, n_valid)
                                    if lock:
                                        with lock:
                                            out[i:j] = model.predict(X_valid[i:j])
                                    else:
                                        out[i:j] = model.predict(X_valid[i:j])
                                    i = j

                                # label -> index
                                idx_map = {lab: k for k, lab in enumerate(labels)} if labels else \
                                          {lab: k for k, lab in enumerate(list(getattr(model, "classes_", [])))}
                                pred_idx = np.vectorize(idx_map.get, otypes=[np.float32])(out)
                                idx[valid_mask] = pred_idx
                            
                            idx = idx.reshape(H, W)

                            if export_label_band:
                                # EXPORT PATH: append labels as *last* band (float32 0..K)
                                # NoData pixels will have nodata_fill value
                                lbl = idx.astype(_float_dtype, copy=False)[..., None]
                                # keep original 'result' dimensionality for output bands
                                rr = result
                                if rr.ndim == 2:
                                    rr = rr[..., None]
                                rr = rr.astype(_float_dtype, copy=False)
                                rr = np.concatenate([rr, lbl], axis=2)
                                return rr
                            else:
                                # VIEWER PATH: Replace result with classification
                                # The viewer expects just what it should display.
                                # Use raw indices (will be shown as grayscale)
                                result = idx.reshape(H, W)
                                logging.info(f"[apply_aux_modifications] Viewer mode: returning classification result only. Shape: {result.shape}")
        except Exception as e:
            logging.info(f"apply_aux_modifications: classification FAILED: {e}")
            import traceback
            logging.info(f"apply_aux_modifications: traceback: {traceback.format_exc()}")

        # ---------- appended bands (from Image Editor's Append button) ----------
        # Process bands that were appended via the (+) button in the Image Editor
        try:
            appended_bands = ax.get("appended_bands") or []
            if appended_bands and isinstance(appended_bands, list):
                logging.info(f"[apply_aux_modifications] Processing {len(appended_bands)} appended bands")

                # Ensure result is 3D for stacking
                if result.ndim == 2:
                    result = result[..., np.newaxis]
                result = result.astype(_float_dtype, copy=False)

                for band_info in appended_bands:
                    if not isinstance(band_info, dict):
                        continue

                    band_type = band_info.get("type", "")
                    band_idx = band_info.get("index", 0)

                    if band_type == "boolean_expression":
                        # Evaluate the stored expression
                        expr = band_info.get("expression", "").strip()
                        if expr:
                            try:
                                # Evaluate on the current result (which may have been transformed)
                                expr_result = eval_band_expression(result, expr)
                                if expr_result is not None:
                                    if expr_result.ndim == 3:
                                        expr_result = expr_result[:, :, -1]
                                    expr_result = expr_result.astype(_float_dtype, copy=False)
                                    result = np.concatenate([result, expr_result[..., np.newaxis]], axis=2)
                                    logging.info(f"[apply_aux_modifications] Appended boolean expression band #{band_idx}")
                            except Exception as e:
                                logging.warning(f"[apply_aux_modifications] Failed to evaluate appended expression: {e}")

                    elif band_type == "band_expression":
                        # Evaluate the stored numeric expression and append as a float band
                        expr = band_info.get("expression", "").strip()
                        if expr:
                            try:
                                expr_result = eval_band_expression(result, expr)
                                if expr_result is not None:
                                    if expr_result.ndim == 3:
                                        expr_result = expr_result[:, :, -1]
                                    expr_result = expr_result.astype(_float_dtype, copy=False)
                                    result = np.concatenate([result, expr_result[..., np.newaxis]], axis=2)
                                    logging.info(f"[apply_aux_modifications] Appended band expression band #{band_idx}")
                            except Exception as e:
                                logging.warning(f"[apply_aux_modifications] Failed to evaluate appended band expression: {e}")

                    elif band_type == "classification":
                        # Re-run classification and append as band
                        try:
                            bundle = getattr(ProjectTab, "shared_random_forest_model", None) or getattr(ProjectTab, "random_forest_model", None)
                            if isinstance(bundle, dict) and "model" in bundle:
                                model = bundle["model"]
                                H, W = result.shape[:2]
                                C = result.shape[2] if result.ndim == 3 else 1

                                # Build feature matrix
                                base_ml = result.astype(np.float32, copy=False)
                                if base_ml.ndim == 2:
                                    base_ml = base_ml[..., np.newaxis]

                                # Simple feature extraction (first 3 bands as RGB)
                                n_features = min(3, base_ml.shape[2])
                                X = base_ml[:, :, :n_features].reshape(H * W, n_features)

                                # Build label->index mapping (model may return string labels)
                                classes = list(getattr(model, "classes_", []))
                                label_to_idx = {lab: i for i, lab in enumerate(classes)}

                                # Predict
                                valid = np.isfinite(X).all(axis=1)
                                preds = np.zeros(H * W, dtype=np.float32)
                                if valid.any():
                                    raw_preds = model.predict(X[valid])
                                    # Convert string labels to numeric indices
                                    if len(classes) > 0 and isinstance(raw_preds[0], str):
                                        preds[valid] = np.array([label_to_idx.get(p, 0) for p in raw_preds], dtype=np.float32)
                                    else:
                                        preds[valid] = np.asarray(raw_preds, dtype=np.float32)

                                cls_band = preds.reshape(H, W).astype(_float_dtype, copy=False)
                                result = np.concatenate([result, cls_band[..., np.newaxis]], axis=2)
                                logging.info(f"[apply_aux_modifications] Appended classification band #{band_idx} (classes: {classes})")
                        except Exception as e:
                            logging.warning(f"[apply_aux_modifications] Failed to append classification band: {e}")

        except Exception as e:
            logging.debug(f"apply_aux_modifications: appended bands failed: {e}")

        # ---------- FINAL: Apply NoData mask GLOBALLY to ALL bands (for display consistency) ----------
        # This ensures that if b1>17000 masks a pixel, ALL bands at that location are masked.
        # IMPORTANT: Only apply if resize is disabled (resize already applies mask via NaN propagation)
        # IMPORTANT: Skip if classification is enabled (classification result is indices, not pixel values)
        # Also use a tracked mask to avoid re-evaluating expressions on transformed pixel values
        classification_enabled = False
        try:
            cblock = (ax.get("classification") or {})
            if isinstance(cblock, dict) and str(cblock.get("mode", "")).lower() == "sklearn" and bool(cblock.get("enabled", False)):
                classification_enabled = True
        except Exception:
            pass
        
        if nodata_enabled and nodata_values and not resize_enabled and not classification_enabled:
            try:
                # Build mask on the final result (after all transformations)
                # For stacked images (C>3), use direct indexing (bgr_input is only for 3-channel BGR)
                final_nd_mask = _build_nodata_mask(result, nodata_values)
                if final_nd_mask is not None and final_nd_mask.any():
                    # Find a numeric restore value (skip expression strings)
                    nd_restore_val = None
                    for nv in nodata_values:
                        if not isinstance(nv, str):
                            try:
                                nd_restore_val = float(nv)
                                break
                            except (ValueError, TypeError):
                                pass
                    
                    # Apply mask to ALL bands (global masking)
                    result = result.astype(np.float32, copy=True)
                    if result.ndim == 2:
                        result[final_nd_mask] = nd_restore_val if nd_restore_val is not None else np.nan
                    else:
                        for c in range(result.shape[2]):
                            result[..., c][final_nd_mask] = nd_restore_val if nd_restore_val is not None else np.nan
                    
                    logging.debug(f"[apply_aux_modifications] Applied global NoData mask to {final_nd_mask.sum()} pixels across all {result.shape[2] if result.ndim == 3 else 1} bands")
            except Exception as e:
                logging.debug(f"[apply_aux_modifications] Global NoData mask application failed: {e}")

        # default: no classification or export_label_band appending already done
        return result


  
    def dragEnterEvent(self, event):
        import os
        md = event.mimeData()
        if not md.hasUrls():
            event.ignore(); return
        exts = {'.png', '.jpg', '.jpeg', '.bmp', '.tif', '.tiff'}
        for u in md.urls():
            p = u.toLocalFile()
            if os.path.isdir(p) or os.path.splitext(p.lower())[1] in exts:
                event.acceptProposedAction()
                return
        event.ignore()

    def dropEvent(self, event):
        import os
        urls = [u for u in event.mimeData().urls() if u.isLocalFile()]
        if not urls:
            event.ignore(); return

        first = urls[0].toLocalFile()
        folder = first if os.path.isdir(first) else os.path.dirname(first)

        # no dialogs: always load with batch_size=10 and replace current project
        self.open_rgb_folder_from_path(folder, batch_size=10)
        event.acceptProposedAction()

    def _set_nav_enabled(self, enabled: bool):
        """Enable/disable navigation controls. When disabled, blocks rapid key presses."""
        # Store state for event filtering
        self._nav_controls_enabled = enabled
        
        for btn_name in ("btn_next", "btn_prev", "btn_first", "btn_last"):
            btn = getattr(self, btn_name, None)
            if btn is not None:
                try:
                    btn.setEnabled(enabled)
                    # extra safety: avoid press-and-hold auto-fire
                    if hasattr(btn, "setAutoRepeat"):
                        btn.setAutoRepeat(False)
                except Exception:
                    pass
        
        # Also disable slider during loading
        if hasattr(self, "group_slider"):
            try:
                self.group_slider.setEnabled(enabled)
            except Exception:
                pass
        
        # Cancel any pending debounced navigation when disabling
        if not enabled:
            try:
                if hasattr(self, '_nav_debounce_timer') and self._nav_debounce_timer is not None:
                    self._nav_debounce_timer.stop()
                self._nav_pending_target = None
            except Exception:
                pass

    def _imagedata_or_fallback(self, filepath):
        """
        Prefer ImageData(...) for normal images, but for TIFFs that are actually stacks
        (multi-page or >3 bands), force a tifffile load so they open as true stacks.

        Returns an object with .filepath and .image (like ImageData).
        Also stores .raw_shape (original dimensions before .ax transforms) and 
        .ax_config (the .ax configuration) for Fix Zoom coordinate mapping.
        """
        import os, logging, numpy as np

        # Lightweight shim that looks like ImageData
        class _Lite:
            __slots__ = ("filepath", "image", "raw_shape", "ax_config")
            def __init__(self, fp, im, raw_shape=None, ax_config=None):
                self.filepath = fp
                self.image = im
                self.raw_shape = raw_shape  # (H, W, C) or (H, W) of raw image
                self.ax_config = ax_config  # .ax dict for this image

        def _tifffile_is_stack(path):
            """Quick metadata probe: does this TIFF represent a stack (>3 bands or >3 pages)?"""
            try:
                import tifffile as tiff
                with tiff.TiffFile(path) as tf:
                    n_pages = len(tf.pages)
                    # Prefer series info if available
                    series = tf.series[0] if tf.series else None
                    axes   = getattr(series, "axes", "") or ""
                    shape  = getattr(series, "shape", ()) or ()
                    spp    = getattr(tf.pages[0], "samplesperpixel", 1) or 1

                    # Channel/band count heuristic
                    band_count = spp
                    if axes and shape:
                        # If 'C' or 'S' axis present, use that for band count
                        if 'C' in axes:
                            band_count = int(shape[axes.index('C')])
                        elif 'S' in axes:
                            band_count = int(shape[axes.index('S')])
                        elif len(shape) == 3:
                            # Fallbacks: infer which dim is channels when axes unknown
                            if shape[0] <= 32 and shape[1] >= 32 and shape[2] >= 32:
                                band_count = int(shape[0])
                            elif shape[2] <= 32:
                                band_count = int(shape[2])

                    # Treat as stack if either: many bands or many uniform pages
                    return (band_count > 3) or (n_pages > 3)
            except Exception as e:
                logging.debug(f"TIFF preflight failed on '{path}': {e}")
                return False

        def _tifffile_read_as_HWC(path):
            """Read with tifffile and coerce to HxWxC when it looks like CxHxW."""
            import tifffile as tiff
            arr = tiff.imread(path)
            arr = np.squeeze(arr)

            # If it's channel-first (C,H,W) with small C, move channels last
            if arr.ndim == 3 and arr.shape[0] <= 32 and arr.shape[1] >= 32 and arr.shape[2] >= 32:
                arr = np.moveaxis(arr, 0, -1)
            return arr

        ext = os.path.splitext(filepath)[1].lower()
        
        # Load .ax config for this file (needed for Fix Zoom coordinate mapping)
        ax_config = None
        try:
            ax_config = self._load_ax_for(filepath) if hasattr(self, '_load_ax_for') else None
        except Exception:
            pass

        # --- 1) TIFF preflight: if it's a real stack, go straight to tifffile ---
        if ext in (".tif", ".tiff") and _tifffile_is_stack(filepath):
            try:
                arr = _tifffile_read_as_HWC(filepath)
                if arr is not None and getattr(arr, "size", 0) > 0:
                    self._last_loader = "tifffile-preflight"
                    self._cache_raw_for_editor(filepath, arr)  # Cache for faster editor opening
                    return _Lite(filepath, arr, raw_shape=arr.shape, ax_config=ax_config)
            except Exception as e:
                logging.warning(f"tifffile stack load failed for '{filepath}', will try ImageData: {e}")

        # --- 2) Try ImageData (cv/PIL path) ---
        try:
            imgd = ImageData(filepath, mode=getattr(self, "mode", None))
            img = getattr(imgd, "image", None)

            if img is not None and getattr(img, "size", 0) > 0:
                # If a TIFF slipped through as 4-ch via cv (e.g., BGRA) but metadata says stack, override.
                if ext in (".tif", ".tiff") and isinstance(img, np.ndarray):
                    try:
                        if img.ndim == 3 and img.shape[2] in (4, 5, 6, 7, 8):  # cv read with >3 channels
                            # Confirm with metadata; if it's truly a stack, reload via tifffile.
                            if _tifffile_is_stack(filepath):
                                arr = _tifffile_read_as_HWC(filepath)
                                if arr is not None and getattr(arr, "size", 0) > 0:
                                    self._last_loader = "tifffile-override-cv"
                                    self._cache_raw_for_editor(filepath, arr)  # Cache for faster editor opening
                                    return _Lite(filepath, arr, raw_shape=arr.shape, ax_config=ax_config)
                    except Exception as e:
                        logging.debug(f"cv override check failed for '{filepath}': {e}")

                # Normal path: keep ImageData result but add raw_shape and ax_config
                self._last_loader = "imagedata"
                self._cache_raw_for_editor(filepath, img)  # Cache for faster editor opening
                # Add raw_shape and ax_config to the ImageData object
                imgd.raw_shape = img.shape
                imgd.ax_config = ax_config
                return imgd

            raise ValueError("ImageData returned empty image")

        except Exception:
            # --- 3) Final fallback (existing raw loader; should already prefer tifffile for stacks) ---
            arr = self._load_raw_image(filepath)
            if arr is None or getattr(arr, "size", 0) == 0:
                raise
            self._last_loader = "fallback"
            self._cache_raw_for_editor(filepath, arr)  # Cache for faster editor opening
            return _Lite(filepath, arr, raw_shape=arr.shape, ax_config=ax_config)

    def _cache_raw_for_editor(self, filepath, image):
        """
        Cache raw image for faster Image Editor Dialog opening.
        The editor checks _raw_cache before loading from disk.
        This is a simple LRU-style cache limited to ~20 images.
        """
        import os
        if image is None:
            return
        if not hasattr(self, "_raw_cache") or self._raw_cache is None:
            return
        try:
            key = os.path.normcase(os.path.abspath(filepath))
            lock = getattr(self, "_raw_cache_lock", None)
            if lock:
                with lock:
                    # Limit cache size to avoid memory bloat
                    limit = 2 if getattr(self, "_is_exporting", False) else 20
                    if len(self._raw_cache) > limit:
                        try:
                            oldest = next(iter(self._raw_cache))
                            del self._raw_cache[oldest]
                        except Exception:
                            pass
                    self._raw_cache[key] = image
            else:
                # Limit cache size to avoid memory bloat
                limit = 2 if getattr(self, "_is_exporting", False) else 20
                if len(self._raw_cache) > limit:
                    try:
                        oldest = next(iter(self._raw_cache))
                        del self._raw_cache[oldest]
                    except Exception:
                        pass
                self._raw_cache[key] = image
        except Exception:
            pass  # Never fail image loading due to cache issues


    # --- AX location policy: project folder first, else temp cache (never image folder) ---
    def _ax_base_name(self, image_path: str) -> str:
        import os
        return os.path.splitext(os.path.basename(image_path))[0] + ".ax"

    def _ax_dir(self) -> str:
        import os, tempfile
        pf = getattr(self, "project_folder", None)
        if pf and str(pf).strip():
            return pf
        # Unsaved project → use a stable temp cache dir
        if not hasattr(self, "_unsaved_ax_dir"):
            self._unsaved_ax_dir = os.path.join(tempfile.gettempdir(), "CanoPie_AX")
            os.makedirs(self._unsaved_ax_dir, exist_ok=True)
        return self._unsaved_ax_dir

    def _ax_path_for(self, image_path: str) -> str:
        # Single truth for writes/reads
        return os.path.join(self._ax_dir(), self._ax_base_name(image_path))


    def _ax_op_order(self, ax: dict):
        """
        Returns the list of ops to apply, in order, limited to {'crop','rotate','resize'}.
        Falls back to ['crop','rotate','resize'] if not provided.
        Accepts variations like 'rotation', 'res', etc.
        """
        if not isinstance(ax, dict):
            return ["crop", "rotate", "resize"]
        raw = ax.get("op_order") or ax.get("ops") or ["crop", "rotate", "resize"]
        if isinstance(raw, str):
            raw = [raw]
        out = []
        for s in (raw or []):
            t = str(s).lower()
            if "crop" in t: out.append("crop")
            elif "rot" in t:   out.append("rotate")
            elif "siz" in t or "res" in t: out.append("resize")
        return [op for op in out if op in ("crop", "rotate", "resize")] or ["crop", "rotate", "resize"]

      
    def _get_exif_data_with_optional_path(self, files):
        """
        Return {abs_normcase_path: {tag: value}}.
        Try helper w/ exiftool_path, then helper w/o, then subprocess with self.exiftool_path,
        and finally prompt once for exiftool.exe if still missing.
        """
        import os, logging

        if not files:
            return {}

        # Dedup + normalize inputs first
        files = [os.path.abspath(f) for f in files]
        files = list(dict.fromkeys(files))  # preserve order, drop dupes

        def _normkey(p):  # single canonical form used everywhere
            return os.path.normcase(os.path.abspath(p))

        # 1) helper with kwarg
        try:
            d = get_exif_data_exiftool_multiple(files, exiftool_path=self.exiftool_path)
            if d:
                return {_normkey(k): v for k, v in d.items()}
        except TypeError:
            logging.debug("Helper doesn’t accept exiftool_path; trying without it.")
        except Exception as e:
            logging.warning("Helper with exiftool_path failed: %s", e)

        # 2) helper without kwarg
        try:
            d = get_exif_data_exiftool_multiple(files)
            if d:
                return {_normkey(k): v for k, v in d.items()}
        except Exception as e:
            logging.warning("Helper without exiftool_path failed: %s", e)

        # 3) subprocess fallback (prefer self.exiftool_path)
        try:
            d = self._extract_exif_via_subprocess(files, exe_path=self.exiftool_path)
            if d:
                return {_normkey(k): v for k, v in d.items()}
        except FileNotFoundError:
            # Ask once
            from PyQt5 import QtWidgets
            path, _ = QtWidgets.QFileDialog.getOpenFileName(
                self, "Locate exiftool.exe", "", "Executable (exiftool*.exe);;All Files (*)"
            )
            if path:
                self.set_exiftool_path(path)
                try:
                    d = self._extract_exif_via_subprocess(files, exe_path=path)
                    if d:
                        return {_normkey(k): v for k, v in d.items()}
                except Exception as e:
                    logging.exception("Direct exiftool call failed after picking path: %s", e)
        except Exception as e:
            logging.exception("Subprocess EXIF fallback failed: %s", e)

        logging.error("EXIF extraction failed; returning empty tags for %d files.", len(files))
        return {_normkey(p): {} for p in files}

    def _extract_exif_via_subprocess(self, files, exe_path=None):
        """
        Run exiftool directly with a given executable path.
        - Chunks input to avoid Windows command-line length limits.
        - Returns a merged dict keyed by absolute file path.
        """
        import os, json, shutil, subprocess

        if not files:
            return {}

        exe = exe_path or self.exiftool_path or "exiftool"
        # Accept a directory pointing to the exe folder
        if os.path.isdir(exe):
            exe = os.path.join(exe, "exiftool.exe")

        # Resolve availability
        if not os.path.isfile(exe) and shutil.which(exe) is None:
            raise FileNotFoundError(f"exiftool not found at '{exe}'")

        # Sanity check & log version (helps diagnose 32/64-bit or wrong binary)
        try:
            ver_proc = subprocess.run(
                [exe, "-ver"],
                stdout=subprocess.PIPE,
                stderr=subprocess.PIPE,
                check=True,
                creationflags=_SUBPROCESS_FLAGS,
            )
            ver = ver_proc.stdout.decode("utf-8", errors="ignore").strip()
            logging.info("Using exiftool %s at %s", ver, exe)
        except Exception as e:
            logging.error("exiftool sanity check failed: %s", e)
            raise

        results = {}
        BATCH = 150  # keep args manageable on Windows

        for i in range(0, len(files), BATCH):
            batch = files[i:i+BATCH]
            batch_abs = [os.path.abspath(p) for p in batch]

            cmd = [
                exe,
                "-j",                       # JSON output
                "-n",                       # numeric values
                "-api", "largefilesupport=1",
                "-charset", "filename=utf8",
                "-q", "-q",                 # be quiet so JSON stays clean on STDOUT
            ] + batch_abs

            try:
                proc = subprocess.run(
                    cmd,
                    stdout=subprocess.PIPE,
                    stderr=subprocess.PIPE,
                    check=True,
                    creationflags=_SUBPROCESS_FLAGS,
                )
                raw_out = proc.stdout.decode("utf-8", errors="ignore")
                if proc.stderr:
                    # Keep it for debugging, but don’t contaminate JSON
                    logging.debug(
                        "exiftool warnings (suppressed): %s",
                        proc.stderr.decode("utf-8", errors="ignore")[:500]
                    )
            except (subprocess.CalledProcessError, OSError) as e:
                # WinError 2 = FileNotFoundError for the executable, even if we checked earlier
                # This can happen if the path is weird or permissions changed
                err_msg = str(e)
                if hasattr(e, 'stderr') and e.stderr:
                    err_msg += " " + e.stderr.decode("utf-8", errors="ignore")
                
                logging.warning(
                    "exiftool execution failed (disabling for session?): %s", err_msg
                )
                
                # If it's a "File not found" type error, we might want to unset the path
                # so we don't try again repeatedly. 
                # (WinError 2 or FileNotFoundError)
                if isinstance(e, FileNotFoundError) or "[WinError 2]" in str(e):
                     logging.error(f"Exiftool executable seemingly missing at '{exe}'. Disabling path.")
                     self.exiftool_path = None
                     
                continue

            try:
                arr = json.loads(raw_out)
            except Exception as e:
                logging.error(
                    "Failed to parse exiftool JSON (first 400 chars): %r",
                    raw_out[:400]
                )
                continue

            for rec in arr:
                src = rec.get("SourceFile") or rec.get("FileName")
                if not src:
                    continue
                key = os.path.abspath(src)
                results[key] = {k: v for k, v in rec.items() if k != "SourceFile"}

        logging.info(
            "Extracted EXIF for %d of %d files via exiftool subprocess.",
            len(results), len(files)
        )
        return results

    def init_data_structures(self):
        # Initialize data structures
        self.image_data_groups = defaultdict(list)
        self.root_names = []

        self.multispectral_image_data_groups = defaultdict(list)
        self.thermal_rgb_image_data_groups = defaultdict(list)
        self.multispectral_root_names = ['Multi1', 'Multi2', 'Multi3']  # Example data
        self.thermal_rgb_root_names = ['Thermal1', 'Thermal2', 'Thermal3']  # Example data
        self.current_root_index = 0
        self.root_offset = 0  # Offset between multispectral roots and thermal/RGB roots
        self.root_id_mapping = {}
        self.mode = 'dual_folder'
        self.sync_enabled = True  # Start with synchronization enabled
        self.root_coordinates = {}
        self.all_polygons = defaultdict(dict)  # Key: logical_name, Value: dict mapping filepath to polygon data
        self.viewer_widgets = []
        self.image_loader_thread = None
        self.image_loader_worker = None
        self.images_to_load = 0
        self.images_loaded = 0
        self.project_folder = ""  # Path to the project folder
        self.root_offset_dialog = None
        self.current_drawing_mode = "polygon"  # Default mode is polygon

        # PERFORMANCE: Display-level QPixmap cache (LRU)
        # Caches final rendered pixmaps to skip expensive _render_with_viewer_stretch
        # Cache key includes file mtime + .ax mtime + stretch params for auto-invalidation
        self._pixmap_cache = {}  # cache_key -> QPixmap
        self._pixmap_cache_lock = threading.Lock()
        self._pixmap_cache_max = 30  # Cache up to 30 pixmaps

        # PERFORMANCE: Transformed ImageData cache (LRU)
        # Caches fully transformed ImageData (after apply_aux_modifications)
        # to skip disk I/O when navigating back to previously viewed roots
        # Cache key: (filepath, file_mtime, ax_mtime)
        self._imgdata_cache = {}  # cache_key -> ImageData
        self._imgdata_cache_lock = threading.Lock()
        self._imgdata_cache_max = 100  # Cache up to 100 images (~100 roots * ~10 images)

        # PERFORMANCE: Raw image cache (for editor dialog)
        # Caches raw pixel arrays before transformations to speed up editor open
        # Cache key: (filepath_norm, file_mtime)
        self._raw_image_cache = {}  # cache_key -> np.ndarray
        self._raw_image_cache_lock = threading.Lock()
        self._raw_image_cache_max = 50  # Cache up to 50 raw images

    def _get_pixmap_cache_key(self, filepath, stretch_params):
        """
        Generate cache key for display pixmap.
        Includes file mtime, .ax mtime, and stretch params hash for auto-invalidation.
        Returns None if caching not possible.
        """
        import os, hashlib
        
        # File modification time
        try:
            file_mtime = os.path.getmtime(filepath)
        except Exception:
            return None  # Can't cache without mtime
        
        # .ax file modification time (for edit invalidation)
        ax_path = os.path.splitext(filepath)[0] + ".ax"
        if self.project_folder:
            base = os.path.splitext(os.path.basename(filepath))[0] + ".ax"
            ax_path = os.path.join(self.project_folder, base)
        try:
            ax_mtime = os.path.getmtime(ax_path) if os.path.exists(ax_path) else 0
        except Exception:
            ax_mtime = 0
        
        # Stretch params hash (changes when user adjusts stretch)
        sp_hash = "none"
        if stretch_params:
            try:
                sp_dict = vars(stretch_params) if hasattr(stretch_params, '__dict__') else {}
                sp_str = str(sorted(sp_dict.items())) if sp_dict else str(stretch_params)
                sp_hash = hashlib.md5(sp_str.encode()).hexdigest()[:8]
            except Exception:
                sp_hash = "err"
        
        return (filepath, file_mtime, ax_mtime, sp_hash)

    def _get_imgdata_cache_key(self, filepath):
        """
        Generate cache key for transformed ImageData.
        Returns (filepath, file_mtime, ax_mtime) or None if can't cache.
        """
        import os
        
        # File modification time
        try:
            file_mtime = os.path.getmtime(filepath)
        except Exception:
            return None  # Can't cache without mtime
        
        # .ax file modification time (for edit invalidation)
        ax_path = os.path.splitext(filepath)[0] + ".ax"
        if self.project_folder:
            base = os.path.splitext(os.path.basename(filepath))[0] + ".ax"
            ax_path = os.path.join(self.project_folder, base)
        try:
            ax_mtime = os.path.getmtime(ax_path) if os.path.exists(ax_path) else 0
        except Exception:
            ax_mtime = 0
        
        return (filepath, file_mtime, ax_mtime)

    def _get_cached_imgdata(self, filepath):
        """
        Check if transformed ImageData is cached and still valid.
        Returns ImageData if valid, None if cache miss.
        """
        if not hasattr(self, '_imgdata_cache') or not hasattr(self, '_imgdata_cache_lock'):
            return None
        
        cache_key = self._get_imgdata_cache_key(filepath)
        if not cache_key:
            return None
        
        with self._imgdata_cache_lock:
            if cache_key in self._imgdata_cache:
                logging.debug(f"[ImgData cache] HIT: {os.path.basename(filepath)}")
                return self._imgdata_cache[cache_key]
        return None

    def _store_cached_imgdata(self, filepath, imgdata):
        """
        Store transformed ImageData in cache with LRU eviction.
        """
        if not hasattr(self, '_imgdata_cache') or not hasattr(self, '_imgdata_cache_lock'):
            return
        
        cache_key = self._get_imgdata_cache_key(filepath)
        if not cache_key:
            return
        
        try:
            with self._imgdata_cache_lock:
                # LRU eviction
                if len(self._imgdata_cache) >= self._imgdata_cache_max:
                    oldest = next(iter(self._imgdata_cache))
                    del self._imgdata_cache[oldest]
                self._imgdata_cache[cache_key] = imgdata
                logging.debug(f"[ImgData cache] STORE: {os.path.basename(filepath)} (cache size: {len(self._imgdata_cache)})")
        except Exception as e:
            logging.debug(f"[ImgData cache] Store error: {e}")


