    def _scientific_with_ax(self, filepath, base_img=None):
        """
        Return the *scientific* image with .ax operations applied
        (rotate/crop/resize/band_expression + hist_match), float32, HxW or HxWxC.
        If base_img is provided, it is assumed to be the raw HWC image for filepath.
        """
        img = base_img
        if img is None:
            # load RAW the same way as export path
            img = self._load_raw_image(filepath)
            if img is None:
                return None

        # Ensure HWC (like export)
        img = self._ensure_hwc(img)

        # Apply .ax exactly like export
        try:
            if hasattr(self, "_apply_ax_to_raw"):
                img, _C = self._apply_ax_to_raw(img, self._load_ax_for(filepath),
                                                filepath=filepath,
                                                all_polygons=getattr(self, "all_polygons", None))
            else:
                # Fallback to the older helper if present
                img = self.apply_aux_modifications(
                    filepath, img,
                    project_folder=getattr(self, "project_folder", None),
                    global_mode=False,
                    all_polygons=getattr(self, "all_polygons", None),
                )
        except Exception:
            pass

        # Always float32 for scientific ops
        return img.astype(np.float32, copy=False) if hasattr(img, "astype") else img

    def _apply_ax_to_raw(self, img, ax, filepath=None, all_polygons=None):
        """
        Compatibility wrapper for export worker.
        Delegates to apply_aux_modifications (which now handles registration).
        Returns (image, n_channels).
        """
        try:
            # Re-use the robust static pipeline
            out = self.apply_aux_modifications(
                filepath, img, 
                project_folder=getattr(self, "project_folder", None),
                global_mode=False,
                all_polygons=all_polygons
            )
            if out is None:
                return None, 0
            C = out.shape[2] if out.ndim == 3 else 1
            return out, C
        except Exception as e:
            import logging
            logging.error(f"_apply_ax_to_raw failed: {e}")
            return img, (img.shape[2] if img.ndim==3 else 1)
        
    def zoom_all_viewers_out(self):
        """
        Zoom every ImageViewer in this tab to 'fit whole image'.
        Finds viewers even if they're subclassed or registered elsewhere.
        """
        import logging
        
        # Reset fixed zoom/center so all viewers fit independently
        try:
            _ZoomBar._fixed_zoom = None
            _ZoomBar._fixed_center = None
        except Exception:
            pass
        
        viewers = []

        # Get viewers from viewer_widgets (list of dicts with 'viewer' key)
        try:
            if hasattr(self, "viewer_widgets") and self.viewer_widgets:
                for wdict in self.viewer_widgets:
                    if isinstance(wdict, dict) and 'viewer' in wdict:
                        v = wdict['viewer']
                        if v is not None:
                            viewers.append(v)
                    elif hasattr(wdict, "zoom_out_to_fit"):
                        viewers.append(wdict)
        except Exception as e:
            logging.debug(f"zoom_all_viewers_out: registry probe failed: {e}")

        # 2) Fallback: any QGraphicsView child that has zoom_out_to_fit()
        try:
            for gv in self.findChildren(QtWidgets.QGraphicsView):
                if hasattr(gv, "zoom_out_to_fit"):
                    viewers.append(gv)
        except Exception as e:
            logging.debug(f"zoom_all_viewers_out: child search failed: {e}")

        # De-dup while preserving order
        seen = set()
        uniq = []
        for v in viewers:
            if id(v) not in seen:
                seen.add(id(v))
                uniq.append(v)
        viewers = uniq

        logging.info("zoom_all_viewers_out triggered; viewers=%d", len(viewers))

        if not viewers:
            return

        for v in viewers:
            try:
                # Skip empty viewers
                if hasattr(v, "has_image") and not v.has_image():
                    continue
                v.zoom_out_to_fit()
            except Exception as e:
                logging.debug(f"zoom_all_viewers_out: failed on {type(v).__name__}: {e}")

    def toggle_rect_zoom_mode(self, checked=None):
        """
        Toggle rectangle zoom mode for all viewers.
        When enabled, right-click drag draws a rectangle and zooms to it.
        """
        # Determine new state
        if checked is None:
            checked = self.rectZoomAct.isChecked()
        
        # Apply to all viewers
        self._apply_rect_zoom_to_viewers(checked)
        
        # Update action state
        self.rectZoomAct.setChecked(checked)

    def _apply_rect_zoom_to_viewers(self, enabled):
        """Apply rectangle zoom mode to all current viewers (helper for persistence)."""
        import logging
        viewers = []
        
        # Get viewers from viewer_widgets (list of dicts with 'viewer' key)
        try:
            if hasattr(self, "viewer_widgets") and self.viewer_widgets:
                for wdict in self.viewer_widgets:
                    if isinstance(wdict, dict) and 'viewer' in wdict:
                        v = wdict['viewer']
                        if v is not None:
                            viewers.append(v)
        except Exception:
            pass
        
        # Also try findChildren as fallback
        try:
            for gv in self.findChildren(QtWidgets.QGraphicsView):
                if hasattr(gv, "set_rect_zoom_mode"):
                    viewers.append(gv)
        except Exception:
            pass
        
        # De-dup
        seen = set()
        for v in viewers:
            if id(v) not in seen:
                seen.add(id(v))
                try:
                    if hasattr(v, "set_rect_zoom_mode"):
                        v.set_rect_zoom_mode(enabled)
                except Exception as e:
                    logging.debug(f"_apply_rect_zoom_to_viewers failed: {e}")

