    def _ensure_polygon_index(self):
        """
        Build/rebuild polygon lookup indices if needed.
        PERFORMANCE: This is O(n) where n = total polygon entries, but only runs when invalid.
        OPTIMIZATION: Single pass builds both exact and normalized indices together.
        """
        if hasattr(self, '_poly_exact_index') and not getattr(self, '_poly_norm_index_invalid', True):
            return  # Already valid
        
        import os
        import logging
        import time
        
        t0 = time.perf_counter()
        
        self._poly_norm_index = {}
        self._poly_exact_index = {}
        
        # SINGLE PASS: Build both indices together (was 2 separate loops - 2x slower!)
        entry_count = 0
        group_count = 0
        for gn, fm in (self.all_polygons or {}).items():
            if not isinstance(fm, dict):
                continue
            group_count += 1
            for fp in fm:
                # Exact path index (FAST - just string hashing)
                if fp not in self._poly_exact_index:
                    self._poly_exact_index[fp] = []
                self._poly_exact_index[fp].append(gn)
                
                # Normalized index (for case-insensitive lookups)
                try:
                    fp_norm = os.path.normpath(fp).lower() if fp else ""
                except Exception:
                    fp_norm = str(fp).lower()
                if fp_norm not in self._poly_norm_index:
                    self._poly_norm_index[fp_norm] = []
                self._poly_norm_index[fp_norm].append((gn, fp))
                
                entry_count += 1
        
        self._poly_norm_index_invalid = False
        
        elapsed = time.perf_counter() - t0
        # Always log on first build, then only if slow
        logging.info(f"[_ensure_polygon_index] Built index: {group_count} groups, {entry_count} entries in {elapsed:.3f}s")

    def _add_to_polygon_index(self, group_name: str, filepath: str):
        """
        INCREMENTAL index update - O(1) instead of O(N) full rebuild.
        Call this when adding a single polygon instead of invalidating the whole index.
        """
        if not filepath or not group_name:
            return
            
        # Ensure base indices exist
        if not hasattr(self, '_poly_exact_index') or self._poly_exact_index is None:
            self._poly_exact_index = {}
        if not hasattr(self, '_poly_norm_index') or self._poly_norm_index is None:
            self._poly_norm_index = {}
        
        # Add to exact index
        if filepath not in self._poly_exact_index:
            self._poly_exact_index[filepath] = []
        if group_name not in self._poly_exact_index[filepath]:
            self._poly_exact_index[filepath].append(group_name)
        
        # Add to normalized index
        try:
            fp_norm = os.path.normpath(filepath).lower() if filepath else ""
        except Exception:
            fp_norm = str(filepath).lower()
        if fp_norm not in self._poly_norm_index:
            self._poly_norm_index[fp_norm] = []
        entry = (group_name, filepath)
        if entry not in self._poly_norm_index[fp_norm]:
            self._poly_norm_index[fp_norm].append(entry)

    def _remove_from_polygon_index(self, group_name: str, filepath: str):
        """
        INCREMENTAL index removal - O(1) instead of O(N) full rebuild.
        Call this when removing a polygon instead of invalidating the whole index.
        """
        if not filepath or not group_name:
            return
            
        # Remove from exact index
        if hasattr(self, '_poly_exact_index') and self._poly_exact_index:
            if filepath in self._poly_exact_index:
                try:
                    self._poly_exact_index[filepath].remove(group_name)
                    if not self._poly_exact_index[filepath]:
                        del self._poly_exact_index[filepath]
                except (ValueError, KeyError):
                    pass
        
        # Remove from normalized index
        if hasattr(self, '_poly_norm_index') and self._poly_norm_index:
            try:
                fp_norm = os.path.normpath(filepath).lower() if filepath else ""
            except Exception:
                fp_norm = str(filepath).lower()
            if fp_norm in self._poly_norm_index:
                entry = (group_name, filepath)
                try:
                    self._poly_norm_index[fp_norm].remove(entry)
                    if not self._poly_norm_index[fp_norm]:
                        del self._poly_norm_index[fp_norm]
                except (ValueError, KeyError):
                    pass

    def _get_polygons_for_filepath(self, filepath: str, polygon_names: list = None):
        """
        O(1) lookup to get all polygons for a specific filepath.
        Uses the polygon index instead of iterating all_polygons.
        
        Args:
            filepath: The image filepath to look up polygons for
            polygon_names: Optional list of polygon names to filter by
            
        Returns:
            List of (group_name, polygon_data) tuples
        """
        if not filepath or not self.all_polygons:
            return []
        
        # Ensure index is built
        self._ensure_polygon_index()
        
        results = []
        
        # Try exact match first (O(1))
        if filepath in self._poly_exact_index:
            for gn in self._poly_exact_index[filepath]:
                if gn in self.all_polygons and filepath in self.all_polygons[gn]:
                    poly_data = self.all_polygons[gn][filepath]
                    if polygon_names is None:
                        results.append((gn, poly_data))
                    else:
                        # Filter by name
                        poly_name = poly_data.get('name', gn) if isinstance(poly_data, dict) else gn
                        if poly_name in polygon_names:
                            results.append((gn, poly_data))
        
        # Try normalized match if no exact match found
        if not results:
            import os
            fp_norm = os.path.normpath(filepath).lower() if filepath else ""
            if fp_norm in self._poly_norm_index:
                for gn, orig_fp in self._poly_norm_index[fp_norm]:
                    if gn in self.all_polygons and orig_fp in self.all_polygons[gn]:
                        poly_data = self.all_polygons[gn][orig_fp]
                        if polygon_names is None:
                            results.append((gn, poly_data))
                        else:
                            poly_name = poly_data.get('name', gn) if isinstance(poly_data, dict) else gn
                            if poly_name in polygon_names:
                                results.append((gn, poly_data))
        
        return results

    def update_all_polygons(self):
        """
        Sync in-memory polygons from currently-loaded viewers.

        CRITICAL FIX:
          - ALWAYS store points in IMAGE coords (pixel space of the effective image).
          - ALWAYS stamp coord_space='image' and image_ref_size={'w','h'} for that basis.
          - ALSO remove polygons from memory that were deleted from the viewer for that filepath.

        This prevents "coordinate-space poisoning" where scene coords get saved as image coords,
        causing polygons to explode/shrink after resize + copy operations.
        """
        import os
        import logging
        from PyQt5 import QtCore, QtGui

        _index_needs_rebuild = False  # ONLY set when structure changes (add/delete)

        if not hasattr(self, "all_polygons") or self.all_polygons is None:
            self.all_polygons = {}

        # PERFORMANCE: Ensure index is built before we need it
        self._ensure_polygon_index()

        # Build a quick list of (viewer, image_data) pairs that are alive
        vw_pairs = []
        for vw in getattr(self, "viewer_widgets", []) or []:
            try:
                viewer = vw.get("viewer", None)
                image_data = vw.get("image_data", None)
                if viewer is None or image_data is None:
                    continue
                fp = getattr(image_data, "filepath", None)
                if not fp:
                    continue
                vw_pairs.append((viewer, image_data))
            except Exception:
                continue

        def _norm(p):
            try:
                return os.path.normpath(os.fspath(p))
            except Exception:
                return str(p)

        for viewer, image_data in vw_pairs:
            filepath = os.fspath(getattr(image_data, "filepath", ""))
            if not filepath:
                continue
            fp_norm = _norm(filepath)

            # CRITICAL FIX: Use the ACTUAL viewer image dimensions FIRST.
            # This ensures consistency with scene_to_image_coords which uses viewer.image_data.image.shape.
            # Using _effective_hw_for_file() first caused coordinate mismatch after reset/refresh
            # because it could return stale cached values or simulate from deleted .ax files.
            eff_h, eff_w = (0, 0)
            try:
                img = getattr(image_data, "image", None)
                if img is not None and hasattr(img, "shape"):
                    eff_h, eff_w = img.shape[:2]
            except Exception:
                pass
            if not (eff_h and eff_w):
                # last resort: viewer basis
                try:
                    eff_h, eff_w = self._viewer_basis_hw(viewer, fallback_hw=None)
                except Exception:
                    eff_h, eff_w = (0, 0)
            if not (eff_h and eff_w):
                continue

            # Current pixmap size (for better mapping fallbacks)
            pm_w = pm_h = 0
            try:
                pm = getattr(viewer, "_image", None)
                if pm is not None and pm.pixmap() is not None:
                    pm_w = int(pm.pixmap().width())
                    pm_h = int(pm.pixmap().height())
            except Exception:
                pm_w = pm_h = 0

            # Which group names are currently present in the viewer for this file?
            items = []
            try:
                items = list(viewer.get_all_polygons() or [])
            except Exception:
                items = []

            present_names = set()
            items_by_name = {}
            for it in items:
                try:
                    nm = (getattr(it, "name", "") or "").strip()
                    if not nm:
                        continue
                    present_names.add(nm)
                    # if multiple, keep the last (existing behavior is "one per name")
                    items_by_name[nm] = it
                except Exception:
                    continue

            # --- Remove any polygons in memory for THIS filepath that no longer exist in the viewer ---
            # (This fixes "clear polygons but they come back after zoom/reload")
            # PERFORMANCE FIX: Use O(1) index lookup (index is ensured at function start)
            try:
                groups_with_this_file = set()
                
                # Use exact index (always available since we called _ensure_polygon_index at start)
                if filepath in self._poly_exact_index:
                    for gn in self._poly_exact_index[filepath]:
                        groups_with_this_file.add((gn, filepath))
                elif fp_norm in self._poly_norm_index:
                    for gn, orig_fp in self._poly_norm_index[fp_norm]:
                        groups_with_this_file.add((gn, orig_fp))
                
                # Now only process the groups that actually have this file
                for group_name, stored_fp in groups_with_this_file:
                    if group_name not in present_names:
                        # This polygon was deleted from viewer - remove from memory
                        try:
                            gdict = self.all_polygons.get(group_name, {})
                            if stored_fp in gdict:
                                del gdict[stored_fp]
                                _index_needs_rebuild = True  # Structure changed - deletion
                            if not gdict:
                                del self.all_polygons[group_name]
                        except Exception:
                            pass
            except Exception as e:
                logging.debug(f"update_all_polygons: prune step failed: {e}")

            # Root number (consistent with your other code paths)
            root_number = None
            try:
                root_name = self.get_root_by_filepath(filepath)
                if root_name:
                    if hasattr(self, "root_id_mapping") and self.root_id_mapping:
                        root_number = str(self.root_id_mapping.get(root_name, "0"))
                    else:
                        # PERFORMANCE: Use O(1) cached lookup instead of O(N) .index()
                        idx = self._get_ms_root_index(root_name)
                        root_number = str(idx + 1) if idx is not None else "0"
            except Exception:
                root_number = "0"

            # --- Write/update each present polygon into all_polygons in IMAGE coord space ---
            for group_name, it in items_by_name.items():
                try:
                    # Get scene points of the item (including item translation)
                    pts_scene = []

                    if hasattr(it, "polygon") and callable(getattr(it, "polygon")):
                        # Map the polygon to scene coords (handles item.pos() moves correctly)
                        try:
                            poly_local = it.polygon()
                            poly_scene = it.mapToScene(poly_local)
                            pts_scene = [(float(p.x()), float(p.y())) for p in poly_scene]
                            shape_type = "polygon"
                        except Exception:
                            # fallback: read local as-is
                            poly_local = it.polygon()
                            pts_scene = [(float(p.x()), float(p.y())) for p in poly_local]
                            shape_type = "polygon"

                    elif hasattr(it, "points"):
                        # Point item: stored points may be pixmap-local
                        shape_type = "point"
                        try:
                            pts = list(getattr(it, "points") or [])
                        except Exception:
                            pts = []

                        if getattr(it, "points_are_pixmap_local", False):
                            # Convert pixmap-local -> scene using pixmap item's position
                            try:
                                pm = getattr(viewer, "_image", None)
                                off = pm.pos() if pm is not None else QtCore.QPointF(0, 0)
                                ox, oy = float(off.x()), float(off.y())
                            except Exception:
                                ox, oy = 0.0, 0.0
                            pts_scene = [(ox + float(p.x()), oy + float(p.y())) for p in pts]
                        else:
                            # Already in item coords; map to scene if possible
                            try:
                                qpoly = QtGui.QPolygonF()
                                for p in pts:
                                    qpoly.append(QtCore.QPointF(float(p.x()), float(p.y())))
                                poly_scene = it.mapToScene(qpoly)
                                pts_scene = [(float(p.x()), float(p.y())) for p in poly_scene]
                            except Exception:
                                pts_scene = [(float(p.x()), float(p.y())) for p in pts]
                    else:
                        continue

                    if not pts_scene:
                        continue

                    # CRITICAL FIX: Convert scene -> image coords directly using scene_to_image_coords.
                    # This ensures the coordinate conversion uses the SAME basis as image_ref_size
                    # (viewer.image_data.image.shape). The old _map_points_scene_to_image approach
                    # could cause mismatch after reset/refresh.
                    img_pts = []
                    for pt in pts_scene:
                        ip = self.scene_to_image_coords(viewer, QtCore.QPointF(pt[0], pt[1]))
                        img_pts.append((float(ip.x()), float(ip.y())))

                    if not img_pts:
                        continue

                    # Ensure container exists
                    if group_name not in self.all_polygons or not isinstance(self.all_polygons.get(group_name), dict):
                        self.all_polygons[group_name] = {}

                    # Keep original filepath key if it exists; else use current filepath
                    store_key = filepath
                    try:
                        for k in list(self.all_polygons[group_name].keys()):
                            if _norm(k) == fp_norm:
                                store_key = k
                                break
                    except Exception:
                        store_key = filepath

                    payload = self.all_polygons[group_name].get(store_key, {}) or {}
                    payload.update(
                        {
                            "points": [(float(x), float(y)) for (x, y) in img_pts],
                            "coord_space": "image",
                            "image_ref_size": {"w": int(eff_w), "h": int(eff_h)},
                            "name": group_name,
                            "type": shape_type,
                        }
                    )

                    # Keep/refresh helpful metadata
                    if root_number is not None:
                        payload["root"] = root_number
                    if pm_w > 0 and pm_h > 0:
                        payload["pixmap_size"] = {"w": int(pm_w), "h": int(pm_h)}
                    try:
                        if getattr(it, "is_mask_polygon", False):
                            payload["is_mask_polygon"] = True
                    except Exception:
                        pass

                    # Check if this is a new entry (not already in all_polygons)
                    is_new_entry = store_key not in self.all_polygons.get(group_name, {})
                    
                    self.all_polygons[group_name][store_key] = payload
                    
                    # CRITICAL: Update index incrementally for new entries
                    if is_new_entry:
                        self._add_to_polygon_index(group_name, store_key)

                except Exception as e:
                    logging.debug(f"update_all_polygons: failed for {group_name} @ {filepath}: {e}")

        # Log summary for debugging
        logging.debug(f"[update_all_polygons] Synced {len(vw_pairs)} viewers")

        # PERFORMANCE: Only invalidate index if structure changed (deletion or new entry)
        # Coordinate updates of existing polygons don't change the filepath->group mapping
        if _index_needs_rebuild:
            self._poly_norm_index_invalid = True




    
 

