    def _cleanup_export_memory(self):
        """
        Clean up memory after export completes.
        Clears export-related caches and triggers garbage collection.
        """
        import gc
        import logging
        
        logging.info("[Memory] Cleaning up export caches...")
        
        try:
            # Clear export cache
            if hasattr(self, '_export_cache') and self._export_cache:
                if hasattr(self, '_export_cache_lock'):
                    with self._export_cache_lock:
                        self._export_cache.clear()
                else:
                    self._export_cache.clear()
                logging.info("[Memory] Cleared _export_cache")
        except Exception as e:
            logging.warning(f"[Memory] Failed to clear _export_cache: {e}")
        
        try:
            # Clear export image cache (BIGGEST memory user)
            if hasattr(self, '_export_image_cache') and self._export_image_cache:
                self._export_image_cache.clear()
                logging.info("[Memory] Cleared _export_image_cache")
        except Exception as e:
            logging.warning(f"[Memory] Failed to clear _export_image_cache: {e}")
        
        try:
            # Clear scene stats cache
            if hasattr(self, '_scene_stats_cache') and self._scene_stats_cache:
                self._scene_stats_cache.clear()
                logging.info("[Memory] Cleared _scene_stats_cache")
        except Exception as e:
            logging.warning(f"[Memory] Failed to clear _scene_stats_cache: {e}")
        
        try:
            # Clear any model expression caches
            if hasattr(self, '_precomputed_model_expr_cache'):
                self._precomputed_model_expr_cache.clear()
                logging.info("[Memory] Cleared _precomputed_model_expr_cache")
        except Exception:
            pass
        
        try:
            # Clear EXIF cache
            if hasattr(self, '_exif_cache') and self._exif_cache:
                self._exif_cache.clear()
                logging.info("[Memory] Cleared _exif_cache")
        except Exception:
            pass
        
        try:
            # Clear raw image cache
            if hasattr(self, '_raw_cache') and self._raw_cache:
                lock = getattr(self, '_raw_cache_lock', None)
                if lock:
                    with lock:
                        self._raw_cache.clear()
                else:
                    self._raw_cache.clear()
                logging.info("[Memory] Cleared _raw_cache")
        except Exception:
            pass
        
        try:
            # Clear .ax JSON cache
            if hasattr(self, '_ax_json_cache') and self._ax_json_cache:
                self._ax_json_cache.clear()
                logging.info("[Memory] Cleared _ax_json_cache")
        except Exception:
            pass
        
        try:
            # Clear effective H/W cache
            if hasattr(self, '_eff_hw_cache') and self._eff_hw_cache:
                self._eff_hw_cache.clear()
                logging.info("[Memory] Cleared _eff_hw_cache")
        except Exception:
            pass
        
        try:
            # Clear copy size cache
            if hasattr(self, '_copy_size_cache') and self._copy_size_cache:
                self._copy_size_cache.clear()
                logging.info("[Memory] Cleared _copy_size_cache")
        except Exception:
            pass
        
        try:
            # Clear band-math expression cache
            if hasattr(self, '_bm_expr_cache') and self._bm_expr_cache:
                self._bm_expr_cache.clear()
                logging.info("[Memory] Cleared _bm_expr_cache")
        except Exception:
            pass
        
        try:
            # Reset export counters
            self._export_files_processed = 0
        except Exception:
            pass
        
        try:
            # Clear cached NoData mask from _apply_ax_to_raw
            self._last_export_nodata_mask = None
            self._last_export_nodata_values = []
            self._last_export_nodata_filepath = None  # Also clear filepath
            # Clear per-filepath cache
            if hasattr(self, "_nodata_mask_by_filepath"):
                self._nodata_mask_by_filepath.clear()
        except Exception:
            pass
        
        # Force garbage collection multiple times to catch circular references
        # and release memory held by threads
        gc.collect()
        gc.collect()
        gc.collect()  # Third pass sometimes needed after threading
        logging.info("[Memory] Garbage collection complete")

    def update_polygon_manager(self):
        """
        PERFORMANCE OPTIMIZED: Only update polygon list if groups changed.
        For navigation, we only need to update current root selection.
        """
        if not self.polygon_manager.isVisible():
            return
        
        # Check if polygon groups have actually changed since last update
        current_groups = set(self.all_polygons.keys()) if self.all_polygons else set()
        last_groups = getattr(self.polygon_manager, '_cached_group_names', None)
        
        # Only rebuild list if groups changed (new group added/removed)
        if last_groups is None or current_groups != last_groups:
            self.polygon_manager.set_polygons(self.all_polygons)
        else:
            # Just update selection for current root (FAST)
            current_root = self.root_names[self.current_root_index] if self.root_names else None
            self.polygon_manager.set_current_root(current_root, self.image_data_groups)

    def select_polygon_from_manager(self, list_item):
        group_name = list_item.data(QtCore.Qt.UserRole)
        if group_name:
            # Iterate through all polygons to find and select them
            for widget in self.viewer_widgets:
                viewer = widget['viewer']
                for item in viewer.get_all_polygons():
                    if item.name == group_name:
                        item.setSelected(True)
                        viewer.centerOn(item)
            # Removed pop-up
        else:
            pass  # Handle cases where group_name is invalid if necessary


    def _debounced_jump(self, target_idx: int):
        """
        Debounced navigation - prevents freezing when user rapidly presses nav keys.
        Only the LAST requested index is navigated to after a short delay.
        """
        from PyQt5 import QtCore
        
        # Skip if navigation disabled or loading - don't even queue
        if not getattr(self, "_nav_controls_enabled", True):
            return
        if getattr(self, "_load_busy", False):
            return
        
        # Clamp target
        total = len(self.multispectral_root_names)
        if total == 0:
            return
        target_idx = max(0, min(target_idx, total - 1))
        
        # Skip if already at target
        if target_idx == getattr(self, 'current_root_index', -1):
            return
        
        # Store the pending target
        self._nav_pending_target = target_idx
        
        # Update slider/label immediately for visual feedback
        if hasattr(self, "group_slider"):
            self.group_slider.blockSignals(True)
            self.group_slider.setValue(target_idx)
            self.group_slider.blockSignals(False)
        self.update_slider_label(target_idx)
        
        # Create debounce timer if needed
        if not hasattr(self, '_nav_debounce_timer') or self._nav_debounce_timer is None:
            self._nav_debounce_timer = QtCore.QTimer(self)
            self._nav_debounce_timer.setSingleShot(True)
            self._nav_debounce_timer.timeout.connect(self._execute_debounced_nav)
        
        # Restart the timer (cancel previous pending nav)
        # Use 250ms delay - long enough to coalesce rapid presses
        self._nav_debounce_timer.stop()
        self._nav_debounce_timer.start(250)

    def _execute_debounced_nav(self):
        """Execute the actual navigation after debounce delay."""
        # Skip if navigation disabled or loading
        if not getattr(self, "_nav_controls_enabled", True):
            self._nav_pending_target = None
            return
        if getattr(self, "_load_busy", False):
            self._nav_pending_target = None
            return
        
        target = getattr(self, '_nav_pending_target', None)
        if target is None:
            return
        
        # Skip if we're already at this index
        if target == getattr(self, 'current_root_index', -1):
            self._nav_pending_target = None
            return
        
        # Clear pending target BEFORE jumping to prevent re-entry issues
        self._nav_pending_target = None
        
        # Do the actual jump
        self._jump_to_index(target)

    def prev_group(self):
        """Go to the previous root (debounced to prevent freeze on rapid presses)."""
        if not self.multispectral_root_names:
            return
        # Skip if navigation is disabled or loading
        if not getattr(self, "_nav_controls_enabled", True):
            return
        if getattr(self, "_load_busy", False):
            return
        # Use pending target if mid-debounce, else current index
        current = getattr(self, '_nav_pending_target', None)
        if current is None:
            current = self.current_root_index
        target = current - 1
        if target < 0:
            return
        self._debounced_jump(target)


    def next_group(self):
        """Go to the next root (debounced to prevent freeze on rapid presses)."""
        if not self.multispectral_root_names:
            return
        # Skip if navigation is disabled or loading
        if not getattr(self, "_nav_controls_enabled", True):
            return
        if getattr(self, "_load_busy", False):
            return
        # Use pending target if mid-debounce, else current index
        current = getattr(self, '_nav_pending_target', None)
        if current is None:
            current = self.current_root_index
        target = current + 1
        if target >= len(self.multispectral_root_names):
            return
        self._debounced_jump(target)

    

   
    def process_single_json_with_processor(self, json_file_path, tree, filenames, coordinates, output_folder):
        """
        Processes a single JSON file using the provided KD-Tree and coordinates.
        Finds the closest image for each target coordinate in the JSON file and saves the result in the 'jsons' folder.
        """
        print(f"\nProcessing JSON file: {json_file_path}")
        try:
            with open(json_file_path, 'r') as f:
                data = json.load(f)
        except Exception as e:
            print(f"Failed to load JSON file {json_file_path}: {e}")
            return

        # Extract target coordinates
        polygons = data.get('polygons') or data.get('points') or data.get('coordinates')
        if not polygons:
            print(f"No polygons or points found in JSON file: {json_file_path}", file=sys.stderr)
            return

        target_coords_list = []
        if 'coordinates' in data:
            target = data['coordinates']
            lat = target.get('latitude')
            lon = target.get('longitude')
            if lat is not None and lon is not None:
                try:
                    target_coords_list.append((float(lat), float(lon)))
                except (TypeError, ValueError) as e:
                    print(f"Invalid coordinate values in {json_file_path}: {e}", file=sys.stderr)
            else:
                print(f"Missing latitude or longitude in {json_file_path}. Skipping this entry.", file=sys.stderr)
        elif 'polygons' in data:
            for idx, polygon in enumerate(data['polygons'], 1):
                if not polygon:
                    print(f"Empty polygon at index {idx} in {json_file_path}. Skipping.", file=sys.stderr)
                    continue
                try:
                    avg_lat = sum(point[0] for point in polygon) / len(polygon)
                    avg_lon = sum(point[1] for point in polygon) / len(polygon)
                    if avg_lat is not None and avg_lon is not None:
                        target_coords_list.append((float(avg_lat), float(avg_lon)))
                    else:
                        print(f"Missing coordinates in polygon at index {idx} in {json_file_path}. Skipping.", file=sys.stderr)
                except (TypeError, IndexError, ValueError) as e:
                    print(f"Invalid polygon format at index {idx} in {json_file_path}: {e}. Skipping.", file=sys.stderr)
                    continue
        elif 'points' in data:
            for idx, point in enumerate(data['points'], 1):
                lat = point[0] if len(point) > 0 else None
                lon = point[1] if len(point) > 1 else None
                if lat is not None and lon is not None:
                    try:
                        target_coords_list.append((float(lat), float(lon)))
                    except (TypeError, ValueError) as e:
                        print(f"Invalid point values at index {idx} in {json_file_path}: {e}. Skipping.", file=sys.stderr)
                else:
                    print(f"Missing latitude or longitude in point at index {idx} in {json_file_path}. Skipping.", file=sys.stderr)

        if not target_coords_list:
            print(f"No valid target coordinates to process in JSON file: {json_file_path}", file=sys.stderr)
            return

        results = []

        # Find closest images
        print(f"Finding closest images for {len(target_coords_list)} target coordinates in {json_file_path}...")
        for idx, target_coords in enumerate(target_coords_list, 1):
            try:
                closest_image, distance = self.find_nearest_images(target_coords, tree, filenames, coordinates)
                result = {
                    'target_index': idx,
                    'closest_image': closest_image,
                    'distance_meters': distance,
                    'target_coordinates': {
                        'latitude': target_coords[0],
                        'longitude': target_coords[1]
                    }
                }
                results.append(result)
                print(f"Target {idx}: Closest image is '{closest_image}' at {distance:.2f} meters.")
            except Exception as e:
                print(f"Error finding nearest image for target {idx} in {json_file_path}: {e}", file=sys.stderr)
                continue

        # Save results to a JSON file in 'jsons' folder
        json_filename = os.path.splitext(os.path.basename(json_file_path))[0]
        output_file_path = os.path.join(output_folder, f"{json_filename}_results.json")
        try:
            with open(output_file_path, 'w') as f:
                json.dump(results, f, indent=4)
            print(f"Results saved to: {output_file_path}")
        except Exception as e:
            print(f"Failed to save results to {output_file_path}: {e}")
            
            
            
            
    def build_kdtree(self, gps_data):
        coordinates = [(item['latitude'], item['longitude']) for item in gps_data]
        filenames = [item['filename'] for item in gps_data]
        tree = KDTree(coordinates)
        return tree, filenames, coordinates

    def find_nearest_images(self, polygon_coords, tree, filenames, coordinates):
        distance, index = tree.query(polygon_coords)
        closest_filename = filenames[index]
        closest_coord = coordinates[index]
        distance_meters = geodesic(polygon_coords, closest_coord).meters
        return closest_filename, distance_meters
        
            
 
    def save_polygons(self):
        # Save polygons for current group to CSV
        self.save_polygons_to_csv() 


    def get_polygons_missing_coordinates(self):
        """
        Return (group_name, filepath) for polygons that truly need geo coords
        but don't have them.  skip polygons whose coord_space is not 'geo'.
        """
        missing = []
        for group_name, polygons in (self.all_polygons or {}).items():
            for filepath, polygon_data in (polygons or {}).items():
                pd = polygon_data or {}
                coord_space = (pd.get("coord_space") or "").lower()
                if coord_space and coord_space != "geo":
                    # Image-space polygon: do not require lat/lon
                    continue
                coords = pd.get("coordinates")
                if not isinstance(coords, dict):
                    missing.append((group_name, filepath))
                    continue
                lat = coords.get("latitude")
                lon = coords.get("longitude")
                # treat empty strings as missing too
                if lat in (None, "") or lon in (None, ""):
                    missing.append((group_name, filepath))
        return missing

   
    def open_image_folders(self):
        """
        Opens the currently used image folders (multispectral and thermal/RGB) in the file explorer.
        Ignores the synthetic/fake second folder created when the user skipped it.
        """
        import os, platform, subprocess
        from PyQt5 import QtWidgets

        FAKE_SENTINEL = "_FAKE_SECOND_FOLDER_"

        folders_to_open = []

        # Multispectral folder
        ms = getattr(self, "current_folder_path", "")
        if ms and os.path.isdir(ms):
            folders_to_open.append(ms)

        # Thermal/RGB folder — skip if fake or flagged
        trgb = getattr(self, "thermal_rgb_folder_path", "")
        is_fake = (
            getattr(self, "_dual_folder_fake_second", False)
            or (trgb and os.path.basename(os.path.normpath(trgb)) == FAKE_SENTINEL)
        )
        if trgb and not is_fake and os.path.isdir(trgb):
            folders_to_open.append(trgb)

        if not folders_to_open:
            QtWidgets.QMessageBox.warning(self, "No Folders", "No image folders are currently open.")
            return

        for folder in folders_to_open:
            try:
                if platform.system() == "Windows":
                    os.startfile(folder)
                elif platform.system() == "Darwin":
                    subprocess.Popen(["open", folder])
                else:
                    subprocess.Popen(["xdg-open", folder])
            except Exception as e:
                QtWidgets.QMessageBox.warning(self, "Folder Open Error",
                                              f"Could not open folder '{folder}': {e}")

