    def clean_polygons(self, viewer):
        """Clear polygons for a single viewer and update state."""
        viewer.clear_polygons()
        # Update all_polygons dictionary
        self.update_all_polygons()
        self.save_polygons_to_json(root_name=self.get_current_root_name())
        self.update_polygon_manager()

    def delete_polygons_for_viewer(self, viewer):
        """
        Delete all polygons for the specific file loaded in the viewer via Undo Stack.
        """
        if not viewer or not getattr(viewer, 'image_data', None):
            return
            
        filepath = getattr(viewer.image_data, 'filepath', None)
        if not filepath:
            return

        base = os.path.basename(filepath)
        self.undo_stack.beginMacro(f"Clean Polygons for {base}")
        try:
             # Find matching polygons
             polygons_dir = os.path.join(self.project_folder, "polygons") if self.project_folder else os.path.join(os.getcwd(), "polygons")
             
             # Use index for performance if available, otherwise scan matches
             groups_to_process = set()
             if hasattr(self, '_ensure_polygon_index'):
                 self._ensure_polygon_index()
                 # Exact match
                 if filepath in self._poly_exact_index:
                     groups_to_process.update(self._poly_exact_index[filepath])
                 # Norm match
                 fp_lower = os.path.normpath(filepath).lower()
                 if fp_lower in self._poly_norm_index:
                     for g, orig in self._poly_norm_index[fp_lower]:
                         groups_to_process.add(g)
             else:
                 # Fallback linear scan
                 fp_norm = os.path.normpath(filepath).lower()
                 for g, map_ in self.all_polygons.items():
                     for k in map_:
                         if os.path.normpath(k).lower() == fp_norm:
                             groups_to_process.add(g)
                             break
                         
             # Iterate identified groups
             for g in groups_to_process:
                 group_map = self.all_polygons.get(g)
                 if not group_map: continue
                 
                 # Find the specific entry
                 poly_data = None
                 key_found = None
                 
                 # Try exact key first
                 if filepath in group_map:
                     poly_data = group_map[filepath]
                     key_found = filepath
                 else:
                     # Check norm keys
                     fp_norm = os.path.normpath(filepath).lower()
                     for k, v in group_map.items():
                         if os.path.normpath(k).lower() == fp_norm:
                             poly_data = v
                             key_found = k
                             break
                 
                 if poly_data and key_found:
                     # Check for points (undo needs geometry)
                     points = poly_data.get("points", [])
                     if not points: continue
                     
                     try:
                         qpoly = QtGui.QPolygonF([QtCore.QPointF(x, y) for x, y in points])
                         base_fn = os.path.splitext(os.path.basename(key_found))[0]
                         json_path = os.path.join(polygons_dir, f"{g}_{base_fn}_polygons.json")
                         
                         json_content = None
                         if os.path.exists(json_path):
                             try:
                                 with open(json_path, 'r', encoding='utf-8') as f:
                                     json_content = f.read()
                             except: pass

                         cmd = DeletePolygonCommand(
                             project_tab=self,
                             label=poly_data.get("name", g),
                             filepath=key_found,
                             json_path=json_path,
                             json_content=json_content,
                             item_points=qpoly,
                             group_name=g
                         )
                         self.undo_stack.push(cmd)
                     except Exception as e:
                         logging.error(f"[CleanViewer] Failed to prep delete for {g}: {e}")

        except Exception as e:
            logging.error(f"[CleanViewer] Macro failed: {e}")
        finally:
            self.undo_stack.endMacro()
    def clean_all_polygons(self):
        """
        Permanently clears polygons for the CURRENT ROOT via Undo Stack.
        """
        active_roots = getattr(self, "root_names", None) or getattr(self, "multispectral_root_names", None)
        if not active_roots:
            print("No roots available – nothing to clean.")
            return

        idx = getattr(self, "current_root_index", -1)
        if not (0 <= idx < len(active_roots)):
            print("current_root_index out of range.")
            return

        current_root = active_roots[idx]
        current_filepaths = set(self.image_data_groups.get(current_root, []))
        if not current_filepaths:
            print(f"No filepaths for root '{current_root}'.")
            return

        self.undo_stack.beginMacro(f"Clean Root {current_root}")
        try:
            polygons_dir = os.path.join(self.project_folder, "polygons") if self.project_folder else os.path.join(os.getcwd(), "polygons")

            # Identify groups and keys to delete using index
            if hasattr(self, '_ensure_polygon_index'):
                self._ensure_polygon_index()
            
            # Map: group_name -> set of filepaths (keys) to delete
            deletions = defaultdict(set) # group -> keys

            # We iterate filepaths in this root and check index
            for fp in current_filepaths:
                # Exact
                if hasattr(self, '_poly_exact_index') and fp in self._poly_exact_index:
                    for g in self._poly_exact_index[fp]:
                        deletions[g].add(fp)
                
                # Norm
                fp_lower = os.path.normpath(fp).lower()
                if hasattr(self, '_poly_norm_index') and fp_lower in self._poly_norm_index:
                    for g, orig in self._poly_norm_index[fp_lower]:
                        deletions[g].add(orig)

            # Perform deletions
            for g, keys in deletions.items():
                group_map = self.all_polygons.get(g)
                if not group_map: continue
                
                for key in keys:
                    poly_data = group_map.get(key)
                    if not poly_data: continue

                    try: 
                        points = poly_data.get("points", [])
                        if not points: continue
                        
                        try:
                            # Undo needs QPolygonF
                            qpoly = QtGui.QPolygonF([QtCore.QPointF(x, y) for x, y in points])
                        except TypeError:
                            # Malformed points?
                            continue

                        base_fn = os.path.splitext(os.path.basename(key))[0]
                        json_path = os.path.join(polygons_dir, f"{g}_{base_fn}_polygons.json")
                        
                        json_content = None
                        if os.path.exists(json_path):
                            try:
                                with open(json_path, 'r', encoding='utf-8') as f:
                                    json_content = f.read()
                            except: pass
                            
                        cmd = DeletePolygonCommand(
                            project_tab=self,
                            label=poly_data.get("name", g),
                            filepath=key,
                            json_path=json_path,
                            json_content=json_content,
                            item_points=qpoly,
                            group_name=g
                        )
                        self.undo_stack.push(cmd)
                    except Exception as e:
                        logging.error(f"[CleanRoot] Failed to prep delete: {e}")

        except Exception as e:
            logging.error(f"[CleanRoot] Macro failed: {e}")
        finally:
            self.undo_stack.endMacro()
    def get_current_root_name(self):
        if self.multispectral_root_names and 0 <= self.current_root_index < len(self.multispectral_root_names):
            return self.multispectral_root_names[self.current_root_index]
        return None
    
    
    
    def save_project(self):
        """
        Saves the current project state to a JSON file within the selected project folder.
        Includes multispectral and thermal/RGB folder paths, root offset, all polygons,
        current root index, root geographical coordinates, root_mapping, and batch options.
        """
        import os, json

        if self.mode == 'dual_folder':
            if not self.current_folder_path or not self.thermal_rgb_folder_path:
                print("Multispectral or Thermal/RGB folder is not set. Please open folders first.")
                QtWidgets.QMessageBox.warning(
                    self, "Folders Not Set",
                    "Please open both Multispectral and Thermal/RGB folders before saving the project."
                )
                return
        elif self.mode == 'rgb_only':
            if not self.current_folder_path:
                print("RGB folder is not set. Please open a folder first.")
                QtWidgets.QMessageBox.warning(
                    self, "Folder Not Set",
                    "Please open an RGB folder before saving the project."
                )
                return

        # Prompt user to select a project folder
        options = QtWidgets.QFileDialog.Options()
        options |= QtWidgets.QFileDialog.DontUseNativeDialog
        project_folder = QtWidgets.QFileDialog.getExistingDirectory(
            self, "Select Project Folder", os.path.expanduser("~"), options=options)
        if not project_folder:
            return  # User canceled the dialog

        self.project_folder = project_folder  # Set the project folder path

        # Show progress dialog
        progress = QtWidgets.QProgressDialog("Saving project...", None, 0, 100, self)
        progress.setWindowTitle("Saving Project")
        progress.setWindowModality(QtCore.Qt.WindowModal)
        progress.setMinimumDuration(0)
        progress.setValue(5)
        QtWidgets.QApplication.processEvents()

        # Update Project Name Based on Folder Name
        project_name = os.path.basename(os.path.normpath(project_folder))
        self.update_project_name(project_name)

        # Compute Root Coordinates Before Saving
        progress.setLabelText("Computing coordinates...")
        progress.setValue(15)
        QtWidgets.QApplication.processEvents()
        self.compute_root_coordinates()

        # Map Matching Roots and Generate Mapping
        progress.setLabelText("Building root mappings...")
        progress.setValue(30)
        QtWidgets.QApplication.processEvents()
        self.map_matching_roots()

        # Prepare project data
        progress.setLabelText("Preparing project data...")
        progress.setValue(45)
        QtWidgets.QApplication.processEvents()
        
        project_data = {
            "project_name": self.project_name,
            "mode": self.mode,
            "root_offset": self.root_offset,
            "all_polygons": {k: v for k, v in self.all_polygons.items()},
            "current_root_index": self.current_root_index,
            "root_coordinates": self.root_coordinates,
            "root_mapping": getattr(self, "root_mapping_dict", {})  # Include root_mapping if present
        }

        # Save folder paths and batch options based on mode.
        if self.mode == 'dual_folder':
            project_data["multispectral_folder_path"] = self.current_folder_path
            project_data["thermal_rgb_folder_path"] = self.thermal_rgb_folder_path
        elif self.mode == 'rgb_only':
            project_data["rgb_folder_path"] = self.current_folder_path
            # Persist batch options and groups so load_project doesn't rescan/lose batches
            project_data["batch_size"] = int(getattr(self, "batch_size", 10) or 10)
            project_data["multispectral_root_names"] = list(getattr(self, "multispectral_root_names", []))
            project_data["multispectral_image_data_groups"] = dict(getattr(self, "multispectral_image_data_groups", {}))

        # Save project.json inside the project folder
        progress.setLabelText("Writing project file...")
        progress.setValue(60)
        QtWidgets.QApplication.processEvents()
        
        project_json_path = os.path.join(project_folder, 'project.json')
        try:
            with open(project_json_path, 'w', encoding='utf-8') as f:
                json.dump(project_data, f, indent=4)
            print(f"Project JSON saved to {project_json_path}")
        except Exception as e:
            progress.close()
            print(f"Failed to save project JSON: {e}")
            return

        # Save all polygons to the 'polygons' subdirectory within the project folder
        progress.setLabelText("Saving polygons...")
        progress.setValue(75)
        QtWidgets.QApplication.processEvents()
        
        self.save_polygons_to_json()

        progress.setValue(100)
        progress.close()
        
        # Clear dirty entries after full save
        if hasattr(self, '_dirty_polygon_entries'):
            self._dirty_polygon_entries.clear()
        
        print(f"Project saved to {self.project_folder}")
        QtWidgets.QMessageBox.information(
            self, "Save Successful", f"Project saved to {self.project_folder}"
        )

    def load_project(self, project_folder=None):
        """
        Loads a project state from a JSON file within the selected project folder.
        On dual-folder projects it DOES NOT prompt for matching; it uses the saved
        root_offset and rebuilds mapping via map_matching_roots().
        If the second folder is missing/invalid/fake, it is skipped and MS roots
        drive the UI (still in dual_folder mode).
        """
        import os, json, logging
        from collections import defaultdict

        # 1) Pick folder
        if project_folder is None:
            options = QtWidgets.QFileDialog.Options()
            options |= QtWidgets.QFileDialog.DontUseNativeDialog
            project_folder = QtWidgets.QFileDialog.getExistingDirectory(
                self, "Select Project Folder", os.path.expanduser("~"), options=options)
            if not project_folder:
                return

        project_json_path = os.path.join(project_folder, 'project.json')
        if not os.path.exists(project_json_path):
            QtWidgets.QMessageBox.warning(
                self, "Invalid Project Folder",
                "The selected folder does not contain a 'project.json' file."
            )
            return

        # Create progress dialog
        progress = QtWidgets.QProgressDialog("Loading project...", None, 0, 100, self)
        progress.setWindowTitle("Loading Project")
        progress.setWindowModality(QtCore.Qt.WindowModal)
        progress.setMinimumDuration(0)
        progress.setValue(5)
        QtWidgets.QApplication.processEvents()

        import time
        t_load_start = time.perf_counter()

        try:
            progress.setLabelText("Reading project file...")
            progress.setValue(10)
            QtWidgets.QApplication.processEvents()
            
            t0 = time.perf_counter()
            with open(project_json_path, 'r', encoding='utf-8') as f:
                project_data = json.load(f)
            t_json = time.perf_counter() - t0
            logging.info(f"[load_project] JSON parse took {t_json:.3f}s")
        except Exception as e:
            progress.close()
            QtWidgets.QMessageBox.critical(self, "Load Error", f"Failed to load the project file:\n{e}")
            return

        required_keys = {"all_polygons", "current_root_index", "root_offset", "root_coordinates"}
        if not required_keys.issubset(project_data.keys()):
            progress.close()
            QtWidgets.QMessageBox.critical(self, "Corrupted Project",
                                           "The project data is incomplete or corrupted.")
            return

        # 2) Restore basic state (no prompts)
        progress.setLabelText("Restoring project state...")
        progress.setValue(15)
        QtWidgets.QApplication.processEvents()
        
        self.root_offset = project_data.get("root_offset", 0)
        project_name = os.path.basename(os.path.normpath(project_folder))
        self.update_project_name(project_name)
        self.project_folder = project_folder

        # Determine mode (do not prompt)
        if "mode" in project_data:
            self.mode = project_data["mode"]
        else:
            has_ms  = bool(project_data.get("multispectral_folder_path"))
            has_tr  = bool(project_data.get("thermal_rgb_folder_path"))
            has_rgb = bool(project_data.get("rgb_folder_path"))
            self.mode = 'dual_folder' if (has_ms and has_tr) else ('rgb_only' if has_rgb else 'dual_folder')

        # 3) Load folders based on mode — NO matching dialog anywhere
        if self.mode == 'dual_folder':
            ms_path = project_data.get("multispectral_folder_path", "")
            tr_path = project_data.get("thermal_rgb_folder_path", "")

            if not ms_path or not os.path.exists(ms_path):
                progress.close()
                QtWidgets.QMessageBox.warning(self, "Folder Not Found",
                                              f"The multispectral folder path '{ms_path}' does not exist.")
                return

            # Always load multispectral
            progress.setLabelText("Loading multispectral images...")
            progress.setValue(25)
            QtWidgets.QApplication.processEvents()
            
            self.current_folder_path = ms_path
            self.load_multispectral_images_from_folder(self.current_folder_path)

            # Decide if second folder is usable; if not, skip cleanly
            FAKE_SENTINEL = "_FAKE_SECOND_FOLDER_"
            second_invalid = (
                not tr_path
                or not os.path.exists(tr_path)
                or os.path.basename(os.path.normpath(tr_path)) == FAKE_SENTINEL
            )

            if second_invalid:
                # Keep dual-folder structures valid but empty; drive UI from MS
                self.thermal_rgb_folder_path = os.path.join(self.project_folder, FAKE_SENTINEL)
                self.thermal_rgb_image_data_groups = {}
                self.thermal_rgb_root_names = []
                self._dual_folder_fake_second = True
                self.root_names = list(self.multispectral_root_names)
            else:
                progress.setLabelText("Loading thermal/RGB images...")
                progress.setValue(40)
                QtWidgets.QApplication.processEvents()
                
                self._dual_folder_fake_second = False
                self.thermal_rgb_folder_path = tr_path
                self.load_thermal_rgb_images_from_folder(self.thermal_rgb_folder_path)
              
                self.root_names = list(self.multispectral_root_names)

        elif self.mode == 'rgb_only':
            rgb_path = project_data.get("rgb_folder_path", "")
            if not rgb_path or not os.path.exists(rgb_path):
                progress.close()
                QtWidgets.QMessageBox.warning(self, "Folder Not Found",
                                              f"The RGB folder path '{rgb_path}' does not exist.")
                return

            progress.setLabelText("Loading RGB images...")
            progress.setValue(30)
            QtWidgets.QApplication.processEvents()
            
            self.current_folder_path = rgb_path
            saved_batch = project_data.get("batch_size", None)
            self.batch_size = int(saved_batch) if isinstance(saved_batch, (int, float, str)) and str(saved_batch).isdigit() else saved_batch
            if not self.batch_size or self.batch_size <= 0:
                self.batch_size = int(getattr(self, "batch_size", 0) or 0)

            saved_names  = project_data.get("multispectral_root_names") or []
            saved_groups = project_data.get("multispectral_image_data_groups") or {}
            if saved_names and saved_groups:
                self.multispectral_root_names = list(saved_names)
                from collections import defaultdict as _dd
                self.multispectral_image_data_groups = _dd(list)
                for root, files in saved_groups.items():
                    fixed = []
                    for p in files:
                        pp = p if os.path.isabs(p) else os.path.join(self.current_folder_path, p)
                        if not os.path.exists(pp):
                            cand = os.path.join(self.current_folder_path, os.path.basename(pp))
                            if os.path.exists(cand):
                                pp = cand
                        fixed.append(pp)
                    self.multispectral_image_data_groups[root] = fixed
                if not self.batch_size:
                    try:
                        first_len = len(next(iter(self.multispectral_image_data_groups.values())))
                        self.batch_size = first_len if first_len > 0 else 10
                    except StopIteration:
                        self.batch_size = 10
            else:
                exts = ('.png', '.jpg', '.jpeg', '.bmp', '.tif', '.tiff')
                all_images = sorted(
                    os.path.join(self.current_folder_path, f)
                    for f in os.listdir(self.current_folder_path)
                    if f.lower().endswith(exts)
                )
                b = self.batch_size if (isinstance(self.batch_size, int) and self.batch_size > 0) else 10
                self.batch_size = b
                self.multispectral_root_names = []
                from collections import defaultdict as _dd
                self.multispectral_image_data_groups = _dd(list)
                for i in range(0, len(all_images), b):
                    root = f"Root{i//b + 1}"
                    self.multispectral_root_names.append(root)
                    self.multispectral_image_data_groups[root] = all_images[i:i+b]

            self.root_names = list(self.multispectral_root_names)
            self.root_id_mapping = {name: i + 1 for i, name in enumerate(self.multispectral_root_names)}

        else:
            progress.close()
            QtWidgets.QMessageBox.warning(self, "Unknown Mode",
                                          f"The project data contains an unknown mode: '{self.mode}'.")
            return

        # 4) Build root_id mapping strictly from saved root_offset (no UI)
        progress.setLabelText("Building root mappings...")
        progress.setValue(55)
        QtWidgets.QApplication.processEvents()
        
        # PERFORMANCE FIX: Try to load existing root_mapping.json instead of regenerating
        root_mapping_loaded = False
        try:
            mapping_path = os.path.join(self.project_folder, 'root_mapping.json') if self.project_folder else None
            if mapping_path and os.path.exists(mapping_path):
                with open(mapping_path, 'r', encoding='utf-8') as f:
                    saved_mapping = json.load(f)
                # Validate it has expected structure
                if isinstance(saved_mapping, dict) and len(saved_mapping) > 0:
                    # Rebuild root_id_mapping and id_to_root from saved file
                    self.root_id_mapping = {}
                    self.id_to_root = {}
                    self.root_mapping_dict = saved_mapping
                    for rid_str, entry in saved_mapping.items():
                        try:
                            rid = int(rid_str)
                            # Get root name from entry or id_to_root convention
                            if isinstance(entry, dict):
                                # Find the root name - check folder1 files or use index
                                if rid - 1 < len(self.multispectral_root_names):
                                    root_name = self.multispectral_root_names[rid - 1]
                                    self.root_id_mapping[root_name] = rid
                                    self.id_to_root[rid] = root_name
                                    # Also map thermal/RGB root if exists
                                    tr_idx = (rid - 1) + self.root_offset
                                    if hasattr(self, 'thermal_rgb_root_names') and 0 <= tr_idx < len(self.thermal_rgb_root_names):
                                        tr_root = self.thermal_rgb_root_names[tr_idx]
                                        self.root_id_mapping[tr_root] = rid
                        except (ValueError, TypeError):
                            continue
                    if self.root_id_mapping:
                        root_mapping_loaded = True
                        logging.info(f"[load_project] Loaded existing root_mapping.json with {len(self.root_id_mapping)} entries")
        except Exception as e:
            logging.debug(f"[load_project] Could not load root_mapping.json: {e}")
        
        # Fallback: Try to load root_mapping from project.json if root_mapping.json not found
        if not root_mapping_loaded:
            try:
                saved_mapping = project_data.get("root_mapping", {})
                if isinstance(saved_mapping, dict) and len(saved_mapping) > 0:
                    self.root_id_mapping = {}
                    self.id_to_root = {}
                    self.root_mapping_dict = saved_mapping
                    for rid_str, entry in saved_mapping.items():
                        try:
                            rid = int(rid_str)
                            if isinstance(entry, dict):
                                if rid - 1 < len(self.multispectral_root_names):
                                    root_name = self.multispectral_root_names[rid - 1]
                                    self.root_id_mapping[root_name] = rid
                                    self.id_to_root[rid] = root_name
                                    tr_idx = (rid - 1) + self.root_offset
                                    if hasattr(self, 'thermal_rgb_root_names') and 0 <= tr_idx < len(self.thermal_rgb_root_names):
                                        tr_root = self.thermal_rgb_root_names[tr_idx]
                                        self.root_id_mapping[tr_root] = rid
                        except (ValueError, TypeError):
                            continue
                    if self.root_id_mapping:
                        root_mapping_loaded = True
                        logging.info(f"[load_project] Loaded root_mapping from project.json with {len(self.root_id_mapping)} entries")
            except Exception as e:
                logging.debug(f"[load_project] Could not load root_mapping from project.json: {e}")
        
        if not root_mapping_loaded:
            self.map_matching_roots()
        else:
            # --- CRITICAL FIX: Restore filtered state from mapping ---
            # If we loaded a mapping, it implies the user might have filtered images.
            # The earlier load_multispectral_images_from_folder() brought back ALL files.
            # We must now prune/rebuild the lists to match the saved mapping.
            
            logging.info(f"[load_project] Restoring filtered state from {len(self.root_mapping_dict)} mapped roots...")
            
            new_ms_roots = []
            new_ms_groups = defaultdict(list)
            new_th_roots = []
            new_th_groups = defaultdict(list)
            
            # Rebuild based on sorted root IDs
            sorted_rids = sorted(self.id_to_root.keys())
            
            for rid in sorted_rids:
                root_name = self.id_to_root[rid]
                entry = self.root_mapping_dict.get(str(rid))
                if not entry:
                    continue
                
                # Restore Multispectral
                # Entry schema: {'folder1': {'dir':..., 'files': [...]}, ...}
                f1 = entry.get('folder1')
                if f1 and f1.get('files'):
                    # Reconstruct full paths
                    d = f1.get('dir')
                    # If dir is None or relative, try to resolve against current_folder_path
                    dir_path = d
                    if not dir_path or (not os.path.isabs(dir_path)):
                        dir_path = self.current_folder_path
                    
                    files = []
                    for fname in f1['files']:
                        files.append(os.path.join(dir_path, fname))
                    
                    if files:
                        new_ms_roots.append(root_name)
                        new_ms_groups[root_name] = files

                # Restore Thermal/RGB
                f2 = entry.get('folder2')
                if f2 and f2.get('files'):
                    d = f2.get('dir')
                    dir_path = d
                    if not dir_path or (not os.path.isabs(dir_path)):
                        dir_path = self.thermal_rgb_folder_path
                    
                    files = []
                    for fname in f2['files']:
                        files.append(os.path.join(dir_path, fname))
                    
                    if files:
                        # For thermal, we track roots but usually they align with MS via offset
                        # We'll just add to groups. If separate root names needed, adds here.
                        # (Normally th root names are just same logic or different list)
                        # We need the thermal ROOT NAME. 
                        # Usually implied by offset, but let's try to find it or infer it.
                        # If we have a stored list of thermal roots, we might need to find which one corresponds.
                        # For now, just store in the group dict using the root_name? 
                        # Wait, thermal groups usually keyed by thermal root name.
                        # Using ms root name as key for thermal group is SAFE if we share keys, 
                        # but typically they use their own names.
                        
                        # Fallback: if we can't easily deduce thermal root name, 
                        # use the first file's root name logic or just index?
                        # ACTUALLY: existing load_thermal... populated self.thermal_rgb_root_names 
                        # with ALL roots. We should pick the one that matches this ID.
                        
                        # Let's see if we can find the thermal root name for this RID
                        # id_to_root[rid] gives the MS root name usually.
                        # We need the TH root name.
                        
                        # Simple approach: Rebuild thermal roots only if we can match them.
                        pass

            # Apply restored MS lists
            if new_ms_roots:
                self.multispectral_root_names = new_ms_roots
                self.multispectral_image_data_groups = new_ms_groups
                self.root_names = list(self.multispectral_root_names)
                logging.info(f"[load_project] Filtered down to {len(self.multispectral_root_names)} roots.")
            
            # Also invoke filter on thermal groups to keep them in sync
            # (Loop through thermal_rgb_image_data_groups and valid_ms_roots?)
            # For simplicity, if MS is filtered, thermal should ostensibly be filtered too 
            # if we trust the map.
            
            # Re-generate thermal lists from the map (more robust)
            # We need to populate new_th_roots and new_th_groups
            
            # Reset TH lists
            from collections import defaultdict
            self.thermal_rgb_root_names = []
            self.thermal_rgb_image_data_groups = defaultdict(list)
            
            # Scan map again for thermal
            for rid in sorted_rids:
                entry = self.root_mapping_dict.get(str(rid))
                if not entry: continue
                
                f2 = entry.get('folder2')
                if f2 and f2.get('files'):
                    d = f2.get('dir')
                    dir_path = d or self.thermal_rgb_folder_path
                    if not os.path.exists(dir_path) and not os.path.isabs(dir_path):
                         dir_path = os.path.join(self.project_folder, dir_path) if dir_path else self.thermal_rgb_folder_path

                    files = [os.path.join(dir_path, fn) for fn in f2['files']]
                    if files:
                        # Extract root name from first file to be safe? 
                        # OR if we know the offset, we can't easily guess the name without scanning.
                        # BETTER: Just infer it from filename
                        th_root = self.extract_root_name(os.path.basename(files[0]))
                        self.thermal_rgb_root_names.append(th_root)
                        self.thermal_rgb_image_data_groups[th_root] = files
            
            # Invalidate filepath cache
            self._filepath_to_root_cache = None

        # 5) Restore polygons & state
        progress.setLabelText("Restoring polygons...")
        progress.setValue(65)
        QtWidgets.QApplication.processEvents()
        
        t0 = time.perf_counter()
        self.all_polygons       = defaultdict(dict, project_data["all_polygons"])
        t_dict = time.perf_counter() - t0
        
        self.root_coordinates   = project_data.get("root_coordinates", {})
        self.current_root_index = project_data.get("current_root_index", 0)

        # Log polygon count for debugging (fast count, don't iterate all values)
        group_count = len(self.all_polygons)
        poly_count = sum(len(fm) for fm in self.all_polygons.values() if isinstance(fm, dict))
        logging.info(f"[load_project] Loaded {group_count} polygon groups, {poly_count} total entries (dict creation: {t_dict:.3f}s)")

        progress.setLabelText("Preparing polygon system...")
        progress.setValue(75)
        QtWidgets.QApplication.processEvents()
        
        # Defer index building to first use (lazy loading is faster for startup)
        self._poly_norm_index_invalid = True

        # Clear all caches to ensure fresh calculations after load
        try:
            if hasattr(self, "_scene_stats_cache"):
                self._scene_stats_cache.clear()
            if hasattr(self, "_export_cache"):
                self._export_cache.clear()
            logging.debug("[load_project] Cleared all caches after project load")
        except Exception:
            pass

        # Clamp index
        if not (0 <= self.current_root_index < len(self.multispectral_root_names)):
            self.current_root_index = 0

        # 6) Slider + label (numeric if helper exists)
        self.group_slider.blockSignals(True)
        self.group_slider.setMaximum(len(self.multispectral_root_names) - 1 if self.multispectral_root_names else 0)
        self.group_slider.setValue(self.current_root_index)
        self.group_slider.blockSignals(False)

        try:
            # numeric label only
            self.slider_label.setText(self._root_number_for_index(self.current_root_index))
        except Exception:
            # fallback to name if helper not present
            if self.multispectral_root_names:
                self.slider_label.setText(f"Root: {self.multispectral_root_names[self.current_root_index]}")
            else:
                self.slider_label.setText("Root: N/A")

        # 7) Load the current group (no extra prompts)
        # Close initial progress and create a new one for image loading
        progress.close()
        
        if self.multispectral_root_names:
            cur_root = self.multispectral_root_names[self.current_root_index]
            # Create progress dialog for image loading - will be managed by load_image_group
            img_progress = QtWidgets.QProgressDialog("Loading images...", None, 0, 100, self)
            img_progress.setWindowTitle("Loading Images")
            img_progress.setWindowModality(QtCore.Qt.WindowModal)
            img_progress.setMinimumDuration(0)
            img_progress.setValue(0)
            QtWidgets.QApplication.processEvents()
            self.load_image_group(cur_root, progress_dialog=img_progress)

        # 8) Update polygon manager
        self.update_polygon_manager()
        
        print(f"Project loaded from {self.project_folder}")


    def save_project_quick(self, *, skip_recompute: bool = False,
                           root_scope: str = "all", wrap: bool = True, skip_polygon_files: bool = False):
        """
        Saves the current project to the existing project folder without prompting the user.
        If no project folder is set, behaves like 'Save Project'.

        If skip_recompute=True, this will NOT prompt to recompute missing coordinates.

        New:
          - root_scope: 'all' (default), 'current', 'prev', or 'next'.
            When not 'all', only polygon files for the selected root are written.
          - wrap: whether 'prev'/'next' wrap around the ends (default True).
          - skip_polygon_files: if True, skips writing individual .json polygon files (FAST).
            Useful for operations like batch size change where only project.json is needed.

        Also persists batch_size and grouped lists in rgb_only mode (same as save_project()).
        """
        import os, json

        # ----------------- helpers (local) -----------------
        def _norm(fp): return os.path.normcase(os.path.abspath(fp))

        def _resolve_root_names_in_order():
            """
            Best-effort root ordering used by the UI. We try common attrs first,
            then fall back to root_mapping_dict key order.
            """
            if hasattr(self, "root_names") and isinstance(self.root_names, (list, tuple)) and self.root_names:
                return list(self.root_names)
            if hasattr(self, "multispectral_root_names") and isinstance(self.multispectral_root_names, (list, tuple)) and self.multispectral_root_names:
                return list(self.multispectral_root_names)
            if isinstance(getattr(self, "root_mapping_dict", None), dict) and self.root_mapping_dict:
                # Preserve insertion order if dict is ordered (Py3.7+)
                return list(self.root_mapping_dict.keys())
            # Fallback: infer from polygons present
            roots = []
            seen = set()
            for group_polygons in getattr(self, "all_polygons", {}).values():
                for fp in group_polygons.keys():
                    rn = self.get_root_by_filepath(fp)
                    if rn not in seen:
                        roots.append(rn); seen.add(rn)
            return roots

        def _filepaths_for_root(root_name: str):
            """Collect filepaths (across all groups) that belong to a given root name."""
            hits = []
            for group_polygons in getattr(self, "all_polygons", {}).values():
                for fp in group_polygons.keys():
                    try:
                        if self.get_root_by_filepath(fp) == root_name:
                            hits.append(fp)
                    except Exception:
                        # If mapping fails, skip
                        pass
            return hits

        def _save_polygons_subset(include_paths):
            """Temporarily filter self.all_polygons, call existing saver, then restore."""
            include_set = {_norm(p) for p in include_paths}
            orig = self.all_polygons
            try:
                filtered = {}
                for grp, mp in (orig or {}).items():
                    sub = {fp: mp[fp] for fp in mp if _norm(fp) in include_set}
                    if sub:
                        filtered[grp] = sub
                self.all_polygons = filtered
                self.save_polygons_to_json()
            finally:
                self.all_polygons = orig
        # ---------------------------------------------------

        if not self.project_folder:
            self.save_project()
            return

        # Optional recompute prompt
        if not skip_recompute:
            missing_polygons = self.get_polygons_missing_coordinates()
            if missing_polygons:
                reply = QtWidgets.QMessageBox.question(
                    self,
                    "Missing Coordinates Detected",
                    f"{len(missing_polygons)} polygons do not have geographical coordinates assigned. "
                    "Would you like to recompute coordinates for these polygons before saving?",
                    QtWidgets.QMessageBox.Yes | QtWidgets.QMessageBox.No,
                    QtWidgets.QMessageBox.Yes
                )
                if reply == QtWidgets.QMessageBox.Yes:
                    self.compute_root_coordinates()
                    self.generate_all_thumbnails()
                    QtWidgets.QMessageBox.information(
                        self,
                        "Coordinates Recomputed",
                        "Geographical coordinates have been recomputed for polygons missing them, and thumbnails have been updated."
                    )

        # If no coordinates in memory, try to load existing ones from project.json
        if not getattr(self, "root_coordinates", None):
            project_json_path = os.path.join(self.project_folder, 'project.json')
            if os.path.exists(project_json_path):
                try:
                    with open(project_json_path, 'r', encoding='utf-8') as f:
                        existing_project_data = json.load(f)
                    self.root_coordinates = existing_project_data.get("root_coordinates", {})
                except Exception as e:
                    print(f"Failed to load existing root coordinates: {e}")

        # Prepare project data (mirror save_project)
        project_data = {
            "project_name": self.project_name,
            "mode": self.mode,
            "root_offset": self.root_offset,
            "all_polygons": {k: v for k, v in self.all_polygons.items()},
            "current_root_index": self.current_root_index,
            "root_coordinates": self.root_coordinates,
            "root_mapping": getattr(self, "root_mapping_dict", {})
        }

        if self.mode == 'dual_folder':
            project_data["multispectral_folder_path"] = self.current_folder_path
            project_data["thermal_rgb_folder_path"] = self.thermal_rgb_folder_path
        elif self.mode == 'rgb_only':
            project_data["rgb_folder_path"] = self.current_folder_path
            project_data["batch_size"] = int(getattr(self, "batch_size", 10) or 10)
            project_data["multispectral_root_names"] = list(getattr(self, "multispectral_root_names", []))
            project_data["multispectral_image_data_groups"] = dict(getattr(self, "multispectral_image_data_groups", {}))

        # Show progress dialog during save
        progress = QtWidgets.QProgressDialog("Saving project...", None, 0, 100, self)
        progress.setWindowTitle("Saving")
        progress.setWindowModality(QtCore.Qt.WindowModal)
        progress.setMinimumDuration(200)  # Only show if takes > 200ms
        progress.setValue(10)
        QtWidgets.QApplication.processEvents()

        # Save project.json
        progress.setLabelText("Writing project file...")
        progress.setValue(30)
        QtWidgets.QApplication.processEvents()
        
        project_json_path = os.path.join(self.project_folder, 'project.json')
        try:
            with open(project_json_path, 'w', encoding='utf-8') as f:
                import json as _json
                _json.dump(project_data, f, indent=4)
            print(f"Project JSON saved to {project_json_path}")
        except Exception as e:
            progress.close()
            print(f"Failed to save project JSON: {e}")
            return

        # Decide polygon save scope
        if skip_polygon_files:
            logging.info("save_project_quick: Skipping individual polygon file writes (skip_polygon_files=True).")
            progress.setValue(100)
            progress.close()
            return

        progress.setLabelText("Saving polygons...")
        progress.setValue(50)
        QtWidgets.QApplication.processEvents()
        
        scope = (root_scope or "all").lower()
        if scope == "all":
            self.save_polygons_to_json()
        else:
            names = _resolve_root_names_in_order()
            if not names:
                print("Could not resolve root ordering; saving all polygons.")
                self.save_polygons_to_json()
            else:
                total = len(names)
                cur = int(getattr(self, "current_root_index", 0) or 0)
                if scope == "current":
                    idx = max(0, min(cur, total - 1))
                elif scope == "prev":
                    idx = (cur - 1) % total if wrap else max(0, cur - 1)
                elif scope == "next":
                    idx = (cur + 1) % total if wrap else min(total - 1, cur + 1)
                else:
                    print(f"Unknown root_scope={root_scope!r}; saving all polygons.")
                    self.save_polygons_to_json()
                    progress.setValue(100)
                    progress.close()
                    print(f"Project saved to {self.project_folder}")
                    return

                primary_root = names[idx]
                # 🔧 include the paired root when in dual_folder
                roots_to_save = {primary_root}
                if getattr(self, "mode", None) == "dual_folder":
                    if hasattr(self, "_paired_thermal_root"):
                        pr = self._paired_thermal_root(primary_root)
                        if pr: roots_to_save.add(pr)
                    if hasattr(self, "_paired_ms_root"):
                        mr = self._paired_ms_root(primary_root)
                        if mr: roots_to_save.add(mr)

                # Collect all filepaths across these roots
                fps = []
                for rn in roots_to_save:
                    fps.extend(_filepaths_for_root(rn))

                if not fps:
                    print(f"No polygons found for roots {sorted(roots_to_save)}. Nothing to save for this scope.")
                else:
                    _save_polygons_subset(fps)
                    print(f"Saved polygons for roots {sorted(roots_to_save)} ({len(fps)} files).")

        progress.setValue(100)
        progress.close()
        
        # Clear dirty entries after full save
        if hasattr(self, '_dirty_polygon_entries'):
            self._dirty_polygon_entries.clear()
        
        print(f"Project saved to {self.project_folder}")


    # Optional convenience wrappers
    def save_project_quick_current_root(self, *, skip_recompute: bool = True, wrap: bool = True):
        return self.save_project_quick(skip_recompute=skip_recompute, root_scope="current", wrap=wrap)

    def save_project_quick_prev_root(self, *, skip_recompute: bool = True, wrap: bool = True):
        return self.save_project_quick(skip_recompute=skip_recompute, root_scope="prev", wrap=wrap)

    def save_project_quick_next_root(self, *, skip_recompute: bool = True, wrap: bool = True):
        return self.save_project_quick(skip_recompute=skip_recompute, root_scope="next", wrap=wrap)

    # ==================== INCREMENTAL SAVE (FAST) ====================

    def save_incremental(self, show_status: bool = True, update_project_json: bool = True):
        """
        FAST SAVE: Saves modified polygon files AND optionally updates project.json state.
        
        - Only writes individual polygon JSON files that have changed
        - Optionally updates project.json with current state (all_polygons, current_root_index)
        - Updates polygon manager UI
        
        Args:
            show_status: Whether to log save status
            update_project_json: Whether to update project.json (default True for Ctrl+Q)
        
        This is what Ctrl+Q calls for fast saves.
        """
        import os, json, logging
        
        if not self.project_folder:
            # No project folder - fall back to full save
            self.save_project()
            return
        
        dirty = getattr(self, '_dirty_polygon_entries', set())
        
        # If nothing dirty and not forcing project.json update, skip
        if not dirty and not update_project_json:
            if show_status:
                logging.info("[save_incremental] No changes to save")
            return
        
        polygons_dir = os.path.join(self.project_folder, 'polygons')
        os.makedirs(polygons_dir, exist_ok=True)
        
        saved_count = 0
        errors = []
        
        # Helper to get coordinates
        def _get_coords(filepath, polygon_data):
            coords = None
            if isinstance(polygon_data, dict):
                c = polygon_data.get('coordinates')
                if isinstance(c, dict) and 'latitude' in c and 'longitude' in c:
                    coords = c
            if not coords:
                try:
                    root = self.get_root_by_filepath(filepath)
                    if root and hasattr(self, 'root_coordinates'):
                        coords = self.root_coordinates.get(root)
                except Exception:
                    pass
            return coords
        
        # Helper to get root ID
        def _get_root_id(filepath):
            try:
                root = self.get_root_by_filepath(filepath)
                if root and hasattr(self, 'root_id_mapping'):
                    return str(self.root_id_mapping.get(root, "0"))
            except Exception:
                pass
            return "0"
        
        # Process each dirty entry (write individual polygon files)
        if dirty:
            # 1) PREPARE tasks on Main Thread
            io_tasks = []
            
            for group_name, filepath in list(dirty):
                try:
                    # Get the polygon data from memory
                    polygon_data = None
                    if hasattr(self, 'all_polygons') and self.all_polygons:
                        polygon_data = self.all_polygons.get(group_name, {}).get(filepath)
                    
                    if polygon_data is None:
                        # DELETE TASK
                        base_filename = os.path.splitext(os.path.basename(filepath))[0]
                        polygon_filename = f"{group_name}_{base_filename}_polygons.json"
                        polygon_filepath = os.path.join(polygons_dir, polygon_filename)
                        io_tasks.append(("delete", polygon_filepath, (group_name, filepath)))
                        continue
                    
                    # SAVE TASK - Build save data
                    pts = polygon_data.get('points', [])
                    ref_size = polygon_data.get('image_ref_size', {})
                    
                    data_to_save = {
                        'points': [(float(x), float(y)) for x, y in pts] if pts else [],
                        'name': polygon_data.get('name', group_name),
                        'root': _get_root_id(filepath),
                        'coordinates': _get_coords(filepath, polygon_data),
                        'type': polygon_data.get('type', 'polygon'),
                        'coord_space': polygon_data.get('coord_space', 'image'),
                        'image_ref_size': ref_size,
                    }
                    
                    base_filename = os.path.splitext(os.path.basename(filepath))[0]
                    polygon_filename = f"{group_name}_{base_filename}_polygons.json"
                    polygon_filepath = os.path.join(polygons_dir, polygon_filename)
                    
                    io_tasks.append(("save", polygon_filepath, (group_name, filepath), data_to_save))

                except Exception as e:
                    errors.append(f"{group_name}/{os.path.basename(filepath)}: {e}")
                    logging.warning(f"[save_incremental] Failed to PREPARE {group_name}/{filepath}: {e}")

            # 2) EXECUTE I/O Parallel
            import concurrent.futures
            
            def _exec_io_task(task):
                # task is tuple: (type, path, key, [data])
                op_type = task[0]
                path = task[1]
                key = task[2] # (group_name, filepath)
                
                try:
                    if op_type == "delete":
                        if os.path.exists(path):
                            os.remove(path)
                            logging.debug(f"[save_incremental] Deleted {os.path.basename(path)}")
                        return (True, key)
                    elif op_type == "save":
                        data = task[3]
                        with open(path, 'w', encoding='utf-8') as f:
                            json.dump(data, f, indent=2)
                        return (True, key)
                except Exception as e:
                    logging.warning(f"[save_incremental] IO error {op_type} for {path}: {e}")
                    return (False, key, str(e))
                return (False, key, "Unknown error")

            if io_tasks:
                with concurrent.futures.ThreadPoolExecutor(max_workers=16) as executor:
                    results = list(executor.map(_exec_io_task, io_tasks))
                
                # Process results to clear dirty set
                for res in results:
                    success = res[0]
                    key = res[1]
                    if success:
                        saved_count += 1
                        dirty.discard(key)
                    else:
                        err_msg = res[2] if len(res) > 2 else "Unknown"
                        errors.append(f"{key}: {err_msg}")
        
        # Update project.json with current state (fast - just memory to disk)
        if update_project_json:
            project_json_path = os.path.join(self.project_folder, 'project.json')
            try:
                # Load existing project data to preserve other fields
                existing_data = {}
                if os.path.exists(project_json_path):
                    with open(project_json_path, 'r', encoding='utf-8') as f:
                        existing_data = json.load(f) or {}
                
                # Update only the fields that matter for quick save
                existing_data["all_polygons"] = {k: v for k, v in (self.all_polygons or {}).items()}
                existing_data["current_root_index"] = self.current_root_index
                existing_data["root_coordinates"] = getattr(self, "root_coordinates", {}) or {}
                
                # Write back
                with open(project_json_path, 'w', encoding='utf-8') as f:
                    json.dump(existing_data, f, indent=4)
                
            except Exception as e:
                logging.warning(f"[save_incremental] Failed to update project.json: {e}")
        
        # Clear dirty tracking
        if hasattr(self, '_dirty_polygon_roots'):
            self._dirty_polygon_roots.clear()
        if hasattr(self, '_dirty_polygon_entries'):
            self._dirty_polygon_entries.clear()
        
        # Update polygon manager UI
        try:
            if hasattr(self, 'update_polygon_manager'):
                self.update_polygon_manager()
        except Exception:
            pass
        
        if show_status:
            json_msg = " + project.json" if update_project_json else ""
            if saved_count > 0:
                logging.info(f"[save_incremental] Saved {saved_count} polygon file(s){json_msg}")
            elif update_project_json:
                logging.info("[save_incremental] Updated project.json (no polygon files changed)")
            else:
                logging.info("[save_incremental] No changes to save")
            if errors:
                logging.warning(f"[save_incremental] {len(errors)} error(s)")
    
    def _toggle_autosave(self, state):
        """Toggle autosave on/off."""
        self._autosave_enabled = bool(state)
        if self._autosave_enabled:
            self._autosave_timer.start(self._autosave_interval_ms)
            logging.info(f"[Autosave] Enabled - saving every {self._autosave_interval_ms // 1000}s")
        else:
            self._autosave_timer.stop()
            logging.info("[Autosave] Disabled")
    
    def _autosave_tick(self):
        """Called by autosave timer - performs incremental save if there are changes."""
        if not self.project_folder:
            return
        
        # CRITICAL FIX: Sync ALL viewer polygons to memory BEFORE saving
        # Without this, autosave only saves stale data from self.all_polygons,
        # missing current viewer positions that haven't been synced yet.
        has_viewers = bool(getattr(self, "viewer_widgets", None))
        viewer_count = len(getattr(self, "viewer_widgets", []) or [])
        
        if has_viewers:
            try:
                if hasattr(self, "update_all_polygons"):
                    self.update_all_polygons()
                    logging.debug(f"[Autosave] Synced {viewer_count} viewers to memory")
            except Exception as e:
                logging.debug(f"[Autosave] update_all_polygons failed: {e}")
        
        # Check for dirty polygon entries (individual file saves)
        dirty = getattr(self, '_dirty_polygon_entries', set())
        dirty_roots = getattr(self, '_dirty_polygon_roots', set())
        
        # Count polygons in memory for debugging
        poly_count = sum(len(fm) for fm in (self.all_polygons or {}).values() if isinstance(fm, dict))
        
        # Save if there are any dirty entries or roots
        if dirty or dirty_roots:
            logging.info(f"[Autosave] Saving {len(dirty)} dirty entries, {len(dirty_roots)} dirty roots, {poly_count} total polygons in memory")
            self.save_incremental(show_status=False, update_project_json=True)
        # If no dirty entries, skip save entirely
    
    def set_autosave_interval(self, seconds: int):
        """Set the autosave interval in seconds."""
        self._autosave_interval_ms = max(10, seconds) * 1000
        if self._autosave_enabled:
            self._autosave_timer.stop()
            self._autosave_timer.start(self._autosave_interval_ms)
        logging.info(f"[Autosave] Interval set to {seconds}s")

    # ==================== END INCREMENTAL SAVE ====================



    def refresh_viewer(self, root_name=None):
        """
        Refreshes the viewer for a specific root by reloading images.
        If no root_name is provided, refreshes the current root.
        """
        # CRITICAL: Flush pending polygon updates before reloading
        # This ensures any moved/deleted polygons are saved to disk first
        try:
            if hasattr(self, "_flush_dirty_polygons"):
                self._flush_dirty_polygons()
            if hasattr(self, "update_all_polygons"):
                self.update_all_polygons()
        except Exception:
            pass
        
        if root_name:
            # PERFORMANCE: Use O(1) cached lookup instead of O(N) .index()
            root_index = self._get_ms_root_index(root_name)
            if root_index is None:
                QMessageBox.warning(self, "Invalid Root Name", f"Root '{root_name}' does not exist.")
                logging.warning(f"Attempted to refresh viewer for non-existent root '{root_name}'.")
                return
        else:
            # Use the current root index
            root_index = self.current_root_index

        #if not self.project_folder:
            #QMessageBox.warning(self, "No Project Folder", "Project folder is not set.")
           # logging.warning("Attempted to refresh viewers without a project folder set.")
            #return

        # Silently ignore if index is -1 (transient/reset state)
        if root_index == -1:
            return

        # RACE CONDITION FIX: Copy list reference locally
        # If the attribute is replaced by another thread during this function,
        # we want to be consistent with what we checked.
        try:
            ms_roots = list(getattr(self, "multispectral_root_names", []) or [])
        except Exception:
            ms_roots = []
            
        if not ms_roots:
            # Project is empty
            return

        if root_index < 0 or root_index >= len(ms_roots):
            # Only warn if it's a "real" index that is wrong. 
            logging.warning(f"Specified root index is out of bounds: {root_index} (limit {len(ms_roots)}) [MARKER: VERIFIED CODE]")
            return
            
        # Use the local copy to access the name safely
        current_root_name = ms_roots[root_index]
        logging.info(f"Refreshing viewer for project '{self.project_name}' and root '{current_root_name}'.")

        try:
            self.load_image_group(current_root_name)
            self.save_polygons_to_json(root_name=current_root_name)
            self.update_polygon_manager()  # Ensure Polygon Manager UI is updated
            self._rewire_all_viewers_for_inspection()
    

            logging.info(f"Completed refreshing viewer for root '{current_root_name}'.")
        except Exception as e:
            logging.error(f"Error during refresh_viewer for root '{current_root_name}': {e}")
            # Use a non-critical message box to avoid system sounds
            msg_box = QMessageBox(self)
            msg_box.setWindowTitle("Refresh Error")
            msg_box.setText(f"An error occurred while refreshing the viewer for root '{current_root_name}':\n{e}")
            msg_box.setIcon(QMessageBox.NoIcon)  # Remove the icon to prevent sound
            msg_box.setStandardButtons(QMessageBox.Ok)
            msg_box.exec_()

    def get_viewer_by_filepath2(self, filepath):
        """Return the first live viewer that shows `filepath` (abs+normcase)."""
        import os
        if not filepath:
            return None
        key = os.path.normcase(os.path.abspath(filepath))
        for rec in getattr(self, "viewer_widgets", []) or []:
            idata = rec.get("image_data")
            if idata and getattr(idata, "filepath", None):
                fp = os.path.normcase(os.path.abspath(idata.filepath))
                if fp == key:
                    return rec.get("viewer")
        # Fallback: some places attach image_data directly on the viewer
        for rec in getattr(self, "viewer_widgets", []) or []:
            v = rec.get("viewer")
            try:
                fp = getattr(getattr(v, "image_data", None), "filepath", None)
                if fp and os.path.normcase(os.path.abspath(fp)) == key:
                    return v
            except Exception:
                pass
        return None

    def get_filepath_for_viewer(self, viewer):
        """Return absolute filepath for a viewer, if known."""
        import os
        if viewer is None:
            return None
        # Prefer the viewer_widgets registry
        for rec in getattr(self, "viewer_widgets", []) or []:
            if rec.get("viewer") is viewer:
                idata = rec.get("image_data")
                if idata and getattr(idata, "filepath", None):
                    return os.path.normcase(os.path.abspath(idata.filepath))
        # Fallback: viewer.image_data
        try:
            fp = getattr(getattr(viewer, "image_data", None), "filepath", None)
            if fp:
                return os.path.normcase(os.path.abspath(fp))
        except Exception:
            pass
        return None



    def refresh_single_viewer(self, viewer_or_filepath, *, reapply_mods=True, preserve_view=True):
        """
        Reload ONLY one viewer (image + polygons), leaving other viewers untouched.
        Applies .ax ops (rotate→crop→hist→resize→band_expr→classification) when reapply_mods=True.
        """
        import os, logging

        # ---- resolve viewer + filepath
        # CRITICAL: Preserve the ORIGINAL filepath to avoid creating duplicate polygon entries
        # with different path casing. Only normalize for lookups, not for storage.
        viewer = None
        original_filepath = None  # Keep original for storage in image_data
        
        if hasattr(viewer_or_filepath, "viewport"):   # likely a QGraphicsView/ImageViewer
            viewer = viewer_or_filepath
            # Get original filepath (NOT normalized) to preserve for polygon consistency
            try:
                for rec in getattr(self, "viewer_widgets", []) or []:
                    if rec.get("viewer") is viewer:
                        idata = rec.get("image_data")
                        if idata and getattr(idata, "filepath", None):
                            original_filepath = idata.filepath  # Keep original!
                            break
                if not original_filepath:
                    original_filepath = getattr(getattr(viewer, "image_data", None), "filepath", None)
            except Exception:
                pass
            filepath = original_filepath
        else:
            filepath = str(viewer_or_filepath)
            original_filepath = filepath
            # For lookup, normalize
            filepath_norm = os.path.normcase(os.path.abspath(filepath))
            viewer = self.get_viewer_by_filepath2(filepath_norm)

        if not filepath or viewer is None:
            logging.warning("refresh_single_viewer: could not resolve viewer/filepath.")
            return

        # ---- snapshot view transform/center (optional)
        view_state = {}
        if preserve_view:
            try:
                gv = viewer.graphicsView if hasattr(viewer, "graphicsView") else viewer
                view_state["transform"] = gv.transform()
                view_state["center"] = gv.mapToScene(gv.viewport().rect().center())
            except Exception:
                pass

        # ---- re-read pixels (with .ax if requested), repaint, and rebind image_data
        try:
            # base scientific container
            imgd = self._imagedata_or_fallback(filepath)
            if imgd is None or imgd.image is None:
                raise RuntimeError("No image returned for single-viewer reload.")

            # re-apply .ax pipeline (this includes CLASSIFICATION at the end)
            if reapply_mods:
                try:
                    imgd.image = self.apply_aux_modifications(
                        filepath,
                        imgd.image,
                        project_folder=getattr(self, "project_folder", None),
                        global_mode=False,
                        all_polygons=getattr(self, "all_polygons", None),
                    )
                except Exception as e:
                    logging.debug(f"apply_aux_modifications failed; keeping base: {e}")

            # Detect classification and band expression for proper rendering
            prefer_last_band = False
            has_classification = False
            try:
                ax = self._load_ax_json(filepath)
                # Check for band expression
                be = ax.get("band_expression")
                if isinstance(be, dict):
                    prefer_last_band = bool((be.get("expression") or "").strip())
                elif isinstance(be, str):
                    prefer_last_band = bool(be.strip())
                # Check for sklearn classification
                cblock = ax.get("classification") or {}
                if isinstance(cblock, dict):
                    has_classification = (
                        str(cblock.get("mode", "")).lower() == "sklearn" and
                        bool(cblock.get("enabled", False))
                    )
                    if has_classification:
                        prefer_last_band = True
                        logging.info(f"refresh_single_viewer: classification detected, prefer_last_band=True")
            except Exception:
                pass

            # CRITICAL FIX: Explicit check - if classification result is already a 2D single-band image (indices),
            # we MUST set prefer_last_band=True so _render_with_viewer_stretch knows to apply the
            # special min-max stretch logic we added.
            if has_classification and imgd.image is not None:
                # If we have a single channel image that is NOT color (RGB), treat as needing last-band logic
                # (which forces grayscale/min-max display)
                if imgd.image.ndim == 2 or (imgd.image.ndim == 3 and imgd.image.shape[2] == 1):
                    prefer_last_band = True

            # render using the current viewer stretch; fall back to standard pixmap
            pm = None
            try:
                # CRITICAL FIX: Update viewer.image_data BEFORE calling _render_with_viewer_stretch
                # so that it can read the correct .ax file (including nodata_values)
                viewer.image_data = imgd
                for rec in getattr(self, "viewer_widgets", []) or []:
                    if rec.get("viewer") is viewer:
                        rec["image_data"] = imgd
                        break
                
                # IMPORTANT: If we already applied aux modifications (which includes hist_match AND classification),
                # skip both in render to avoid double application
                if reapply_mods:
                    viewer._skip_hist_match_once = True
                    viewer._skip_classification_once = True
                    # For classification, force auto-stretch since old stretch won't work on class indices
                    if has_classification:
                        viewer._force_auto_stretch = True
                        viewer.stretch_params = None
                pm = self._render_with_viewer_stretch(imgd.image, viewer, prefer_last_band=prefer_last_band)
            except Exception:
                pass
            if pm is None:
                pm = self.convert_cv_to_pixmap(imgd.image, prefer_last_band=prefer_last_band)

            if pm is not None and hasattr(viewer, "set_image"):
                viewer.set_image(pm)

        except Exception as e:
            logging.error(f"refresh_single_viewer: failed to reload '{filepath}': {e}")
            return

        # ---- reload polygons ONLY for this viewer
        try:
            logging.debug(f"refresh_single_viewer: reloading polygons for {filepath}")
            self.load_polygons(viewer, viewer.image_data)
        except Exception as e:
            logging.warning(f"refresh_single_viewer: polygons reload FAILED for {filepath}: {e}")
            import traceback
            logging.debug(traceback.format_exc())

        # ---- restore view
        if preserve_view:
            try:
                gv = viewer.graphicsView if hasattr(viewer, "graphicsView") else viewer
                
                # Check if Fix Zoom is enabled - if so, use its mechanism instead of old center
                # This is important because geometry changes (crop/rotate/resize) invalidate
                # the old center point which was in the old coordinate system
                fix_zoom_enabled = False
                try:
                    # Get _ZoomBar from the viewer's zoombar if available
                    zb = getattr(gv, '_zoombar', None)
                    if zb:
                        zb_class = type(zb)
                        fix_zoom_enabled = getattr(zb_class, '_zoom_sync_enabled', False) and \
                                          getattr(zb_class, '_fixed_zoom', None) is not None
                except Exception:
                    pass
                
                if fix_zoom_enabled:
                    # Let Fix Zoom handle centering using raw-space anchor
                    if "transform" in view_state:
                        # Restore zoom level from saved transform
                        gv.setTransform(view_state["transform"])
                    # Then let Fix Zoom re-center using its raw anchor
                    if hasattr(gv, 'reapply_fixed_zoom_if_enabled'):
                        from PyQt5.QtCore import QTimer
                        QTimer.singleShot(0, gv.reapply_fixed_zoom_if_enabled)
                else:
                    # Standard restore when Fix Zoom is not enabled
                    if "transform" in view_state:
                        gv.setTransform(view_state["transform"])
                    if "center" in view_state:
                        gv.centerOn(view_state["center"])
            except Exception:
                pass

        logging.info(f"Refreshed single viewer: {filepath}")


    def _reload_image_into_viewer(self, viewer, filepath, *, reapply_mods=True):
        """
        Internal helper: re-read image + .ax and paint into the *existing* viewer.
        Keeps the same viewer instance and signals; does NOT touch other viewers.
        """
        import logging

        # (A) Rebuild image_data from disk using your existing loader
        image_data = self._imagedata_or_fallback(filepath)  # has .image and .filepath
        if image_data is None or image_data.image is None:
            raise RuntimeError("No image returned for single-viewer reload.")

        # Optionally re-apply .ax steps (crop/resize/band-math/etc.) for THIS file only
        if reapply_mods:
            try:
                # if your project uses this helper, keep it:
                image_data.image = self.apply_aux_modifications(
                    filepath,
                    image_data.image,
                    project_folder=getattr(self, "project_folder", None),
                    all_polygons=getattr(self, "all_polygons", None),
                )
            except Exception as e:
                logging.debug(f"_reload_image_into_viewer: aux mods skipped: {e}")

        # (B) Detect classification and band expression for proper rendering
        prefer_last_band = False
        has_classification = False
        try:
            ax = self._load_ax_json(filepath)
            # Check for band expression
            be = ax.get("band_expression")
            if isinstance(be, dict):
                prefer_last_band = bool((be.get("expression") or "").strip())
            elif isinstance(be, str):
                prefer_last_band = bool(be.strip())
            # Check for sklearn classification
            cblock = ax.get("classification") or {}
            if isinstance(cblock, dict):
                has_classification = (
                    str(cblock.get("mode", "")).lower() == "sklearn" and
                    bool(cblock.get("enabled", False))
                )
                if has_classification:
                    prefer_last_band = True
        except Exception:
            pass

        # (C) Render with the current viewer stretch and paint into the SAME viewer
        # CRITICAL FIX: Update viewer.image_data BEFORE calling _render_with_viewer_stretch
        # so that it can read the correct .ax file (including nodata_values)
        viewer.image_data = image_data
        
        pm = None
        try:
            # IMPORTANT: If we already applied aux modifications (which includes hist_match AND classification),
            # skip both in render to avoid double application
            if reapply_mods:
                viewer._skip_hist_match_once = True
                viewer._skip_classification_once = True
                # For classification, force auto-stretch
                if has_classification:
                    viewer._force_auto_stretch = True
                    viewer.stretch_params = None
            pm = self._render_with_viewer_stretch(image_data.image, viewer, prefer_last_band=prefer_last_band)
        except Exception:
            pass
        if pm is None:
            pm = self.convert_cv_to_pixmap(image_data.image, prefer_last_band=prefer_last_band)

        if hasattr(viewer, "set_image"):
            # Your viewer expects a pixmap; no need to pass image_data here
            viewer.set_image(pm)
        else:
            # Very defensive fallback
            if hasattr(viewer, "update_scene_from_image_data"):
                viewer.update_scene_from_image_data()
            elif hasattr(viewer, "update"):
                viewer.update()

        # (C) If you have a per-viewer stretch method, keep it (no-op if absent)
        try:
            if hasattr(viewer, "apply_current_stretch"):
                viewer.apply_current_stretch()
            elif hasattr(self, "_apply_viewer_stretch"):
                self._apply_viewer_stretch(viewer)
        except Exception as e:
            logging.debug(f"_reload_image_into_viewer: stretch reapply skipped: {e}")

     
    def switch_to_group(self, group_name):
        """
        Switches the current view to the root group that contains polygons of the specified group_name.
        
        Uses FILEPATH-BASED root lookup (not the stale 'root' field in polygon data)
        so that navigation works correctly after Find Similar Images or other operations
        that change file associations.
        
        Logic:
        1. Look up which root each polygon filepath actually belongs to (via image_data_groups).
        2. If the CURRENT root is among them, STAY (don't jump).
        3. Otherwise jump to the last valid root found (likely the newest).
        """
        import os
        print(f"[switch_to_group] Attempting to switch to group: {group_name}")
       
        if group_name not in self.all_polygons:
            print(f"[switch_to_group] Group '{group_name}' not in all_polygons.")
            return

        # --- Build root_name -> index map for fast lookup ---
        rootname_to_idx = {}
        for idx, rn in enumerate(self.root_names or []):
            rootname_to_idx[rn] = idx

        valid_indices = []
        valid_root_names = []

        # --- PRIMARY: Use filepath -> root lookup (always current) ---
        for filepath in self.all_polygons[group_name].keys():
            root_name = self.get_root_by_filepath(filepath)
            if root_name and root_name in rootname_to_idx:
                ridx = rootname_to_idx[root_name]
                if ridx not in valid_indices:
                    valid_indices.append(ridx)
                    valid_root_names.append(root_name)

        # --- FALLBACK: If filepath lookup found nothing, try the stored 'root' field ---
        if not valid_indices:
            for filepath, polygon_data in self.all_polygons[group_name].items():
                try:
                    root_index = int(polygon_data.get('root', 0)) - 1
                    if 0 <= root_index < len(self.root_names) and root_index not in valid_indices:
                        valid_indices.append(root_index)
                        valid_root_names.append(self.root_names[root_index])
                except Exception:
                    pass

        if not valid_indices:
            print(f"[switch_to_group] No valid root found for group '{group_name}'.")
            return

        print(f"[switch_to_group] Valid roots for '{group_name}': {list(zip(valid_indices, valid_root_names))}")

        # --- Check if we're ALREADY on a valid root ---
        try:
            current_idx = self.current_root_index
            if current_idx in valid_indices:
                print(f"[switch_to_group] Already on valid root (index {current_idx}). Staying put.")
                return
        except AttributeError:
            pass

        # --- Jump to the LAST valid root (most recently added) ---
        target_index = valid_indices[-1]
        root_name = self.root_names[target_index]
        
        print(f"[switch_to_group] Jumping to root '{root_name}' (index {target_index}).")
        self.current_root_index = target_index
        
        if hasattr(self, "group_slider"):
            self.group_slider.blockSignals(True)
            self.group_slider.setValue(target_index)
            self.group_slider.blockSignals(False)
        if hasattr(self, "update_slider_label"):
            self.update_slider_label(target_index)
        
        self.load_image_group(root_name)


    # **Helper Method to Get Root by Filepath**
    def get_root_by_filepath(self, filepath):
        """
        Retrieves the root name associated with a given filepath.
        PERFORMANCE: Uses O(1) cached lookup instead of O(n) scan.
        Cache is built from source-of-truth groups (multispectral/thermal) which are
        fully populated at project load time.
        """
        import os
        
        # Build/use cached reverse lookup - invalidate if source groups changed
        cache = getattr(self, "_filepath_to_root_cache", None)
        cache_key = getattr(self, "_filepath_to_root_cache_key", None)
        
        # Use source-of-truth groups for cache key (these are populated at project load)
        ms_count = len(self.multispectral_image_data_groups) if self.multispectral_image_data_groups else 0
        th_count = len(self.thermal_rgb_image_data_groups) if self.thermal_rgb_image_data_groups else 0
        current_key = (ms_count, th_count)
        
        if cache is None or cache_key != current_key:
            cache = self._filepath_to_root_cache = {}
            # Include both multispectral and thermal/RGB groups
            for root_name, filepaths in (self.multispectral_image_data_groups or {}).items():
                for fp in filepaths:
                    fp_norm = os.path.normpath(fp).lower() if fp else ""
                    cache[fp_norm] = root_name
            for root_name, filepaths in (self.thermal_rgb_image_data_groups or {}).items():
                for fp in filepaths:
                    fp_norm = os.path.normpath(fp).lower() if fp else ""
                    if fp_norm not in cache:  # Don't overwrite multispectral
                        cache[fp_norm] = root_name
            self._filepath_to_root_cache_key = current_key
        
        # O(1) lookup
        fp_norm = os.path.normpath(filepath).lower() if filepath else ""
        return cache.get(fp_norm)




