# Refactored ProcessingModeDialog (Moved from save_polygons_to_csv to module level)
# ==============================================================================
from PyQt5.QtWidgets import QDialog, QVBoxLayout, QHBoxLayout, QLabel, QRadioButton, QButtonGroup, QPushButton, QSpinBox, QGroupBox, QCheckBox

class ProcessingModeDialog(QDialog):
    def __init__(self, parent, n_polygons, n_files, ram_gb, n_cpu,
                 max_file_gb, allow_parallel, recommended_threads, auto_max_in_flight):
        super().__init__(parent)
        self.setWindowTitle("Export Options")
        self.setMinimumWidth(560)

        self._parent = parent
        self._allow_parallel = bool(allow_parallel)
        self._recommended_threads = int(max(1, recommended_threads or 1))
        self._auto_max_in_flight = int(max(1, auto_max_in_flight or 1))
        self._max_file_gb = float(max_file_gb or 0.0)

        layout = QVBoxLayout(self)

        # ---------------- Task Info ----------------
        info_box = QGroupBox("Task Info")
        info_layout = QVBoxLayout(info_box)
        info_layout.addWidget(QLabel(f"• {n_polygons} polygons across {n_files} images"))
        info_layout.addWidget(QLabel(f"• {ram_gb:.1f} GB RAM available, {n_cpu} CPU cores"))

        if self._allow_parallel:
            reco = f"✓ Parallel processing available ({self._auto_max_in_flight} workers recommended)"
            info_layout.addWidget(QLabel(reco))
        else:
            info_layout.addWidget(QLabel("• Sequential processing recommended for this configuration"))

        layout.addWidget(info_box)

        # ---------------- Mode selection ----------------
        mode_box = QGroupBox("Processing Mode")
        mode_layout = QVBoxLayout(mode_box)

        self.btn_group = QButtonGroup(self)

        # Option 1: File-batched sequential (recommended for low-RAM)
        self.radio_multi = QRadioButton("⚡ File-Batched Sequential - Safe, moderate speed")
        self.radio_multi.setToolTip(
            "Process all polygons per image file before moving to next.\n"
            "Best cache utilization, lowest RAM, most stable."
        )
        self.btn_group.addButton(self.radio_multi, 1)
        mode_layout.addWidget(self.radio_multi)

        # Option 2: Sequential by polygon (original)
        self.radio_seq = QRadioButton("🛡️ Sequential by Polygon - Original")
        self.radio_seq.setToolTip("Process polygons in order. May reload the same image multiple times.")
        self.btn_group.addButton(self.radio_seq, 2)
        mode_layout.addWidget(self.radio_seq)

        # Option 3: File-batched parallel (threads)
        parallel_title = "🚀 File-Batched Parallel (threads) - Faster but uses more RAM"
        if self._allow_parallel:
            parallel_title = f"🚀 File-Batched Parallel (threads) - Faster (safe up to ~{self._auto_max_in_flight} in-flight)"
        self.radio_thread = QRadioButton(parallel_title)
        self.radio_thread.setToolTip(
            "Process multiple files in parallel using threads.\n"
            "Each thread loads and processes one file at a time (file-batched).\n"
            "Memory is monitored and will fall back to sequential if RAM gets low.\n"
            f"Recommended: {self._recommended_threads} threads based on your system."
        )
        self.btn_group.addButton(self.radio_thread, 3)
        mode_layout.addWidget(self.radio_thread)

        thread_opts = QHBoxLayout()
        thread_opts.addSpacing(25)
        thread_opts.addWidget(QLabel("In-flight files:"))
        self.spin_thread = QSpinBox()
        self.spin_thread.setRange(1, max(1, int(self._auto_max_in_flight)))
        self.spin_thread.setValue(max(1, min(self.spin_thread.maximum(), self._recommended_threads)))
        self.spin_thread.setEnabled(False)
        thread_opts.addWidget(self.spin_thread)
        thread_opts.addStretch()
        mode_layout.addLayout(thread_opts)

        self.radio_thread.toggled.connect(self.spin_thread.setEnabled)

        # Smart default: select parallel for systems that can handle it
        if self._allow_parallel and self._auto_max_in_flight >= 2:
            self.radio_thread.setChecked(True)
            self.spin_thread.setEnabled(True)
        else:
            self.radio_multi.setChecked(True)

        layout.addWidget(mode_box)

        # ---------------- Execution ----------------
        bg_box = QGroupBox("Execution")
        bg_layout = QVBoxLayout(bg_box)
        self.bg_checkbox = QCheckBox("🔄 Run in Background (continue using app)")
        self.bg_checkbox.setToolTip(
            "Export runs in a background worker thread.\n"
            "To avoid GUI/thread crashes, background export always uses the safe\n"
            "File-Batched Sequential mode regardless of the selection above."
        )
        self.bg_checkbox.setChecked(True)  # Default to background
        bg_layout.addWidget(self.bg_checkbox)
        layout.addWidget(bg_box)

        # Buttons
        btn_layout = QHBoxLayout()
        self.btn_manager = QPushButton("Export Manager...")
        self.btn_manager.setToolTip("View running and completed exports")
        self.btn_manager.clicked.connect(self._show_manager)
        btn_layout.addWidget(self.btn_manager)

        btn_layout.addStretch()

        btn_ok = QPushButton("Start Export")
        btn_ok.clicked.connect(self.accept)
        btn_cancel = QPushButton("Cancel")
        btn_cancel.clicked.connect(self.reject)
        btn_layout.addWidget(btn_ok)
        btn_layout.addWidget(btn_cancel)
        layout.addLayout(btn_layout)

        # Apply initial constraints
        self.bg_checkbox.toggled.connect(self._apply_constraints)
        self._apply_constraints()

    def _apply_constraints(self):
        # If background is selected, we force stability.
        if self.bg_checkbox.isChecked():
            self.radio_thread.setEnabled(False)
            self.spin_thread.setEnabled(False)
            self.radio_multi.setChecked(True)
            return

        # Foreground mode
        self.radio_thread.setEnabled(True)
        if not self._allow_parallel:
            try:
                self.spin_thread.setRange(1, 1)
                self.spin_thread.setValue(1)
            except Exception:
                pass
            self.radio_thread.setToolTip(
                "Low RAM headroom for this job/machine.\n"
                "Threading is limited to 1 in-flight file to avoid crashes.\n"
                "For best stability, use File-Batched Sequential."
            )
        else:
            try:
                self.spin_thread.setRange(1, max(1, int(self._auto_max_in_flight)))
                if self.spin_thread.value() > self.spin_thread.maximum():
                    self.spin_thread.setValue(self.spin_thread.maximum())
            except Exception:
                pass
        self.spin_thread.setEnabled(self.radio_thread.isChecked())

    def _show_manager(self):
        mgr = ExportManagerDialog.get_instance(self._parent)
        mgr.show()
        mgr.raise_()

    def get_mode(self):
        if self.bg_checkbox.isChecked():
            return ("multiprocessing", 1)

        if self.radio_multi.isChecked():
            return ("multiprocessing", 1)
        elif self.radio_seq.isChecked():
            return ("sequential", 1)
        else:
            return ("threading", int(self.spin_thread.value()))

    def run_in_background(self):
        return self.bg_checkbox.isChecked()





class ModifyPolygonCommand(QUndoCommand):
    def __init__(self, project_tab, label, filepath, group_name, old_points, new_points):
        super().__init__(f"Move Polygon '{label}'")
        self.tab = project_tab
        self.label = label
        self.filepath = filepath
        self.group_name = group_name
        self.old_points = old_points  # QPolygonF (scene coords)
        self.new_points = new_points  # QPolygonF (scene coords)
        self._first_run = True

    def redo(self):
        # On first run (initial drag end), we do NOT update visual because it is already consistent.
        # But we MUST update memory and save JSON.
        logging.info(f"[UndoStack] Redo Move: {self.label}")
        self._apply_state(self.new_points, update_visual=not self._first_run)
        self._first_run = False

    def undo(self):
        logging.info(f"[UndoStack] Undo Move: {self.label}")
        self._apply_state(self.old_points, update_visual=True)

    def _apply_state(self, points, update_visual=False):
        import os
        # 1. Update memory
        if self.group_name in self.tab.all_polygons:
             d = self.tab.all_polygons[self.group_name].get(self.filepath)
             if d:
                 pts_list = [(p.x(), p.y()) for p in points]
                 d['points'] = pts_list
        
        # 2. Save to JSON (Single File)
        if hasattr(self.tab, '_save_specific_polygon_file'):
            self.tab._save_specific_polygon_file(self.group_name, self.filepath)

        # 3. Update Visuals
        if update_visual:
            if hasattr(self.tab, 'viewer_widgets'):
                for widget_dict in self.tab.viewer_widgets:
                    viewer = widget_dict.get('viewer')
                    if viewer and viewer.image_data and hasattr(viewer.image_data, 'filepath'):
                         if os.path.normpath(viewer.image_data.filepath) == os.path.normpath(self.filepath):
                             for item in viewer.scene().items():
                                 # We access EditablePolygonItem from global scope (imported at top)
                                 if isinstance(item, EditablePolygonItem):
                                     if getattr(item, "name", "") == self.label:
                                         item.prepareGeometryChange()
                                         item.polygon = points
                                         item.setPos(0, 0) # Reset pos because points are scene coords
                                         item.update()
                                         break




